    // ── Compile-to-object (requires linker) ───────────────────────

    #[test]
    fn test_compile_to_object_hello_world() {
        use karac::codegen::compile_to_object;
        use std::path::Path;

        let src = r#"
fn main() {
    println(42);
}
"#;
        let mut parsed = karac::parse(src);
        assert!(parsed.errors.is_empty());
        let resolved = karac::resolve(&parsed.program);
        let typed = karac::typecheck(&parsed.program, &resolved);
        karac::lower(&mut parsed.program, &typed);

        let obj_path = "/tmp/karac_test_hello.o";
        let result = compile_to_object(&parsed.program, obj_path, None, None);
        assert!(result.is_ok(), "compile_to_object failed: {:?}", result);
        assert!(Path::new(obj_path).exists(), "object file should exist");

        // Clean up
        let _ = std::fs::remove_file(obj_path);
    }

    // ── End-to-end execution tests ────────────────────────────────
    // These compile → link → run and verify stdout.

    /// Spawn a built kara test binary and capture stdout+stderr, with a
    /// per-spawn 15s hang watchdog. Thin wrapper over the shared helper
    /// in `tests/common/mod.rs` — see the module doc there for the full
    /// rationale (concurrent-spawn deadlock, 2026-05-25 incident).
    fn output_with_hang_watchdog(cmd: std::process::Command) -> Option<std::process::Output> {
        super::common::output_with_hang_watchdog(cmd, std::time::Duration::from_secs(15))
    }

    fn run_program(src: &str) -> Option<String> {
        run_program_capturing(src).map(|c| c.stdout)
    }

    #[test]
    fn test_e2e_volatile_read_write_roundtrip() {
        // MMIO intrinsics `volatile_write` / `volatile_read`
        // (`runtime/stdlib/intrinsics.kara`) lower to a volatile store / load
        // through a raw pointer. Exercised over a regular stack slot (volatile
        // semantics on ordinary memory behave as a normal read/write, so the
        // value round-trips): write 42 through `*mut i32`, read it back through
        // `*const i32`, expect 42. Witnesses the codegen intercept in
        // `compile_call` + the pointee-sized volatile load/store.
        let out = run_program(
            r#"
fn main() {
    let mut cell: i32 = 7;
    // Safety: pw / pr point to the live local `cell`.
    let after = unsafe {
        let pw: *mut i32 = ptr.mut(cell);
        volatile_write(pw, 42);
        let pr: *const i32 = ptr.const(cell);
        volatile_read(pr)
    };
    println(after);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "42");
        }
    }

    #[test]
    fn test_e2e_volatile_write_narrow_field_ref_param_roundtrip() {
        // B-2026-07-12-7 — `volatile_write(pw, 777)` through a `*mut i32` used
        // to store an `i64` (an integer literal defaults to i64 in codegen),
        // mismatching the `i32` pointee. Under `-O` (AOT) the 8-byte volatile
        // store and the paired 4-byte volatile load didn't forward, so a
        // same-function read-back value-numbered to the pre-write value: `karac
        // build` printed the stale `20` while `karac run`/JIT (at -O0) printed
        // the correct `777`. `run_program` builds a REAL optimized binary, so it
        // exercises the AOT path where this reproduced. Both the in-function
        // read-back (bump's return) AND the cross-function read-back (main) must
        // now be 777. The fix coerces the written value to the pointee width.
        let out = run_program(
            r#"
struct Reg { status: i32, control: i32 }
fn bump(r: mut ref Reg) -> i32 {
    // Safety: r is a live borrow of the caller's Reg.
    unsafe {
        let pw: *mut i32 = ptr.mut(r.control);
        volatile_write(pw, 777);
        let pr: *const i32 = ptr.const(r.control);
        volatile_read(pr)
    }
}
fn main() {
    let mut r: Reg = Reg { status: 10, control: 20 };
    let inside = bump(mut r);
    println(inside);
    // Safety: r is still live here.
    unsafe {
        let pr: *const i32 = ptr.const(r.control);
        println(volatile_read(pr));
    }
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "777\n777");
        }
    }

    #[test]
    fn test_ir_fence_seqcst_emits_cross_thread_fence() {
        // `fence(MemoryOrdering.SeqCst)` (`runtime/stdlib/intrinsics.kara`)
        // lowers to a cross-thread LLVM `fence seq_cst` (no syncscope
        // qualifier ⇒ the default cross-thread scope). Witnesses the
        // `compile_atomic_fence` intercept in `compile_call`.
        let ir = ir_for(
            r#"
fn barrier() with reads(Hardware) {
    // Safety: a full barrier ordering the surrounding accesses.
    unsafe { fence(MemoryOrdering.SeqCst); }
}
fn main() { barrier(); }
"#,
        );
        assert!(
            ir.contains("fence seq_cst"),
            "expected a cross-thread `fence seq_cst`; IR:\n{ir}"
        );
        assert!(
            !ir.contains("fence syncscope(\"singlethread\") seq_cst"),
            "cross-thread `fence` must NOT carry the singlethread syncscope; IR:\n{ir}"
        );
    }

    #[test]
    fn test_ir_fence_acquire_release_orderings() {
        // Each non-Relaxed ordering maps to its LLVM spelling. Acquire and
        // Release cover the load/store-half barriers; AcqRel the combined form.
        let ir = ir_for(
            r#"
fn barriers() {
    // Safety: paired with matching accesses on other threads.
    unsafe {
        fence(MemoryOrdering.Acquire);
        fence(MemoryOrdering.Release);
        fence(MemoryOrdering.AcqRel);
    }
}
fn main() { barriers(); }
"#,
        );
        assert!(
            ir.contains("fence acquire"),
            "missing `fence acquire`; IR:\n{ir}"
        );
        assert!(
            ir.contains("fence release"),
            "missing `fence release`; IR:\n{ir}"
        );
        assert!(
            ir.contains("fence acq_rel"),
            "missing `fence acq_rel`; IR:\n{ir}"
        );
    }

    #[test]
    fn test_ir_compiler_fence_uses_singlethread_syncscope() {
        // `compiler_fence(order)` is a compiler-only reordering barrier: LLVM
        // `fence syncscope("singlethread") <order>` restrains the optimizer
        // without emitting a CPU barrier. It is *safe* (no `unsafe` block).
        let ir = ir_for(
            r#"
fn barrier() {
    compiler_fence(MemoryOrdering.SeqCst);
}
fn main() { barrier(); }
"#,
        );
        assert!(
            ir.contains("fence syncscope(\"singlethread\") seq_cst"),
            "expected a singlethread-syncscope `compiler_fence`; IR:\n{ir}"
        );
    }

    #[test]
    fn test_ir_fence_relaxed_rejected() {
        // A `Relaxed` fence orders nothing and LLVM forbids `fence monotonic`;
        // `compile_atomic_fence` rejects it with an actionable diagnostic.
        let mut parsed = karac::parse(
            r#"
fn barrier() {
    // Safety: rejected before this matters.
    unsafe { fence(MemoryOrdering.Relaxed); }
}
fn main() { barrier(); }
"#,
        );
        assert!(
            parsed.errors.is_empty(),
            "parse errors: {:?}",
            parsed.errors
        );
        let resolved = karac::resolve(&parsed.program);
        let typed = karac::typecheck(&parsed.program, &resolved);
        karac::lower(&mut parsed.program, &typed);
        let err = compile_to_ir(&parsed.program, None, None)
            .expect_err("a Relaxed fence must be rejected at codegen");
        assert!(
            err.contains("fence ordering must be") && err.contains("Relaxed"),
            "expected a Relaxed-fence rejection, got: {err}"
        );
    }

    #[test]
    fn test_e2e_fence_and_compiler_fence_run() {
        // Both fences are valid barriers around ordinary code; a
        // single-threaded program observes no reordering, so the program
        // simply runs and prints. Witnesses end-to-end lowering + link.
        let out = run_program(
            r#"
fn main() {
    // Safety: no paired cross-thread accesses in this single-threaded demo.
    unsafe { fence(MemoryOrdering.SeqCst); }
    compiler_fence(MemoryOrdering.Acquire);
    println(1);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "1");
        }
    }

    #[test]
    fn test_ir_critical_section_acquire_emits_acquire_and_scope_exit_release() {
        // `critical_section.acquire()` lowers to a call to the runtime
        // `karac_critical_section_acquire`, and the guard's scope-exit Drop
        // (hand-rolled `@CriticalSectionGuard.drop`) calls
        // `karac_critical_section_release` — both appear in module IR.
        let ir = ir_for(
            r#"
fn f() with writes(Hardware) {
    let _guard = critical_section.acquire();
    println(7);
}
fn main() { f(); }
"#,
        );
        assert!(
            ir.contains("call i64 @karac_critical_section_acquire()"),
            "expected an acquire call; IR:\n{ir}"
        );
        assert!(
            ir.contains("@karac_critical_section_release"),
            "expected a scope-exit release call (guard Drop); IR:\n{ir}"
        );
        // The Drop wrapper the RAII machinery routes through must exist.
        assert!(
            ir.contains("@\"CriticalSectionGuard.drop\"")
                || ir.contains("@CriticalSectionGuard.drop"),
            "expected the hand-rolled CriticalSectionGuard.drop body; IR:\n{ir}"
        );
    }

    #[test]
    fn test_e2e_critical_section_run() {
        // End-to-end: acquire a critical section, do work, drop the guard at
        // scope exit (re-enabling interrupts via the runtime). Single-threaded
        // hosted target, so it simply runs and prints — witnesses lowering +
        // link of the acquire/release runtime pair.
        let out = run_program(
            r#"
fn work() with writes(Hardware) {
    let _guard = critical_section.acquire();
    println(42);
}
fn main() {
    work();
    println(99);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "42\n99");
        }
    }

    #[test]
    fn test_e2e_ptr_const_mut_place_shapes_roundtrip() {
        // `ptr.const(place)` / `ptr.mut(place)` over the full place grammar the
        // typechecker's place-validator accepts — field access, a nested field
        // chain, a tuple index, and a Vec index — not just the bare-binding /
        // deref shapes the earlier codegen slice covered. Each place: write a
        // sentinel through `ptr.mut(place)`, read it back through
        // `ptr.const(place)`, and expect the sentinel. Witnesses `ptr_place_addr`
        // GEPing to the correct in-place field / element address (owned-local
        // roots, where the same-scope round-trip is observable — the reliable
        // pattern the volatile-roundtrip test above also uses).
        let out = run_program(
            r#"
struct Reg { status: i32, control: i32 }
struct Block { inner: Reg, id: i64 }
fn main() {
    let mut r: Reg = Reg { status: 10, control: 20 };
    // Safety: every pointer addresses a live owned local for the duration of use.
    unsafe {
        let pw: *mut i32 = ptr.mut(r.status);
        volatile_write(pw, 99);
        let pr: *const i32 = ptr.const(r.status);
        println(volatile_read(pr));
    }
    let mut b: Block = Block { inner: Reg { status: 1, control: 2 }, id: 7 };
    unsafe {
        let pw: *mut i32 = ptr.mut(b.inner.control);
        volatile_write(pw, 500);
        let pr: *const i32 = ptr.const(b.inner.control);
        println(volatile_read(pr));
    }
    let mut pair: (i32, i32) = (11, 22);
    unsafe {
        let pw: *mut i32 = ptr.mut(pair.1);
        volatile_write(pw, 222);
        let pr: *const i32 = ptr.const(pair.1);
        println(volatile_read(pr));
    }
    let mut v: Vec[i32] = Vec.new();
    v.push(3);
    v.push(4);
    unsafe {
        let pw: *mut i32 = ptr.mut(v[1]);
        volatile_write(pw, 444);
    }
    println(v[1]);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "99\n500\n222\n444");
        }
    }

    #[test]
    fn test_e2e_volatile_cell_read_write_roundtrip() {
        // Baked `VolatileCell[T]` stdlib type (`runtime/stdlib/volatile_cell.kara`,
        // prelude-visible — used here WITHOUT a local definition). Codegen lowers
        // it transparently to its inner `T` and intercepts `.read()` / `.write(v)`
        // as a volatile load / store against the binding's slot. Exercises two
        // instantiations at different widths (i32 + u8) in one program — the
        // generic-mono path fixed in B-2026-07-12-16. `0x1F` == 31.
        let out = run_program(
            r#"
fn main() {
    let mut reg: VolatileCell[i32] = VolatileCell.new(7);
    println(reg.read());
    reg.write(42);
    println(reg.read());
    reg.write(0x1F);
    println(reg.read());
    let mut flag: VolatileCell[u8] = VolatileCell.new(0);
    flag.write(1);
    println(flag.read());
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "7\n42\n31\n1");
        }
    }

    #[test]
    fn test_e2e_field_read_option_shared_push_correct() {
        // B-2026-07-12-4 correctness pin (the ASAN/leak gate lives in
        // tests/memory_sanitizer.rs). Pushing a FIELD-READ `Option[shared]`
        // (`stack.push(n.left)` / `n.right`) onto a `Vec[Option[shared]]`, then
        // reading the pushed nodes back, must yield the correct values — the
        // co-ownership retain fix must not disturb the stored handles. Non-ASAN
        // so it runs everywhere as a value regression guard.
        let out = run_program(
            r#"
shared struct Node { val: i64, mut left: Option[Node], mut right: Option[Node] }
fn main() {
    let root = Some(Node {
        val: 1,
        left: Some(Node { val: 2, left: None, right: None }),
        right: Some(Node { val: 3, left: None, right: None }),
    });
    let mut stack: Vec[Option[Node]] = Vec.new();
    match root {
        None => {}
        Some(n) => { stack.push(n.left); stack.push(n.right); }
    }
    let mut sum: i64 = 0;
    for item in stack {
        match item { None => {} Some(node) => { sum = sum + node.val; } }
    }
    println(sum);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "5");
        }
    }

    #[test]
    fn test_e2e_direct_index_match_option_shared_correct() {
        // B-2026-07-12-21 correctness pin (the ASAN/leak gate lives in
        // tests/memory_sanitizer.rs::asan_direct_index_match_option_shared_no_leak).
        // A direct `match vec[i]` on an `Option[shared]` index-read leaked the
        // extracted node; the lowering fix rewrites it into a let-bound
        // scrutinee. This pins that the rewrite preserves the value — the bound
        // arm must still read the right node's field. Non-ASAN so it guards the
        // value everywhere.
        let out = run_program(
            r#"
shared struct Node { val: i64, mut left: Option[Node], mut right: Option[Node] }
fn xfer() -> i64 {
    let mut dst: Vec[Option[Node]] = Vec.new();
    dst.push(Some(Node { val: 10, left: None, right: None }));
    let mut r: i64 = 0;
    match dst[0] {
        None => {}
        Some(nd) => { r = nd.val; }
    }
    r
}
fn main() {
    let mut i: i64 = 0;
    let mut t: i64 = 0;
    while i < 200 {
        t = t + xfer();
        i = i + 1;
    }
    println(t);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "2000");
        }
    }

