    #[test]
    fn test_e2e_vec_macro_literal() {
        // `vec![a, b, c]` desugars to the same PrefixCollectionLiteral node
        // codegen already lowers for `Vec[a, b, c]` — codegen never sees a
        // `vec!` node. Pins the parser desugaring through the AOT backend
        // (skips vacuously when the runtime archive is absent). The repeat
        // form `vec![v; n]` / `Vec[v; n]` is covered by
        // `test_e2e_vec_repeat_literal` below.
        let Some(output) = run_program(
            "fn main() {\n\
                 let v = vec![10, 20, 30];\n\
                 let mut total = 0;\n\
                 for x in v { total = total + x; }\n\
                 println(total);\n\
                 println(v.len());\n\
             }",
        ) else {
            return;
        };
        assert_eq!(output, "60\n3\n");
    }

    #[test]
    fn test_e2e_vec_repeat_literal() {
        // `Vec[v; n]` / `vec![v; n]` build a heap Vec[T] of n copies of v via
        // the shared `build_vec_filled` (malloc + runtime fill loop) — the same
        // path as `Vec.filled(n, v)`. Covers: literal count, runtime count, the
        // `vec!` macro spelling, push-after-fill (cap==len ⇒ first push grows),
        // and indexing the filled element. This is the codegen tail of the
        // phase-4-interpreter.md `Vec[v; n]` repeat-literal item.
        let Some(output) = run_program(
            "fn main() {\n\
                 let v: Vec[i64] = Vec[7; 4];\n\
                 let mut sum = 0;\n\
                 for x in v { sum = sum + x; }\n\
                 println(sum);\n\
                 println(v.len());\n\
                 let m = vec![3; 5];\n\
                 println(m.len());\n\
                 let n = 6;\n\
                 let r: Vec[i64] = Vec[2; n];\n\
                 println(r.len());\n\
                 let mut g: Vec[i64] = Vec[0; 3];\n\
                 g.push(99);\n\
                 println(g.len());\n\
                 println(g[3]);\n\
             }",
        ) else {
            return;
        };
        assert_eq!(output, "28\n4\n5\n6\n4\n99\n");
    }

    #[test]
    fn test_e2e_option_result_unwrap_or() {
        // B-2026-06-11-10: `unwrap_or(default)` on Option/Result. The bug
        // report mis-scoped this as a non-identifier-receiver dispatch gap; it
        // was actually unimplemented across typecheck + interp + codegen. This
        // pins the receiver-shape-agnostic codegen path: a chained call-result
        // receiver (`m.get(k).unwrap_or(d)` — the original repro), a plain
        // Option identifier, a width-mismatched default (i64 literal into an
        // `i32` payload, exercising the codegen width-coerce), a `Result`, and
        // a heap `String` payload (3-word reconstitution + default).
        let output = run_program(
            "fn rstr(o: Result[String, i64]) -> String { o.unwrap_or(\"fb\") }\n\
             fn main() {\n\
                 let mut m: Map[i64, i64] = Map.new();\n\
                 m.insert(1, 2);\n\
                 println(m.get(1).unwrap_or(0));\n\
                 println(m.get(9).unwrap_or(-1));\n\
                 let a: Option[i64] = Some(5);\n\
                 let b: Option[i64] = None;\n\
                 println(a.unwrap_or(0));\n\
                 println(b.unwrap_or(7));\n\
                 let mut n: Map[i64, i32] = Map.new();\n\
                 n.insert(3, 30);\n\
                 println(n.get(8).unwrap_or(-9));\n\
                 println(rstr(Result.Ok(\"got\")));\n\
                 println(rstr(Result.Err(404)));\n\
                 let s: Option[String] = None;\n\
                 println(s.unwrap_or(\"def\"));\n\
             }",
        )
        .expect("compile + run failed");
        assert_eq!(output, "2\n-1\n5\n7\n-9\ngot\nfb\ndef\n");
    }

    #[test]
    fn test_e2e_result_unwrap_err_expect_err() {
        // B-2026-07-09-10: `Result::unwrap_err()` / `expect_err()` — the
        // Err-extracting, Ok-panicking mirrors of `unwrap`/`expect`. Codegen
        // panics on the Ok tag (tag == 1) and reconstitutes the Err payload
        // (inner type E, from `method_unwrap_inner_types`), sharing the
        // extract-or-panic shape with `unwrap`. Covers a scalar `Err(i64)`, a
        // heap `Err(String)` on a fresh-temp receiver (the common `f().unwrap_err()`
        // shape), and `expect_err`. `unwrap` on the Ok side stays correct.
        let output = run_program(
            "fn parse(ok: bool) -> Result[i64, i64] {\n\
             \x20   if ok { Result.Ok(42) } else { Result.Err(99) }\n\
             }\n\
             fn emsg(ok: bool) -> Result[i64, String] {\n\
             \x20   if ok { Result.Ok(1) } else { Result.Err(\"the error message here\".to_string()) }\n\
             }\n\
             fn main() {\n\
             \x20   println(parse(true).unwrap());\n\
             \x20   println(parse(false).unwrap_err());\n\
             \x20   println(emsg(false).unwrap_err());\n\
             \x20   println(emsg(false).expect_err(\"wanted an error\"));\n\
             }",
        )
        .expect("compile + run failed");
        assert_eq!(
            output,
            "42\n99\nthe error message here\nthe error message here\n"
        );
    }

    #[test]
    fn e2e_enum_heap_payload_eq_compares_by_content() {
        // A variant with a concrete `String` payload compares by *content*, not
        // by pointer word — the variant-aware `compile_enum_eq` rebuilds the
        // payload at its declared type and recurses (`Text("a"+"b")` is a
        // distinct allocation from `Text("ab")` but must compare equal). Scalar
        // and unit variants stay correct.
        if let Some(out) = run_program(
            "#[derive(Eq)]\n\
             enum Msg { Text(String), Code(i64), Empty }\n\
             fn main() {\n\
                 let a = Msg.Text(\"a\" + \"b\");\n\
                 let b = Msg.Text(\"ab\");\n\
                 let c = Msg.Text(\"xy\");\n\
                 let d = Msg.Code(5);\n\
                 let e = Msg.Code(5);\n\
                 let f = Msg.Empty;\n\
                 println(f\"{a == b}\");\n\
                 println(f\"{a == c}\");\n\
                 println(f\"{d == e}\");\n\
                 println(f\"{a == d}\");\n\
                 println(f\"{f == f}\");\n\
                 println(f\"{a == f}\");\n\
             }",
        ) {
            assert_eq!(out, "true\nfalse\ntrue\nfalse\ntrue\nfalse\n");
        }
    }

    #[test]
    fn e2e_generic_enum_heap_payload_eq_compares_by_content() {
        // Generic heap-payload enums (`Option[String]`, `Result[_, String]`)
        // compare by *content*, not by pointer word. The bare seeded layout is
        // monomorphization-blind (one `Option`/`Result` shape, payload-as-
        // words), so routing keys off the lowering pass's recorded
        // instantiation (`enum_inst_type_exprs`): `compile_enum_eq` substitutes
        // the `[String]` arg into the `Some`/`Err` payload type and rebuilds it
        // as a `String`. Distinct allocations with equal content must compare
        // equal; scalar instantiations (`Option[i64]`) stay word-wise.
        // Comparisons are written *inline inside f-string interpolations* on
        // purpose: every interp expr is re-parsed under a fixed-length
        // `fn __interp__() { … }` wrapper, so same-position operands across
        // different f-strings share a span. Routing therefore resolves an
        // identifier operand's instantiation by *name* (`enum_inst_var_types`),
        // not by the colliding span — without that, `g == h` (`Option[i64]`)
        // and `a == b` (`Option[String]`) would alias and mis-route. The
        // bound-then-formatted variant is covered by the assertions below too,
        // but the inline form is the regression guard for the span collision.
        if let Some(out) = run_program(
            "fn main() {\n\
                 let a: Option[String] = Some(\"a\" + \"b\");\n\
                 let b: Option[String] = Some(\"ab\");\n\
                 let c: Option[String] = Some(\"xy\");\n\
                 let n: Option[String] = None;\n\
                 println(f\"{a == b}\");\n\
                 println(f\"{a == c}\");\n\
                 println(f\"{a == n}\");\n\
                 println(f\"{n == n}\");\n\
                 let r: Result[String, i64] = Ok(\"a\" + \"b\");\n\
                 let s: Result[String, i64] = Ok(\"ab\");\n\
                 println(f\"{r == s}\");\n\
                 let e1: Result[i64, String] = Err(\"x\" + \"y\");\n\
                 let e2: Result[i64, String] = Err(\"xy\");\n\
                 let e3: Result[i64, String] = Err(\"zz\");\n\
                 println(f\"{e1 == e2}\");\n\
                 println(f\"{e1 == e3}\");\n\
                 let g: Option[i64] = Some(7);\n\
                 let h: Option[i64] = Some(7);\n\
                 println(f\"{g == h}\");\n\
             }",
        ) {
            assert_eq!(out, "true\nfalse\nfalse\ntrue\ntrue\ntrue\nfalse\ntrue\n");
        }
    }

    #[test]
    fn e2e_generic_enum_heap_eq_constructor_operand_in_fstring() {
        // The residual gap B-2026-06-09-1's enum workaround did NOT close:
        // *non-identifier* operands (direct constructor calls) compared inline
        // inside f-strings. The name-keyed `enum_inst_var_types` only resolves
        // identifiers, so a `Some(...)` operand had to fall back to the
        // span-keyed table — which, under wrapper-relative spans, collided
        // across f-strings and degraded to the word-wise pointer compare
        // (distinct allocations → wrong `false` for equal content). With the
        // parser fix (absolute interpolation spans) the constructor operand's
        // span is unique and correctly keys `enum_inst_type_exprs`, so content
        // comparison routes even for the inline-constructor form. The two
        // f-strings put differently-typed comparisons at the SAME syntactic
        // position to prove the former alias is gone.
        if let Some(out) = run_program(
            "fn main() {\n\
                 println(f\"{Some(\"a\" + \"b\") == Some(\"ab\")}\");\n\
                 println(f\"{Some(1) == Some(2)}\");\n\
                 println(f\"{Some(\"a\" + \"b\") == Some(\"zz\")}\");\n\
             }",
        ) {
            assert_eq!(out, "true\nfalse\nfalse\n");
        }
    }

    #[test]
    fn e2e_generic_enum_heap_eq_through_params() {
        // The instantiated-enum type of a *parameter* (`opt: Option[String]`)
        // is registered by name at function entry, so a heap-payload `==`
        // inside the function body compares by content — exercises the
        // parameter-binding leg of `enum_inst_var_types` (distinct from the
        // let-binding leg above).
        if let Some(out) = run_program(
            "fn same_opt(x: Option[String], y: Option[String]) -> bool { x == y }\n\
             fn same_res(x: Result[String, i64], y: Result[String, i64]) -> bool { x == y }\n\
             fn main() {\n\
                 let a: Option[String] = Some(\"a\" + \"b\");\n\
                 let b: Option[String] = Some(\"ab\");\n\
                 let c: Option[String] = Some(\"zz\");\n\
                 println(f\"{same_opt(a, b)}\");\n\
                 println(f\"{same_opt(a, c)}\");\n\
                 let r: Result[String, i64] = Ok(\"x\" + \"y\");\n\
                 let s: Result[String, i64] = Ok(\"xy\");\n\
                 println(f\"{same_res(r, s)}\");\n\
             }",
        ) {
            assert_eq!(out, "true\nfalse\ntrue\n");
        }
    }

    /// Stdout + stderr capture. Used by tests that assert against trace
    /// output written to stderr by the runtime's atexit handler.
    struct CapturedRun {
        stdout: String,
        stderr: String,
        /// Child process exit status. Lets tests distinguish a clean exit
        /// from a crash (SIGSEGV / abort) when stdout alone can't — e.g.
        /// B-2026-06-09-1, where the program prints its output and *then*
        /// faults at scope-exit drop.
        status: std::process::ExitStatus,
    }

    fn run_program_capturing(src: &str) -> Option<CapturedRun> {
        run_program_capturing_inner(src, None)
    }

    /// Like `run_program_capturing` but threads `source_filename` into codegen
    /// so `?` propagation traces print as `<file>:<line>:<col>`.
    fn run_program_capturing_with_filename(src: &str, filename: &str) -> Option<CapturedRun> {
        run_program_capturing_inner(src, Some(filename))
    }

    fn run_program_capturing_inner(src: &str, filename: Option<&str>) -> Option<CapturedRun> {
        use karac::codegen::{compile_to_object_with_options, link_executable};
        use std::sync::atomic::{AtomicU64, Ordering};
        static COUNTER: AtomicU64 = AtomicU64::new(0);

        // Parse errors are programming bugs in the test source, not a
        // legitimate "skip" condition — panic with a clear message so
        // failures surface instead of being swallowed by the downstream
        // `if let Some(out) = out { ... }` accept-on-None pattern.
        let mut parsed = karac::parse(src);
        if !parsed.errors.is_empty() {
            let mut msg = String::from("test source failed to parse:\n");
            for e in &parsed.errors {
                msg.push_str(&format!("  {:?}\n", e));
            }
            panic!("{}", msg);
        }
        // Mirror the real CLI pipeline: desugar (impl-Trait args,
        // parallel assignment, …) runs between parse and resolve, then gated
        // stdlib imports (`import std.secret.{Secret};` etc.) are spliced in
        // before resolve. A no-op for programs with no gated import.
        karac::desugar_program(&mut parsed.program);
        karac::prelude::expand_gated_stdlib_imports(&mut parsed.program);
        let resolved = karac::resolve(&parsed.program);
        let typed = karac::typecheck(&parsed.program, &resolved);
        karac::lower(&mut parsed.program, &typed);
        // Ownership-loaded by default — `karac build` (cli.rs) always
        // passes `pipeline.ownership` to codegen, so a harness that
        // passes `None` leaves the entire RC-fallback boxing surface
        // (`is_rc_fallback_binding` / `rc_fallback_heap_types`) dead
        // across the suite and systematically diverges from shipped
        // binaries on exactly the bindings the ownership checker flags.
        // That blind spot hid the Option[shared] RC-fallback boxing
        // collision (b027fc15 bug 3): every real build of the
        // prepend-builder shape segfaulted while 1100+ E2E tests stayed
        // green. The suite tests what ships.
        let ownership = karac::ownershipcheck(&parsed.program, &typed);
        // And ships only ownership-CLEAN programs — `karac check` rejects
        // on ownership errors, so a test program that flunks the checker
        // feeds codegen input production never reaches (that masked
        // B-2026-07-01-10 for weeks).
        super::common::assert_ownership_clean(&ownership, src);

        // W3.3 — LLJIT dispatch under env-var control. Routes the whole
        // 543-test E2E suite through `LLJITEngine` instead of the AOT
        // object+link+spawn path. Stderr is always empty under this
        // path (the runtime's atexit handler runs at test-binary exit,
        // not per-test) — stderr-dependent assertions need a different
        // approach and are currently the known failure bucket.
        #[cfg(feature = "llvm")]
        if std::env::var("KARAC_TEST_JIT").as_deref() == Ok("1") {
            return jit_dispatch(&parsed.program, filename);
        }

        let id = COUNTER.fetch_add(1, Ordering::Relaxed);
        let obj_path = format!("/tmp/karac_e2e_{}_{}.o", std::process::id(), id);
        let exe_path = format!("/tmp/karac_e2e_{}_{}", std::process::id(), id);

        // Codegen failures are also programming bugs (in the compiler or in
        // the test program) — surface them loudly. Link and exec failures
        // stay as soft-skip because they can fire in environments that
        // lack libkarac_runtime.a or a working linker.
        if let Err(e) = compile_to_object_with_options(
            &parsed.program,
            &obj_path,
            Some(&ownership),
            None,
            filename,
            None,
        ) {
            panic!("codegen failed for test program: {}", e);
        }
        link_executable(&obj_path, &exe_path).ok()?;

        let output = output_with_hang_watchdog(std::process::Command::new(&exe_path))?;

        let _ = std::fs::remove_file(&obj_path);
        let _ = std::fs::remove_file(&exe_path);

        Some(CapturedRun {
            stdout: String::from_utf8_lossy(&output.stdout).to_string(),
            stderr: String::from_utf8_lossy(&output.stderr).to_string(),
            status: output.status,
        })
    }

    /// W3.4 LLJIT dispatch — **subprocess** helper instead of
    /// in-process JIT. Writes the codegen-emitted LLVM IR to a tempfile
    /// and shells out to the `karac_jit_runner` bin target; that helper
    /// runs the LLJIT compile + executes `main` and exits with main's
    /// return code (or with `emit_panic`'s `exit(1)` when a runtime
    /// check fires). `Command::output` via the existing hang-watchdog
    /// captures stdout + stderr + exit code identically to the AOT path.
    ///
    /// **Why subprocess rather than in-process (W3.3 → W3.4).** W3.3 ran
    /// the JIT in the test runner itself. That works for the 134 tests
    /// that don't panic, but tests which *intentionally* trip a bounds
    /// check, map-miss, or runtime abort terminate the runner via
    /// `exit(1)` / `abort()`, killing the whole `cargo test` invocation.
    /// Subprocess isolation collapses two known stop-point classes —
    /// panic-asserting tests **and** stderr-atexit `?`-trace tests (the
    /// runtime's atexit printer now fires on the child's exit, not on
    /// test-binary exit) — into a non-issue.
    ///
    /// The "always-JIT" promise lives in production (users running
    /// `karac run foo.kara` get true in-process JIT) and in the direct
    /// engine-driven tests under `tests/lljit_prototype.rs` /
    /// `tests/lljit_e2e.rs`. The codegen suite uses subprocess JIT
    /// only as a test-runner artifact, parallel to how the AOT codegen
    /// suite uses subprocess-execed binaries.
    #[cfg(feature = "llvm")]
    fn jit_dispatch(program: &karac::ast::Program, filename: Option<&str>) -> Option<CapturedRun> {
        use karac::codegen::compile_to_ir_with_options;
        use std::io::Write;
        use std::sync::atomic::{AtomicU64, Ordering};
        static COUNTER: AtomicU64 = AtomicU64::new(0);

        let _ = super::force_link_karac_runtime();

        // Codegen failures are programming bugs in the compiler or test
        // — surface loudly, mirroring the AOT path's `panic!` on
        // `compile_to_object` failure. `filename` is threaded through
        // so `?`-propagation traces print `<file>:<line>:<col>`
        // consistently with the AOT path.
        let ir = match compile_to_ir_with_options(program, None, None, filename, None) {
            Ok(ir) => ir,
            Err(e) => panic!("compile_to_ir failed for JIT dispatch: {}", e),
        };

        let id = COUNTER.fetch_add(1, Ordering::Relaxed);
        let ir_path = format!("/tmp/karac_jit_ir_{}_{}.ll", std::process::id(), id);
        {
            let mut f = std::fs::File::create(&ir_path).expect("create IR tempfile");
            f.write_all(ir.as_bytes()).expect("write IR");
        }

        // `CARGO_BIN_EXE_<name>` is a cargo-set compile-time env var
        // resolving to the helper binary's path. Cargo guarantees the
        // bin target is built before the test crate when both share
        // the workspace — no runtime path-hunting needed.
        let runner = env!("CARGO_BIN_EXE_karac_jit_runner");
        let mut cmd = std::process::Command::new(runner);
        cmd.arg(&ir_path);

        let output = output_with_hang_watchdog(cmd);

        let _ = std::fs::remove_file(&ir_path);

        let output = output?;
        Some(CapturedRun {
            stdout: String::from_utf8_lossy(&output.stdout).to_string(),
            stderr: String::from_utf8_lossy(&output.stderr).to_string(),
            status: output.status,
        })
    }

    /// Historical alias from when the default harness passed
    /// `ownership: None`. `run_program` is ownership-loaded now (see
    /// `run_program_capturing_inner`), so this just delegates — kept so
    /// the tests written against the split read unchanged and the name
    /// keeps documenting *why* those tests exist (they exercise
    /// RC-fallback-flagged shapes).
    fn run_program_with_ownership(src: &str) -> Option<String> {
        run_program(src)
    }

    #[test]
    fn test_e2e_print_integer() {
        let out = run_program("fn main() { println(42); }");
        if let Some(out) = out {
            assert_eq!(out.trim(), "42");
        }
    }

    #[test]
    fn test_e2e_print_bool() {
        let out = run_program("fn main() { println(true); }");
        if let Some(out) = out {
            assert_eq!(out.trim(), "true");
        }
    }

    #[test]
    fn test_e2e_float_shortest_roundtrip_formatting() {
        // AOT floats render with Rust's shortest-round-trip `{}` (via
        // `karac_runtime_f64_to_str`), matching the interpreter — not C
        // `printf("%g")`'s 6 significant figures. Covers all four lowering
        // sites: `println`, f-string interpolation, struct `Display`, plus
        // the special values (`%g` rendered `nan` lowercase). Each line is
        // exactly what `karac run` prints for the same program.
        let out = run_program(
            "struct P { a: f64, b: f32 }\n\
             fn main() {\n\
                 println(7.0 / 3.0);\n\
                 println(1.0);\n\
                 println(100.0);\n\
                 println(0.1);\n\
                 println(f\"x={2.0 / 3.0}\");\n\
                 let p = P { a: 3.141592653589793, b: 1.5 };\n\
                 println(f\"{p.a} {p.b}\");\n\
                 let nan: f64 = 0.0 / 0.0;\n\
                 println(nan);\n\
                 let inf: f64 = 1.0 / 0.0;\n\
                 println(inf);\n\
             }\n",
        );
        if let Some(out) = out {
            assert_eq!(
                out,
                "2.3333333333333335\n1\n100\n0.1\nx=0.6666666666666666\n\
                 3.141592653589793 1.5\nNaN\ninf\n",
                "AOT float formatting must match the interpreter's shortest-round-trip output",
            );
        }
    }

    #[test]
    fn test_e2e_borrow_return_let_bound() {
        // B-2026-06-07-5: returning a borrow (`-> ref T`) — a field reached
        // through a `ref` param (String + scalar) and a forwarded `ref`
        // param — derefs correctly at a let-bound caller.
        let out = run_program(
            "struct User { name: String, age: i64 }\n\
             fn name_of(u: ref User) -> ref String { u.name }\n\
             fn age_of(p: ref User) -> ref i64 { p.age }\n\
             fn fwd(s: ref String) -> ref String { s }\n\
             fn main() {\n\
             \x20   let u = User { name: \"ada\", age: 36 };\n\
             \x20   let n = name_of(u); println(n);\n\
             \x20   let a = age_of(u); println(a);\n\
             \x20   let s = \"hello\"; let f = fwd(s); println(f);\n\
             }\n",
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "ada\n36\nhello");
        }
    }

    #[test]
    fn test_e2e_borrow_return_local_read_methods() {
        // B-2026-06-07-5 residue: read-only methods BEYOND `len`/`is_empty` on
        // a borrow-LOCAL (`let n = sid(s)`, registered in `ref_params`) now
        // dispatch through the value-receiver Vec/String path
        // (`compile_vec_method`), reading through the borrow via
        // `get_data_ptr`'s ref-deref. Before the fix these fell through to
        // "no handler for method X on variable n" — only `len`/`is_empty` had a
        // dedicated borrow-local arm. Covers String `starts_with`/`is_empty`
        // and Vec `get`/`first`/`last`.
        let out = run_program(
            "fn sid(s: ref String) -> ref String { s }\n\
             fn vid(v: ref Vec[i64]) -> ref Vec[i64] { v }\n\
             fn main() {\n\
             \x20   let s: String = \"hello world\";\n\
             \x20   let n = sid(s);\n\
             \x20   println(n.starts_with(\"hello\"));\n\
             \x20   println(n.is_empty());\n\
             \x20   let xs: Vec[i64] = [10, 20, 30];\n\
             \x20   let m = vid(xs);\n\
             \x20   match m.get(1) { Some(x) => println(x), None => println(0 - 1) }\n\
             \x20   match m.first() { Some(x) => println(x), None => println(0 - 1) }\n\
             \x20   match m.last() { Some(x) => println(x), None => println(0 - 1) }\n\
             }\n",
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "true\nfalse\n20\n10\n30");
        }
    }

    #[test]
    fn e2e_string_ends_with() {
        // `String.ends_with(suffix) -> bool` — memcmp of the trailing
        // `suffix.len` bytes (the `recv.data + (recv_len - suffix_len)` offset).
        // Empty suffix is always true; an over-long suffix is false (length
        // guard). Must match `karac run`.
        if let Some(out) = run_program(
            "fn main() {\n\
             \x20   let s: String = \"hello world\";\n\
             \x20   println(s.ends_with(\"world\"));\n\
             \x20   println(s.ends_with(\"hello\"));\n\
             \x20   println(s.ends_with(\"\"));\n\
             \x20   println(s.ends_with(\"this is far too long to fit\"));\n\
             }\n",
        ) {
            assert_eq!(out, "true\nfalse\ntrue\nfalse\n");
        }
    }

    #[test]
    fn test_e2e_borrow_return_if_multi_source() {
        // Tier 2 (B-2026-06-07-5): `longer`-style `if` over two `ref`
        // params returns a borrow from whichever branch runs — phi of
        // pointers, deref'd correctly at the let-bound caller.
        let out = run_program(
            "fn longer(a: ref String, b: ref String) -> ref String {\n\
             \x20   if a.len() > b.len() { a } else { b }\n\
             }\n\
             fn main() {\n\
             \x20   let x = \"hi\"; let y = \"wordy\";\n\
             \x20   let n = longer(x, y); println(n);\n\
             \x20   let p = \"aaaaaa\"; let q = \"bb\";\n\
             \x20   let m = longer(p, q); println(m);\n\
             }\n",
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "wordy\naaaaaa");
        }
    }

    #[test]
    fn test_e2e_borrow_return_method_accessor() {
        // B-2026-06-07-5 method-ref: `ref self -> ref T` accessors. The
        // call result is bound as a ref-local (via the lowering span table)
        // and derefs correctly at use.
        let out = run_program(
            "struct User { name: String, age: i64 }\n\
             impl User {\n\
             \x20   fn name(ref self) -> ref String { self.name }\n\
             \x20   fn age(ref self) -> ref i64 { self.age }\n\
             }\n\
             fn main() {\n\
             \x20   let u = User { name: \"alice\", age: 30 };\n\
             \x20   let n = u.name(); println(n);\n\
             \x20   let a = u.age(); println(a);\n\
             }\n",
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "alice\n30");
        }
    }

    #[test]
    fn test_e2e_method_ref_struct_arg() {
        // B-2026-06-12-8: a struct-typed `ref`/`mut ref` NON-receiver arg in a
        // METHOD call must be passed by address, not by value. The method-call
        // arg-lowering path used to emit the struct by value into a `ptr` param
        // slot (invalid IR / module-verify failure). Two halves to the fix:
        //   (1) ownership no longer classifies a `ref`/`mut ref` method arg as a
        //       container-store consume, so the borrowed binding is NOT spuriously
        //       RC-promoted (which boxed it on the heap and segfaulted at use);
        //   (2) codegen passes the arg's address for a `ref`/`mut ref` struct param.
        // Covers a `ref` arg (read), a `mut ref` arg (write-through, observed
        // back in the caller), and an accumulating loop reusing the borrow.
        let out = run_program(
            "struct Acc { total: i64 }\n\
             struct Src { val: i64 }\n\
             impl Acc {\n\
             \x20   fn add(mut ref self, s: ref Src) { self.total = self.total + s.val; }\n\
             \x20   fn drain(mut ref self, s: mut ref Src) { self.total = self.total + s.val; s.val = 0; }\n\
             }\n\
             fn main() {\n\
             \x20   let mut a: Acc = Acc { total: 0 };\n\
             \x20   let mut s: Src = Src { val: 5 };\n\
             \x20   let mut i: i64 = 0;\n\
             \x20   while i < 4 { a.add(s); i = i + 1; }\n\
             \x20   println(f\"{a.total}\");\n\
             \x20   a.drain(s);\n\
             \x20   println(f\"{a.total}\");\n\
             \x20   println(f\"{s.val}\");\n\
             \x20   a.add(Src { val: 7 });\n\
             \x20   println(f\"{a.total}\");\n\
             }\n",
        );
        if let Some(out) = out {
            // 4*5=20; +5=25, s.val zeroed; +7=32.
            assert_eq!(out.trim(), "20\n25\n0\n32");
        }
    }

    #[test]
    fn test_e2e_borrow_return_match_multi_source() {
        // Tier sibling of the `if` arm (B-2026-06-07-5): a `match` over a
        // scalar selector returns a borrow from whichever arm runs — per-arm
        // pointer phi'd at the merge, deref'd correctly at the let-bound
        // caller. Exercises literal arms + the wildcard catch-all.
        let out = run_program(
            "fn pick(a: ref String, b: ref String, c: ref String, which: i32) -> ref String {\n\
             \x20   match which {\n\
             \x20       0 => a,\n\
             \x20       1 => b,\n\
             \x20       _ => c,\n\
             \x20   }\n\
             }\n\
             fn main() {\n\
             \x20   let x = \"alpha\"; let y = \"beta\"; let z = \"gamma\";\n\
             \x20   let p0 = pick(x, y, z, 0); println(p0);\n\
             \x20   let p1 = pick(x, y, z, 1); println(p1);\n\
             \x20   let p2 = pick(x, y, z, 2); println(p2);\n\
             }\n",
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "alpha\nbeta\ngamma");
        }
    }

