    #[test]
    fn test_e2e_ambient_env_var_question_mark_propagates_as_io_error() {
        // `env.var(x)?` in a `Result[_, IoError]`-returning fn desugars to a
        // match whose Err arm calls `IoError.from(varErr)` via the stdlib
        // `impl From for IoError { fn from(VarError) }` (runtime/stdlib/io.kara)
        // — that conversion impl resolves on the codegen path, so the missing
        // key propagates out as an `IoError` and the caller's match takes the
        // Err arm. Pins that the slice-3a Result construction composes with
        // `?`-propagation + cross-error-type `From` conversion (the idiomatic
        // usage), not just the direct-match form.
        let out = run_program(
            r#"
fn read_it() -> Result[String, IoError] reads(Env) {
    let s: String = env.var("__KARAC_E2E_QMARK_NO_SUCH__")?;
    Ok(s)
}
fn main() reads(Env) {
    match read_it() {
        Ok(v) => { println(v); }
        Err(_) => { println("io-err"); }
    }
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "io-err");
        }
    }

    #[test]
    fn test_e2e_ambient_stdin_read_line_eof_returns_ok_empty() {
        // `Stdin.read_line() -> Result[String, IoError]`. The E2E harness
        // spawns the binary via `Command::output`, which closes the child's
        // stdin — so `read_line` hits immediate EOF and returns `Ok("")`
        // (Rust's `read_line` yields `Ok(0)` with an empty buffer). Lowers
        // through the shared `karac_runtime_stdin_read_line` +
        // `lower_kara_io_result(StringPayload)` path, same as
        // `FileSystem.read_to_string`. The Ok arm binds the String payload
        // and checks `len() == 0`, exercising the full Result/String unpack
        // (payload-typed binding + method dispatch), not just the branch.
        // (Capitalized form is the resolvable surface — the lowercase `stdin`
        // alias is not yet wired into the resolver; see the lowercase-ambient
        // -alias gap entry in phase-7-codegen.md.)
        let out = run_program(
            r#"
fn main() reads(Stdin) {
    match Stdin.read_line() {
        Ok(s) => { if s.len() == 0 { println("eof-ok"); } else { println("got-line"); } }
        Err(_) => { println("io-err"); }
    }
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "eof-ok");
        }
    }

    #[test]
    fn test_e2e_ambient_stdin_read_to_string_eof_returns_ok_empty() {
        // Companion to read_line: `Stdin.read_to_string()` slurps to EOF.
        // With the harness's closed stdin that's the empty string → `Ok("")`.
        let out = run_program(
            r#"
fn main() reads(Stdin) {
    match Stdin.read_to_string() {
        Ok(s) => { if s.len() == 0 { println("eof-ok"); } else { println("got-data"); } }
        Err(_) => { println("io-err"); }
    }
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "eof-ok");
        }
    }

    #[test]
    fn test_stdin_read_line_resolves_and_typechecks_clean() {
        // Full-pipeline check (NOT the `run_program` path, which tolerates
        // resolve/typecheck errors — see the
        // codegen-run_program-bypasses-typecheck hazard). `Stdin.read_line()`
        // must resolve and typecheck cleanly: it is a real stdlib
        // `#[compiler_builtin]` method whose `Result[String, IoError]` return
        // flows to the `Ok(s)` binding so `s.len()` dispatches. Guards against
        // regressing the capitalized surface into a codegen-only "fake pass".
        let src = r#"
fn main() reads(Stdin) {
    match Stdin.read_line() {
        Ok(s) => { let _n = s.len(); }
        Err(_) => {}
    }
}
"#;
        let parsed = karac::parse(src);
        assert!(
            parsed.errors.is_empty(),
            "parse errors: {:?}",
            parsed.errors
        );
        let resolved = karac::resolve(&parsed.program);
        assert!(
            resolved.errors.is_empty(),
            "resolve errors for Stdin.read_line: {:?}",
            resolved.errors
        );
        let typed = karac::typecheck(&parsed.program, &resolved);
        assert!(
            typed.errors.is_empty(),
            "typecheck errors for Stdin.read_line: {:?}",
            typed.errors
        );
    }

    #[test]
    fn test_e2e_stdout_println_interleaves_with_free_println() {
        // `Stdout.println(s)` must share the SAME libc stdout buffer as the
        // free `println` builtin — otherwise the two streams flush in the
        // wrong order. Interleaving free and explicit prints and asserting
        // exact line order is the sharp witness that `Stdout.*` routes
        // through `self.printf_fn` (not a separately-buffered runtime
        // stdout). L646 slice 4b.
        let out = run_program(
            r#"
fn main() {
    println("a");
    Stdout.println("b");
    print("c");
    Stdout.print("d");
    Stdout.println("e");
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out, "a\nb\ncde\n");
        }
    }

    #[test]
    fn test_e2e_stderr_println_writes_to_stderr_not_stdout() {
        // `Stderr.println(s)` lowers to `dprintf(2, …)` — it must land on
        // stderr (fd 2), NOT stdout. Capture both streams and assert the
        // split: the stderr line on stderr, the stdout line on stdout.
        let cap = run_program_capturing(
            r#"
fn main() {
    Stderr.println("to-stderr");
    println("to-stdout");
}
"#,
        );
        if let Some(cap) = cap {
            assert_eq!(cap.stdout.trim(), "to-stdout");
            assert!(
                cap.stderr.contains("to-stderr"),
                "expected 'to-stderr' on stderr, got: {:?}",
                cap.stderr
            );
            assert!(
                !cap.stdout.contains("to-stderr"),
                "stderr content leaked onto stdout: {:?}",
                cap.stdout
            );
        }
    }

    #[test]
    fn test_e2e_main_result_question_and_returns() {
        // B-2026-06-12-9: `main() -> Result[(), E]` used to fail module
        // verification — a `?` early-return (and explicit `return Ok/Err`)
        // emitted the `{tag, …}` Result aggregate against `main`'s `i32` C
        // signature. The fix adapts every Result-returning site in `main` to a
        // process exit code per design.md § Entry Point: `Ok` exits 0, `Err(e)`
        // prints `Error: {e}\n` to stderr (via E's Display) and exits 1.

        // (a) `?` success path — body continues, `Ok(())` tail exits 0.
        let ok = run_program_capturing(
            r#"
#[derive(Display)]
enum MyErr { Bad }
fn helper(x: i64) -> Result[i64, MyErr] {
    if x < 0 { return Err(MyErr.Bad); }
    Ok(x + 1)
}
fn main() -> Result[(), MyErr] {
    let v = helper(5)?;
    println(v);
    Ok(())
}
"#,
        );
        if let Some(cap) = ok {
            assert_eq!(cap.stdout.trim(), "6");
            assert_eq!(
                cap.status.code(),
                Some(0),
                "Ok path must exit 0; stderr={:?}",
                cap.stderr
            );
        }

        // (b) `?` error-propagation path — Err exits 1 with `Error: <Display>`
        // on stderr (a unit enum renders as its bare variant name).
        let q_err = run_program_capturing(
            r#"
#[derive(Display)]
enum MyErr { Bad }
fn helper(x: i64) -> Result[i64, MyErr] {
    if x < 0 { return Err(MyErr.Bad); }
    Ok(x + 1)
}
fn main() -> Result[(), MyErr] {
    let v = helper(0 - 5)?;
    println(v);
    Ok(())
}
"#,
        );
        if let Some(cap) = q_err {
            assert_eq!(
                cap.status.code(),
                Some(1),
                "Err path must exit 1; stdout={:?} stderr={:?}",
                cap.stdout,
                cap.stderr
            );
            assert!(
                cap.stderr.contains("Error: Bad"),
                "expected 'Error: Bad' on stderr, got: {:?}",
                cap.stderr
            );
            assert!(
                cap.stdout.trim().is_empty(),
                "Err path must not print the unwrapped value to stdout: {:?}",
                cap.stdout
            );
        }

        // (c) explicit `return Err(struct)` — struct Display, stderr/stdout
        // split, exit 1. Prior stdout work (`println` before the return) is
        // still observable.
        let ret_err = run_program_capturing(
            r#"
#[derive(Display)]
struct IoError { code: i64 }
fn main() -> Result[(), IoError] {
    println("before");
    return Err(IoError { code: 42 });
}
"#,
        );
        if let Some(cap) = ret_err {
            assert_eq!(cap.status.code(), Some(1), "stderr={:?}", cap.stderr);
            assert_eq!(cap.stdout.trim(), "before");
            assert!(
                cap.stderr.contains("Error: IoError { code: 42 }"),
                "expected struct Display on stderr, got: {:?}",
                cap.stderr
            );
            assert!(
                !cap.stdout.contains("Error:"),
                "error line leaked onto stdout: {:?}",
                cap.stdout
            );
        }

        // (d) tail `Err` with a scalar error type — exits 1, `Error: 99`.
        let tail_err = run_program_capturing(
            r#"
fn pick(x: i64) -> Result[(), i64] {
    if x > 0 { return Ok(()); }
    Err(99)
}
fn main() -> Result[(), i64] {
    pick(0 - 1)
}
"#,
        );
        if let Some(cap) = tail_err {
            assert_eq!(cap.status.code(), Some(1), "stderr={:?}", cap.stderr);
            assert!(
                cap.stderr.contains("Error: 99"),
                "expected 'Error: 99' on stderr, got: {:?}",
                cap.stderr
            );
        }
    }

    #[test]
    fn e2e_baked_stdlib_enum_display_and_qualified_match() {
        // B-2026-06-14 — `#[derive(Display)]` on a baked-stdlib enum
        // (`IoError`, `VarError`) renders correctly in the interpreter but, in
        // AOT, the enum had no codegen layout (never seeded, never in the user
        // `program_snapshot`): construction fell to an `i64 0` placeholder
        // (display printed `0`), a payload-variant `match` couldn't bind the
        // payload, and `main() -> Result[(), IoError]` printed `Error: 0`.
        // Companion: the bare-variant `Other` collides across
        // IoError/Utf8Error/TcpError/TlsError, so qualified construction/match
        // picked a wrong tag by HashMap order. Fix: seed the IoError layout +
        // STDLIB_PROGRAMS variant fallback in `emit_enum_display_fn` + honor the
        // qualified `Enum.Variant` path in construction and match.

        // (a) f-string / println Display of a payload + a unit variant.
        let disp = run_program(
            "fn main() {\n\
             \x20   let e = IoError.Other(\"disk full\");\n\
             \x20   println(f\"{e}\");\n\
             \x20   let n = IoError.NotFound;\n\
             \x20   println(f\"{n}\");\n\
             \x20   let v = VarError.NotPresent;\n\
             \x20   println(f\"{v}\");\n\
             }\n",
        );
        if let Some(out) = disp {
            assert_eq!(out, "Other(disk full)\nNotFound\nNotPresent\n");
        }

        // (b) qualified match — unit, payload (binds `m`), collision-prone
        // `PermissionDenied` (shared with TlsError), and a wildcard tail.
        let matched = run_program(
            "fn classify(e: IoError) -> String {\n\
             \x20   match e {\n\
             \x20       IoError.NotFound => { \"nf\" }\n\
             \x20       IoError.PermissionDenied => { \"pd\" }\n\
             \x20       IoError.Other(m) => { f\"other:{m}\" }\n\
             \x20       _ => { \"rest\" }\n\
             \x20   }\n\
             }\n\
             fn main() {\n\
             \x20   println(classify(IoError.NotFound));\n\
             \x20   println(classify(IoError.PermissionDenied));\n\
             \x20   println(classify(IoError.Other(\"disk full\")));\n\
             \x20   println(classify(IoError.Interrupted));\n\
             }\n",
        );
        if let Some(out) = matched {
            assert_eq!(out, "nf\npd\nother:disk full\nrest\n");
        }

        // (c) `main() -> Result[(), IoError]` returning a payload Err — the
        // runtime prints `Error: {e}` on stderr (rendered, not `Error: 0`) and
        // exits 1.
        let main_err = run_program_capturing(
            "fn main() -> Result[(), IoError] {\n\
             \x20   Err(IoError.Other(\"disk full\"))\n\
             }\n",
        );
        if let Some(cap) = main_err {
            assert_eq!(cap.status.code(), Some(1), "stderr={:?}", cap.stderr);
            assert!(
                cap.stderr.contains("Error: Other(disk full)"),
                "expected rendered baked-enum Err on stderr, got: {:?}",
                cap.stderr
            );
        }
    }

    #[test]
    fn test_e2e_stdout_print_and_flush() {
        // `Stdout.print` (no newline) + `Stdout.flush()` + `Stdout.println`.
        // flush lowers to `fflush(NULL)` and must run without crashing; the
        // accumulated output is the concatenation with the final newline.
        let out = run_program(
            r#"
fn main() {
    Stdout.print("x");
    Stdout.flush();
    Stdout.println("y");
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out, "xy\n");
        }
    }

    #[test]
    fn test_stdout_stderr_methods_resolve_and_typecheck_clean() {
        // Full-pipeline check (NOT `run_program`, which tolerates
        // resolve/typecheck errors). The capitalized `Stdout.*` / `Stderr.*`
        // forms are real stdlib `#[compiler_builtin]` methods and must
        // resolve + typecheck cleanly.
        let src = r#"
fn main() {
    Stdout.print("a");
    Stdout.println("b");
    Stdout.flush();
    Stderr.print("c");
    Stderr.println("d");
    Stderr.flush();
}
"#;
        let parsed = karac::parse(src);
        assert!(
            parsed.errors.is_empty(),
            "parse errors: {:?}",
            parsed.errors
        );
        let resolved = karac::resolve(&parsed.program);
        assert!(
            resolved.errors.is_empty(),
            "resolve errors for Stdout/Stderr methods: {:?}",
            resolved.errors
        );
        let typed = karac::typecheck(&parsed.program, &resolved);
        assert!(
            typed.errors.is_empty(),
            "typecheck errors for Stdout/Stderr methods: {:?}",
            typed.errors
        );
    }

    #[test]
    fn test_e2e_with_provider_override_rand_next_u64_scalar() {
        // `with_provider[RandomSource]` override of `next_u64` — a method with
        // NO vtable slot before this slice (it errored loudly at codegen,
        // `test_ambient_override_of_nonvtable_method_errors_loudly`). Now it
        // gets a slot + a runtime override-vs-default branch. Scalar (i64)
        // phi shape. The override returns a fixed 777, observed BOTH directly
        // and cross-boundary (`draw()` is a separate fn, so dispatch is via
        // the runtime provider stack, not lexical scope). After the scope
        // pops, the real FFI default resumes (two draws differ → "false").
        // `karac run` of the same source matches.
        let out = run_program(
            r#"
struct FakeRng { v: i64 }
impl FakeRng { fn next_u64(ref self) -> i64 { self.v } }
fn draw() -> i64 reads(RandomSource) { rand.next_u64() }
fn main() reads(RandomSource) {
    with_provider[RandomSource](FakeRng { v: 777 }, || {
        println(draw());
        println(rand.next_u64());
    });
    println(rand.next_u64() == rand.next_u64());
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "777\n777\nfalse");
        }
    }

    #[test]
    fn test_e2e_with_provider_override_env_var_result() {
        // `with_provider[Env]` override of `var` — `Result[String, VarError]`
        // return, exercising the dispatch-branch phi at an *enum struct* type
        // (the generalization beyond the old hardcoded-i64 phi). The override
        // returns `Ok("mocked")` for any key; after the scope pops, the real
        // FFI default returns `Err(VarError.NotPresent)` for an unset key.
        // The call lives in a separate fn (`rv`) so dispatch is cross-boundary.
        let out = run_program(
            r#"
struct FakeEnv {}
impl FakeEnv { fn var(self, name: String) -> Result[String, VarError] { Ok("mocked") } }
fn rv() -> String reads(Env) {
    match env.var("ANYTHING") { Ok(s) => s, Err(e) => "missing" }
}
fn main() reads(Env) {
    with_provider[Env](FakeEnv {}, || { println(rv()); });
    match env.var("KARA_DEFINITELY_UNSET_XYZ") {
        Ok(s) => println(s),
        Err(e) => println("unset-default"),
    }
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "mocked\nunset-default");
        }
    }

    #[test]
    fn test_e2e_with_provider_override_env_args_vec() {
        // `with_provider[Env]` override of `args` — `Vec[String]` return, the
        // dispatch-branch phi at a *Vec struct* type. This is the exact case
        // the old `test_ambient_override_of_nonvtable_method_errors_loudly`
        // pinned as a LOUD error; the slice lifts that to a working override.
        // (The provider body builds the Vec via an explicitly-typed
        // `Vec.new()` + push — an array literal as a `Vec[String]` return is a
        // separate, pre-existing codegen-coercion gap, tracked in
        // phase-7-codegen.md, orthogonal to override dispatch.) Cross-boundary
        // call in `count()`.
        let out = run_program(
            r#"
struct FakeEnv {}
impl FakeEnv {
    fn args(self) -> Vec[String] {
        let mut v: Vec[String] = Vec.new();
        v.push("alpha");
        v.push("beta");
        v.push("gamma");
        v
    }
}
fn count() -> i64 reads(Env) { env.args().len() }
fn main() reads(Env) {
    with_provider[Env](FakeEnv {}, || { println(count()); });
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "3");
        }
    }

    #[test]
    fn test_e2e_with_provider_ambient_override() {
        // `with_provider[Clock](FakeClock {}, || ...)` overrides the
        // ambient `Clock` resource with a statically-typed provider. The
        // capitalized `Clock.now()` call inside the body must dispatch to
        // the override's `FakeClock.now` (returning 42), NOT the builtin
        // `karac_runtime_clock_now` FFI. Static-monomorphization path —
        // the override decision is entirely compile-time (no runtime
        // provider vtable). Mirrors the interpreter's ambient override
        // (`karac run` of the same source prints 42) and the repl
        // `:provide Clock = FakeClock {}` flow. Regression guard for the
        // historical `with_provider: unknown effect resource 'Clock'`
        // codegen error (and the capitalized-Clock.now()-returns-0 bug).
        let out = run_program(
            r#"
struct FakeClock {}
impl FakeClock { fn now(ref self) -> i64 { 42 } }
fn main() reads(Clock) {
    with_provider[Clock](FakeClock {}, || {
        println(Clock.now());
    });
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "42");
        }
    }

    #[test]
    fn test_e2e_with_provider_trait_less_user_resource() {
        // Gap (c): a *trait-less* user resource (`effect resource R;` with no
        // `: T`) overridden by a statically-typed provider. Unlike a prelude
        // ambient resource (`Clock`), a trait-less user resource has no
        // canonical method order and no FFI default — its method order is
        // derived from the override type's inherent impl, and every call
        // dispatches through the active override. Two methods exercise the
        // vtable-index path, and the call lives in a *separate function*
        // (`tally`) so dispatch is cross-boundary (the runtime provider
        // stack, not lexical scope). Before the fix this errored at codegen
        // with "resource 'AuditLog' has no provider trait". `karac run` of
        // the same source prints 12.
        let out = run_program(
            r#"
effect resource AuditLog;
struct FakeLog { n: i64 }
impl FakeLog {
    fn count(self) -> i64 { self.n }
    fn bump(self) -> i64 { self.n + 7 }
}
fn tally() -> i64 reads(AuditLog) {
    AuditLog.count() + AuditLog.bump()
}
fn main() reads(AuditLog) {
    with_provider[AuditLog](FakeLog { n: 1 }, || {
        println(tally());
    });
}
"#,
        );
        if let Some(out) = out {
            // count() = n = 1; bump() = n + 7 = 8; sum = 9.
            assert_eq!(out.trim(), "9");
        }
    }

    #[test]
    fn test_e2e_with_provider_trait_less_call_ctor() {
        // Sibling to the gap-(c) test above, but the provider is bound to a
        // *constructor call* (`let p = make_log();`) rather than an inline
        // struct literal. The eager ambient-vtable pre-pass must resolve `p`'s
        // type from `make_log`'s declared return type — it used to recognize
        // only struct-literal providers, so this errored at codegen with "no
        // method order for resource". `karac run` prints 9.
        let out = run_program(
            r#"
effect resource AuditLog;
struct FakeLog { n: i64 }
impl FakeLog { fn count(self) -> i64 { self.n } }
fn make_log() -> FakeLog { FakeLog { n: 9 } }
fn tally() -> i64 reads(AuditLog) { AuditLog.count() }
fn main() reads(AuditLog) {
    let p = make_log();
    with_provider[AuditLog](p, || { println(tally()); });
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "9");
        }
    }

    #[test]
    fn test_e2e_with_provider_nested_block_closures_two_resources() {
        // Two trait-less user resources via NESTED `with_provider`, where each
        // provider is bound in the OUTER block and the closures are
        // block-bodied. The eager pre-pass must inherit the outer-block
        // provider bindings into the nested-block scan — it used to reset the
        // binding map per block, so the inner `with_provider[ResB](pb, ...)`
        // couldn't resolve `pb` and dropped the override ("no method order for
        // ResB"). `karac run` prints 1 then 2.
        let out = run_program(
            r#"
effect resource ResA;
effect resource ResB;
struct A { t: i64 }
impl A { fn now(self) -> i64 { self.t } }
struct B { t: i64 }
impl B { fn now(self) -> i64 { self.t } }
fn main() reads(ResA) reads(ResB) {
    let pa = A { t: 1 };
    let pb = B { t: 2 };
    with_provider[ResA](pa, || {
        with_provider[ResB](pb, || {
            println(ResA.now());
            println(ResB.now());
        });
    });
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "1\n2");
        }
    }

    /// phase-7 — an explicit valueless `return;` reachable in `main` must
    /// emit `ret i32 0` (main lowers to a C-ABI `i32 main()`), not
    /// `ret void`. Before the fix this failed module verification
    /// ("ret void / i32"); the implicit end-of-main already returned 0,
    /// so only the *explicit* `return;` path was broken. Exercises the
    /// nested (while + if) reachable case, and asserts the early return
    /// actually stops execution.
    #[test]
    fn test_e2e_explicit_return_in_main_exits_zero() {
        let out = run_program(
            "fn main() {\n\
             \x20   let mut i = 0;\n\
             \x20   while i < 5 {\n\
             \x20       if i == 2 { println(99); return; }\n\
             \x20       println(i);\n\
             \x20       i = i + 1;\n\
             \x20   }\n\
             \x20   println(0 - 1);\n\
             }",
        );
        if let Some(out) = out {
            // i=0,1 printed; i=2 prints 99 then returns; the post-loop
            // `println` never runs.
            assert_eq!(out.trim(), "0\n1\n99");
        }
    }

    /// IR pin for the same fix: the explicit `return;` in `main` lowers to
    /// `ret i32 0`. A bare `fn main() { return; }` would otherwise verify-
    /// fail, so reaching this assertion at all already proves the fix; the
    /// grep pins the exact instruction.
    #[test]
    fn test_ir_explicit_return_in_main_is_ret_i32_zero() {
        let ir = ir_for("fn main() { return; }");
        let body = function_body(&ir, "main").expect("main body");
        assert!(
            body.contains("ret i32 0"),
            "explicit return in main should emit `ret i32 0`; body was:\n{}",
            body
        );
        assert!(
            !body.contains("ret void"),
            "main must not emit `ret void`; body was:\n{}",
            body
        );
    }

    /// gap-d IR pin: `unreachable()` (type `!`) as the tail of a
    /// value-returning fn must lower to an `unreachable` terminator, NOT a
    /// `ret <i64 placeholder>`. Before the fix, `boom`'s body emitted
    /// `ret i64 0` against the `{ i64 }` (FakeClock) return type and failed
    /// module verification ("return type does not match operand type").
    /// `boom` is private, so its `panics` effect is inferred — no annotation
    /// needed.
    #[test]
    fn test_ir_diverge_unreachable_tail_emits_unreachable_not_ret() {
        let ir = ir_for(
            "struct FakeClock { t: i64 }\n\
             fn boom() -> FakeClock { unreachable() }\n\
             fn main() { let _c = boom(); }",
        );
        let body = function_body(&ir, "boom").expect("boom body");
        assert!(
            body.contains("unreachable"),
            "diverging tail should emit an `unreachable` terminator; body was:\n{}",
            body
        );
        assert!(
            !body.contains("ret i64"),
            "diverging tail must not emit `ret i64 <placeholder>` against the struct \
             return type; body was:\n{}",
            body
        );
    }

    /// gap-d: a diverging arm (`unreachable()`) must not collapse an
    /// `if`-expression's value to the const-0 placeholder — the live arm's
    /// value is the result. Before the fix this printed `0`.
    #[test]
    fn test_e2e_diverge_if_branch_yields_live_value() {
        let out = run_program(
            "fn pick(n: i64) -> i64 { if n > 0 { n } else { unreachable() } }\n\
             fn main() { println(pick(7)); }",
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "7");
        }
    }

    /// gap-d: same for a `match` with a diverging arm — the single live arm's
    /// value flows through (one-incoming phi), and the struct-returning fn
    /// compiles (proving the `unreachable()` arm emitted a terminator, not a
    /// `ret` mismatch).
    #[test]
    fn test_e2e_diverge_match_arm_in_struct_returning_fn() {
        let out = run_program(
            "struct Point { x: i64 }\n\
             fn make(n: i64) -> Point {\n\
             \x20   match n {\n\
             \x20       0 => Point { x: 42 },\n\
             \x20       _ => unreachable(),\n\
             \x20   }\n\
             }\n\
             fn main() { let p = make(0); println(p.x); }",
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "42");
        }
    }

    /// B-2026-07-09-9: `panic()` is a diverging prelude primitive, lowered
    /// inline via `compile_diverge` exactly like `todo`/`unreachable` — so a
    /// `panic()` tail in a value-returning fn emits an `unreachable`
    /// terminator, not a `ret <placeholder>` mismatch.
    #[test]
    fn test_ir_panic_tail_emits_unreachable_not_ret() {
        let ir = ir_for(
            "struct FakeClock { t: i64 }\n\
             fn boom() -> FakeClock { panic(\"kaboom\") }\n\
             fn main() { let _c = boom(); }",
        );
        let body = function_body(&ir, "boom").expect("boom body");
        assert!(
            body.contains("unreachable"),
            "diverging `panic()` tail should emit an `unreachable` terminator; body was:\n{}",
            body
        );
        assert!(
            !body.contains("ret i64"),
            "diverging `panic()` tail must not emit `ret i64 <placeholder>`; body was:\n{}",
            body
        );
    }

    /// B-2026-07-09-9: `panic("msg")` runs end-to-end — exits 1 and surfaces
    /// the user message VERBATIM (no "not yet implemented"/"entered unreachable
    /// code" prefix, which are `todo`/`unreachable`'s defaults).
    #[test]
    fn test_e2e_panic_prints_message_verbatim() {
        if let Some(cap) = run_program_capturing("fn main() { panic(\"kaboom\"); }") {
            assert_eq!(cap.status.code(), Some(1), "stderr={:?}", cap.stderr);
            assert!(
                cap.stdout.contains("kaboom")
                    && !cap.stdout.contains("not yet implemented")
                    && !cap.stdout.contains("entered unreachable code"),
                "panic() must surface its message verbatim; stdout={:?}",
                cap.stdout
            );
        }
    }

    // ── println signedness round-trips ───────────────────────────
    //
    // Pre-fix `println(x: i32)` passed the raw i32 to printf "%lld";
    // LLVM zero-padded the slot to 64 bits and `%lld` read the high
    // bits as 0, producing the *unsigned* representation on negatives
    // (e.g. `-123` printed as `4_294_967_173`). Fix routes narrow ints
    // through `sext + %lld` (signed) or `zext + %llu` (unsigned) based
    // on the source-level type, mirroring `synth_display`. These
    // regression tests pin the signed and unsigned arms at i8 / i16 /
    // i32 / i64 / u8 / u16 / u32 / u64 plus a u64 value > 2^32 to
    // exercise the wide-unsigned arm that pre-fix also misprinted.

    #[test]
    fn test_e2e_print_i32_negative_prints_signed() {
        let out = run_program("fn main() { let x: i32 = -123i32; println(x); }");
        if let Some(out) = out {
            assert_eq!(out.trim(), "-123");
        }
    }

    #[test]
    fn test_e2e_print_i16_negative_prints_signed() {
        let out = run_program("fn main() { let x: i16 = -7i16; println(x); }");
        if let Some(out) = out {
            assert_eq!(out.trim(), "-7");
        }
    }

    #[test]
    fn test_e2e_print_i8_negative_prints_signed() {
        let out = run_program("fn main() { let x: i8 = -7i8; println(x); }");
        if let Some(out) = out {
            assert_eq!(out.trim(), "-7");
        }
    }

    #[test]
    fn test_e2e_print_i64_negative_prints_signed() {
        let out = run_program("fn main() { let x: i64 = -123i64; println(x); }");
        if let Some(out) = out {
            assert_eq!(out.trim(), "-123");
        }
    }

    #[test]
    fn test_e2e_print_u8_prints_unsigned() {
        let out = run_program("fn main() { let x: u8 = 200u8; println(x); }");
        if let Some(out) = out {
            assert_eq!(out.trim(), "200");
        }
    }

    #[test]
    fn test_e2e_u8_cast_to_i32_zero_extends() {
        // 0xff as u8 widened to i32 must yield 255, not -1. Pre-fix
        // `compile_cast` used `build_int_cast` which sign-extends on widening;
        // the load+cast path for `Vec[u8]` / `Slice[u8]` elements produced
        // negative results for any byte ≥ 128. Hot-loop impact on kata-91
        // (`(bytes[i] as i32) - (zero as i32)` for digit math): the extra
        // sext+mask sequence cost ~2 inst/iter vs rust's single ldrb.
        let out = run_program(
            r#"
fn main() {
    let b: u8 = 255u8;
    let x: i32 = b as i32;
    println(x);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "255");
        }
    }

    #[test]
    fn test_e2e_int_to_int_cast_spec_cases() {
        // phase-8 cast slice 5 (int→int verification): the design.md test
        // vectors. Narrowing keeps the low bits (`trunc`); widening sign- or
        // zero-extends per source signedness. Compiled output must match the
        // interpreter (and these documented values).
        let out = run_program(
            r#"
fn main() {
    println(0x1FFi32 as u8);   // narrow: low 8 bits -> 255
    println(-1i32 as u8);      // narrow: 0xFF -> 255
    println(300i32 as i8);     // narrow: 300 & 0xFF = 0x2C -> 44
    println(-1i8 as u8);       // same width reinterpret -> 255
    let a: i8 = -5;
    println(a as i64);         // signed widen (sext) -> -5
    let u: u8 = 200;
    println(u as i64);         // unsigned widen (zext) -> 200
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "255\n255\n44\n255\n-5\n200");
        }
    }

    #[test]
    fn test_e2e_int_to_float_casts() {
        // phase-8 cast slice 6 (int→float verification): signed via sitofp,
        // unsigned via uitofp, never panics. Large values round to nearest —
        // shown via a round-trip through a value not representable in f64
        // (2^60 + 1 → 2^60), which prints as a stable integer (no float-format
        // dependence).
        let out = run_program(
            r#"
fn main() {
    println(5i64 as f64);
    println(255u8 as f64);
    let x: i64 = 1152921504606846977;
    println((x as f64) as i64);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "5\n255\n1152921504606846976");
        }
    }

    #[test]
    fn test_e2e_float_to_float_casts() {
        // phase-8 cast slice 7 (float→float verification): widening is implicit
        // (f32→f64 is value-preserving), narrowing via `as` rounds, and
        // narrowing overflow produces ±Infinity per IEEE 754 (not a trap).
        let out = run_program(
            r#"
fn main() {
    let f: f32 = 2.5;
    println(f as f64);
    println(1.5f64 as f32);
    println(1e300f64 as f32);
    println(-1e300f64 as f32);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "2.5\n1.5\ninf\n-inf");
        }
    }

    #[test]
    fn test_e2e_u8_slice_index_cast_to_i32_zero_extends() {
        // Same fix exercised through the kata-91 shape — `bytes: Vec[u8]`,
        // `bytes[i] as i32`. The `expr_is_unsigned_int` `Index` arm reads
        // the element TypeExpr off `var_elem_type_exprs` and drives the
        // zext-widening lane.
        let out = run_program(
            r#"
fn main() {
    let mut bs: Vec[u8] = Vec.new();
    bs.push(200u8);
    let x: i32 = (bs[0] as i32) - (b'0' as i32);
    println(x);
}
"#,
        );
        if let Some(out) = out {
            // 200 - 48 ('0') = 152. Pre-fix the sext load + sext cast made
            // bs[0] = -56 (i8) → -56 - 48 = -104.
            assert_eq!(out.trim(), "152");
        }
    }

    #[test]
    fn test_ir_u8_cast_to_i32_emits_zext() {
        // IR-level pin: the cast must lower to a zext, not a sext. ARM
        // backend fuses `load i8` + `zext i8 to i32` into `ldrb` — that's
        // the assembly-level win we're chasing in kata-91's hot loop.
        let ir = ir_for(
            r#"
fn main() {
    let b: u8 = 200u8;
    let x: i32 = b as i32;
    println(x);
}
"#,
        );
        assert!(
            ir.contains("zext i8") || ir.contains("zext nneg i8"),
            "expected zext widening from i8 in IR, got no match in:\n{}",
            ir
        );
    }

