    #[test]
    fn test_e2e_string_to_cstring_as_ptr_feeds_libc_puts() {
        // The motivating use case CString exists for (design.md § C-String
        // Literals): hand a RUNTIME-CONSTRUCTED string to a C function. Unlike
        // the `c"..."` literal (rodata), the buffer here is built at run time
        // (concatenation), so it needs the owning `CString` + its appended NUL.
        // Build → to_cstring → as_ptr → libc `puts` → link → run.
        let src = r#"
effect resource Console;

unsafe extern "C" {
    fn puts(s: *const u8) -> i32 with writes(Console);
}

pub fn main() with writes(Console) {
    let s = "hello, " + "world";
    match s.to_cstring() {
        Ok(cs) => { puts(cs.as_ptr()); }
        Err(_) => { println("ERR"); }
    }
}
"#;
        let out = run_program(src);
        if let Some(out) = out {
            assert_eq!(out, "hello, world\n");
        }
    }

    #[test]
    fn test_e2e_string_marshaling_round_trips_through_cstring() {
        // The complete FFI String-marshaling loop (phase-8 "FFI — String
        // marshaling"): a runtime-built Kāra `String` crosses the C boundary as
        // a NUL-terminated `char*` and comes back losslessly. Outbound via the
        // OWNING `CString` (`to_cstring` appends the NUL, owns the heap buffer)
        // + `as_ptr`; inbound via `CStr.from_ptr` (borrows the caller's memory,
        // libc `strlen` recomputes the length) + `to_string` (copies, validates
        // UTF-8). The two halves are exercised individually elsewhere; this pins
        // that they COMPOSE into a String→char*→String identity. `cs` outlives
        // the borrowed pointer (drops at end of `main`), so `p` stays valid.
        let src = r#"
fn main() {
    let s = "hello, " + "world";
    let cs = s.to_cstring().unwrap();
    let p = cs.as_ptr();
    // Safety: `p` points into `cs`'s NUL-terminated buffer, live until main exits.
    let back = unsafe { CStr.from_ptr(p) }.to_string().unwrap();
    println(back);
    println(back.len());
}
"#;
        let out = run_program(src);
        if let Some(out) = out {
            assert_eq!(out, "hello, world\n12\n");
        }
    }

    #[test]
    fn test_e2e_extern_link_name_binds_foreign_symbol() {
        // `#[link_name("strlen")]` redirects the emitted symbol from the
        // Kāra fn name (`measure`) to the foreign symbol (`strlen`), so a
        // snake_case Kāra name can bind a differently-spelled C symbol —
        // the mechanism the self-hosted LLVM-C binding needs to call the
        // PascalCase `LLVMContextCreate` family
        // (`docs/spikes/self-hosting-llvm-c-ffi.md` § Linking). `strlen`
        // also exercises the dedup-against-a-codegen-builtin path (codegen
        // pre-declares `strlen` in `Codegen::new`), proving the import
        // reuses that symbol instead of emitting a renamed `strlen.1`.
        let src = r#"
unsafe extern "C" {
    #[link_name("strlen")]
    fn measure(s: *const u8) -> i64;
}

fn main() {
    let s = c"hello, world";
    // Safety: `c"..."` is NUL-terminated; strlen reads to the NUL.
    let n = unsafe { measure(s.as_ptr()) };
    println(n);
}
"#;
        let out = run_program(src);
        if let Some(out) = out {
            assert_eq!(out.trim(), "12"); // "hello, world" — 12 bytes
        }
    }

    #[test]
    fn test_e2e_cstr_from_ptr_round_trips_len_and_bytes() {
        // The inbound raw-pointer constructor (LLVM-C FFI spike sub-q 4):
        // a c"..." literal -> as_ptr (raw *const u8) -> CStr.from_ptr
        // (libc `strlen` recomputes the length) -> the borrowed surface
        // (len / is_empty / as_bytes) reads the same bytes back. Proves the
        // `{ptr, strlen(ptr)}` aggregate the assoc-call lowering builds is a
        // well-formed CStr indistinguishable from the literal it came from.
        let src = r#"
fn main() {
    let original = c"hello, world";
    let p = original.as_ptr();
    // Safety: `p` is a NUL-terminated rodata pointer from a c"..." literal.
    let rebuilt = unsafe { CStr.from_ptr(p) };
    println(rebuilt.len());
    println(rebuilt.is_empty());
    let bytes = rebuilt.as_bytes();
    println(bytes[0]);
    println(bytes[4]);
    // An empty C string round-trips to len 0 / is_empty true.
    let ep = c"".as_ptr();
    let rebuilt_empty = unsafe { CStr.from_ptr(ep) };
    println(rebuilt_empty.is_empty());
}
"#;
        let out = run_program(src);
        if let Some(out) = out {
            // len=12, not empty, bytes[0]='h'(104), bytes[4]='o'(111), empty=true
            assert_eq!(out, "12\nfalse\n104\n111\ntrue\n");
        }
    }

    #[test]
    fn test_e2e_array_as_ptr_feeds_cstr_from_ptr() {
        // B-2026-06-11-1: `Array[u8, N].as_ptr()` / `.as_mut_ptr()` had no
        // codegen handler (method dispatch fell through). The fix GEPs to
        // element 0 of the owned array's storage and hands it out as the raw
        // pointer `*const T` / `*mut T`. Here a NUL-terminated byte array's
        // pointer feeds `CStr.from_ptr` (libc `strlen` recomputes the length),
        // and the borrowed surface reads the bytes back — proving the pointer
        // addresses the array's first element. `as_mut_ptr()` produces the
        // same usable address (coerces to the `*const u8` param), confirming
        // both arms emit the element-0 pointer.
        let src = r#"
fn main() {
    let a: Array[u8, 4] = [104u8, 105u8, 0u8, 0u8];
    // Safety: `a` is NUL-terminated within its 4 bytes (b"hi\0\0").
    let s = unsafe { CStr.from_ptr(a.as_ptr()) };
    println(s.len());
    let bytes = s.as_bytes();
    println(bytes[0]);
    println(bytes[1]);
    // `as_mut_ptr()` addresses the same first element.
    let s2 = unsafe { CStr.from_ptr(a.as_mut_ptr()) };
    println(s2.len());
}
"#;
        let out = run_program(src);
        if let Some(out) = out {
            // len=2 ("hi" before NUL), bytes[0]='h'(104), bytes[1]='i'(105)
            assert_eq!(out, "2\n104\n105\n2\n");
        }
    }

    #[test]
    fn test_e2e_raw_ptr_deref_reads_byte() {
        // B-2026-06-11-3: `unsafe { *p }` on a `*const T` / `*mut T` used to
        // yield the pointer value (the address) instead of loading through it.
        // The deref arm now emits a real `load` of the pointee for raw-pointer
        // operands (those the lowering pass flags in `raw_pointer_pointee_types`),
        // while `ref T` / `mut ref T` keep the load_variable pass-through.
        // Reads a byte back through both an `Array.as_ptr` and a `CStr.as_ptr`.
        let src = r#"
fn main() {
    let a: Array[u8, 3] = [65u8, 66u8, 67u8];
    let pa = a.as_ptr();
    // Safety: `pa` addresses element 0 of the live owned array.
    let ba: u8 = unsafe { *pa };
    println(ba);
    let s = c"hi";
    let ps = s.as_ptr();
    // Safety: `ps` addresses the first byte of the live c-string literal.
    let bs: u8 = unsafe { *ps };
    println(bs);
}
"#;
        let out = run_program(src);
        if let Some(out) = out {
            // a[0]=65, "hi"[0]='h'(104) — values, not addresses.
            assert_eq!(out, "65\n104\n");
        }
    }

    #[test]
    fn test_e2e_raw_ptr_deref_store_round_trip() {
        // B-2026-06-11-3 (store side): `*p = val` on a `*mut T` used to store
        // into the pointer variable's own alloca (`get_data_ptr`'s owned-local
        // branch) rather than through the pointer — clobbering `p` instead of
        // the pointee. The store arm now compiles the raw-pointer operand to its
        // address value and stores through it. Round-trip: write 90, read 90.
        let src = r#"
fn main() {
    let mut a: Array[u8, 3] = [65u8, 66u8, 67u8];
    let p = a.as_mut_ptr();
    // Safety: `p` addresses element 0 of the live mutable owned array.
    unsafe { *p = 90u8; }
    let b: u8 = unsafe { *p };
    println(b);
    // The write lands in the array itself, observable via indexing.
    println(a[0]);
}
"#;
        let out = run_program(src);
        if let Some(out) = out {
            assert_eq!(out, "90\n90\n");
        }
    }

