    fn test_e2e_ptr_dangling_is_not_null() {
        // ptr.dangling() returns a non-null pointer; ptr.is_null
        // observes false.
        let src = "fn main() { \
                       let p: *const u8 = ptr.dangling(); \
                       if ptr.is_null(p) { println(1); } else { println(0); } \
                   }";
        let out = run_program(src);
        if let Some(out) = out {
            assert_eq!(out, "0\n");
        }
    }

