    // ── Closure compilation ───────────────────────────────────────────

    #[test]
    fn test_ir_closure_simple() {
        let ir = ir_for(
            r#"
fn main() {
    let f = |x: i64| x + 1;
    println(f(5));
}
"#,
        );
        // A closure function should be generated.
        assert!(
            ir.contains("__closure_0"),
            "should define a closure function"
        );
        // The closure function pointer is extracted from the fat-pointer struct.
        assert!(
            ir.contains("extractvalue"),
            "should extract fn_ptr/env_ptr from fat pointer"
        );
    }

    /// B-2026-06-20-1: a bare named `fn` passed as a first-class `Fn(...)`
    /// value. `apply(doubler, 21)` must lower the `Fn(i64)->i64` parameter to
    /// the closure fat-pointer ABI and reify the bare fn name into a
    /// `{trampoline, null-env}` fat pointer, so the higher-order call runs.
    /// Previously the `Fn`-typed param lowered to `i64` while the bare fn name
    /// lowered to a raw `ptr`, failing LLVM module verification.
    /// B-2026-06-21-2: a `fn` body that *returns* a first-class `Fn(...)` value
    /// (`fn pick() -> Fn(i64)->i64 { doubler }`). The bare fn name in return-tail
    /// position now lowers to a closure fat pointer (the free-fn-as-value source
    /// arm), matching the `{ptr,ptr}` return slot; `let f = pick()` registers
    /// `f` in `closure_fn_types` from `pick`'s declared `Fn(...)` return type, so
    /// the direct call through it works. Before: `ret ptr @doubler` vs `{ptr,ptr}`
    /// verifier error.
    #[test]
    fn fn_value_returned_then_called() {
        let out = run_program(
            "fn doubler(n: i64) -> i64 { n * 2i64 }\n\
             fn pick() -> Fn(i64) -> i64 { doubler }\n\
             fn main() { let f = pick(); println(f\"{f(21i64)}\"); }\n",
        );
        assert_eq!(out.as_deref(), Some("42\n"));
    }

    /// A returned fn value passed straight into a `Fn(...)` parameter — the call
    /// result is already a fat pointer, so it flows through with no reify.
    #[test]
    fn fn_value_returned_passed_directly() {
        let out = run_program(
            "fn doubler(n: i64) -> i64 { n * 2i64 }\n\
             fn pick() -> Fn(i64) -> i64 { doubler }\n\
             fn apply(f: Fn(i64) -> i64, x: i64) -> i64 { f(x) }\n\
             fn main() { println(f\"{apply(pick(), 21i64)}\"); }\n",
        );
        assert_eq!(out.as_deref(), Some("42\n"));
    }

    /// B-2026-06-21-3: an **un-annotated** fn value read out of a struct field
    /// (`let g = h.f;`, no `: Fn(..)`) and called. The lowering pass records the
    /// field-read expression's inferred `Fn(..)` type in `fn_value_typed_exprs`,
    /// so `let_binding_fn_value_type` registers `g` in `closure_fn_types` and
    /// `g(x)` lowers to an indirect call. Before this it fell through to the
    /// unknown-callee path and silently returned 0.
    #[test]
    fn fn_value_struct_field_unannotated_extraction() {
        let out = run_program(
            "fn doubler(n: i64) -> i64 { n * 2i64 }\n\
             struct H { f: Fn(i64) -> i64 }\n\
             fn main() { let h = H { f: doubler }; let g = h.f; println(f\"{g(21i64)}\"); }\n",
        );
        assert_eq!(out.as_deref(), Some("42\n"));
    }

    /// B-2026-06-21-3: the same, un-annotated, from a `Vec[Fn(..)]` element.
    #[test]
    fn fn_value_vec_element_unannotated_extraction() {
        let out = run_program(
            "fn doubler(n: i64) -> i64 { n * 2i64 }\n\
             fn main() {\n\
                 let mut v: Vec[Fn(i64) -> i64] = Vec.new();\n\
                 v.push(doubler);\n\
                 let g = v[0];\n\
                 println(f\"{g(21i64)}\");\n\
             }\n",
        );
        assert_eq!(out.as_deref(), Some("42\n"));
    }

    /// B-2026-06-21-2: a fn value stored in a struct field (`H { f: doubler }`)
    /// — the field initializer lowers to a fat pointer matching the
    /// `f: Fn(...)` field slot. The explicit-annotation extraction path
    /// (`let g: Fn(..) = h.f`); the un-annotated form is covered above
    /// (B-2026-06-21-3).
    #[test]
    fn fn_value_struct_field_annotated_extraction() {
        let out = run_program(
            "fn doubler(n: i64) -> i64 { n * 2i64 }\n\
             struct H { f: Fn(i64) -> i64 }\n\
             fn main() { let h = H { f: doubler }; let g: Fn(i64) -> i64 = h.f; println(f\"{g(21i64)}\"); }\n",
        );
        assert_eq!(out.as_deref(), Some("42\n"));
    }

    /// B-2026-06-21-2: a fn value stored in a `Vec[Fn(...)]` element, extracted
    /// with an explicit annotation and called.
    #[test]
    fn fn_value_vec_element_annotated_extraction() {
        let out = run_program(
            "fn doubler(n: i64) -> i64 { n * 2i64 }\n\
             fn main() {\n\
                 let mut v: Vec[Fn(i64) -> i64] = Vec.new();\n\
                 v.push(doubler);\n\
                 let g: Fn(i64) -> i64 = v[0];\n\
                 println(f\"{g(21i64)}\");\n\
             }\n",
        );
        assert_eq!(out.as_deref(), Some("42\n"));
    }

    /// B-2026-06-21-1 (sibling of B-2026-06-20-1): a bare named `fn` bound to a
    /// local first — `let g = doubler;` — then (a) passed to a `Fn(...)`-typed
    /// parameter and (b) called directly through the local. Both forms, and the
    /// `Fn(...)`-annotated binding, must reify the fn name into the closure
    /// fat-pointer ABI + register the local in `closure_fn_types`. Before this
    /// the local held a raw `ptr`: the pass-to-param form failed LLVM
    /// verification and the direct call silently returned 0.
    #[test]
    fn fn_value_let_bound_named_fn_passed_and_called() {
        let out = run_program(
            "fn doubler(n: i64) -> i64 { n * 2i64 }\n\
             fn apply(f: Fn(i64) -> i64, x: i64) -> i64 { f(x) }\n\
             fn main() {\n\
                 let g = doubler;\n\
                 let h: Fn(i64) -> i64 = doubler;\n\
                 println(f\"{apply(g, 10i64)}\");\n\
                 println(f\"{h(11i64)}\");\n\
             }\n",
        );
        assert_eq!(out.as_deref(), Some("20\n22\n"));
    }

    /// A let-bound fn value and a direct-argument reify of the same fn share one
    /// memoized `__karac_fnval_<name>` trampoline (a single `define`).
    #[test]
    fn fn_value_let_and_arg_reify_share_one_trampoline() {
        let ir = ir_for(
            "fn doubler(n: i64) -> i64 { n * 2i64 }\n\
             fn apply(f: Fn(i64) -> i64, x: i64) -> i64 { f(x) }\n\
             fn main() {\n\
                 let g = doubler;\n\
                 let a = apply(g, 1i64);\n\
                 let b = apply(doubler, 2i64);\n\
                 println(f\"{a + b}\");\n\
             }\n",
        );
        let tramp_defs = ir
            .lines()
            .filter(|l| l.starts_with("define") && l.contains("@__karac_fnval_doubler"))
            .count();
        assert_eq!(tramp_defs, 1, "expected one memoized trampoline:\n{ir}");
    }

    #[test]
    fn fn_value_named_fn_as_fn_typed_param_runs() {
        let out = run_program(
            "fn doubler(n: i64) -> i64 { n * 2i64 }\n\
             fn apply(f: Fn(i64) -> i64, x: i64) -> i64 { f(x) }\n\
             fn main() { println(f\"{apply(doubler, 21i64)}\"); }\n",
        );
        assert_eq!(out.as_deref(), Some("42\n"));
    }

    /// Multi-arg + float `Fn(...)` parameters: the env-first trampoline ABI
    /// forwards every user arg, regardless of arity or scalar width.
    #[test]
    fn fn_value_fn_typed_param_multiarg_and_float_run() {
        let multiarg = run_program(
            "fn combine(a: i64, b: i64) -> i64 { a * 10i64 + b }\n\
             fn apply2(f: Fn(i64, i64) -> i64, x: i64, y: i64) -> i64 { f(x, y) }\n\
             fn main() { println(f\"{apply2(combine, 4i64, 2i64)}\"); }\n",
        );
        assert_eq!(multiarg.as_deref(), Some("42\n"));

        let float = run_program(
            "fn half(x: f64) -> f64 { x / 2.0 }\n\
             fn applyf(f: Fn(f64) -> f64, x: f64) -> f64 { f(x) }\n\
             fn main() { println(f\"{applyf(half, 84.0)}\"); }\n",
        );
        assert_eq!(float.as_deref(), Some("42\n"));
    }

    /// The same bare fn passed in `Fn(...)` position at two call sites reuses a
    /// single memoized trampoline (one `define` of `__karac_fnval_doubler`),
    /// and both higher-order calls run.
    #[test]
    fn fn_value_named_fn_reused_across_call_sites() {
        let src = "fn doubler(n: i64) -> i64 { n * 2i64 }\n\
                   fn apply(f: Fn(i64) -> i64, x: i64) -> i64 { f(x) }\n\
                   fn main() {\n\
                       let a = apply(doubler, 10i64);\n\
                       let b = apply(doubler, 11i64);\n\
                       println(f\"{a + b}\");\n\
                   }\n";
        assert_eq!(run_program(src).as_deref(), Some("42\n"));
        let ir = ir_for(src);
        let tramp_defs = ir
            .lines()
            .filter(|l| l.starts_with("define") && l.contains("@__karac_fnval_doubler"))
            .count();
        assert_eq!(
            tramp_defs, 1,
            "trampoline must be synthesized exactly once (memoized):\n{ir}"
        );
    }

    /// Bonus path the same fix enables: a closure *literal* flowing into a
    /// `Fn(...)` parameter slot. The param now lowers to the fat-pointer ABI
    /// and the body call routes through the indirect-call path, so the closure
    /// value passes through and runs (no reify needed — it is already a fat
    /// pointer).
    #[test]
    fn fn_value_closure_literal_into_fn_typed_param_run() {
        let out = run_program(
            "fn apply(f: Fn(i64) -> i64, x: i64) -> i64 { f(x) }\n\
             fn main() { println(f\"{apply(|n| n * 2i64, 21i64)}\"); }\n",
        );
        assert_eq!(out.as_deref(), Some("42\n"));
    }

    /// The reify path synthesizes a per-fn env-ignoring trampoline so the bare
    /// fn name conforms to the env-first closure-call ABI.
    #[test]
    fn test_ir_fn_value_named_fn_reified_trampoline() {
        let ir = ir_for(
            "fn doubler(n: i64) -> i64 { n * 2i64 }\n\
             fn apply(f: Fn(i64) -> i64, x: i64) -> i64 { f(x) }\n\
             fn main() { let r = apply(doubler, 21i64); println(f\"{r}\"); }\n",
        );
        assert!(
            ir.contains("__karac_fnval_doubler"),
            "should synthesize an env-ignoring trampoline for the bare fn value:\n{ir}"
        );
    }

