    // ── Async `sleep_ms` — park-on-timer lowering (phase-5 auto-par ──
    //    divergence A2a-2.2) ──
    //
    // `sleep_ms(ms)` (the leaf `suspends` primitive, `std.time`) lowers to
    // the `karac_park_on_timer` state machine: the call site converts ms →
    // ns, allocs the state struct, drives the poll-fn once (state_0 arms a
    // reactor deadline via `karac_runtime_event_loop_register_timer` and
    // returns Pending), then blocks on a completion slot the dispatcher
    // signals on expiry. Unlike a `blocks` libc `usleep`, two `sleep_ms`
    // calls under `par {}` overlap on the timer wheel rather than pin two
    // OS threads for their full naps.

    #[test]
    fn sleep_ms_lowers_to_park_on_timer() {
        // Runtime-valued duration so the ms→ns multiply is NOT
        // constant-folded away (a literal `sleep_ms(500)` folds
        // `500 * 1_000_000` to a constant and the named `mul` vanishes).
        let ir = ir_for(
            "fn nap(ms: i64) {\n\
                 sleep_ms(ms);\n\
             }\n\
             fn main() {\n\
                 nap(500);\n\
             }",
        );
        // The deadline is armed through the timer-register FFI (NOT
        // register_fd — there is no fd).
        assert!(
            ir.contains("karac_runtime_event_loop_register_timer"),
            "expected sleep_ms to arm a reactor deadline via \
             karac_runtime_event_loop_register_timer; IR:\n{ir}"
        );
        // The park-on-timer poll-fn + constructor are emitted.
        assert!(
            ir.contains("__kara_poll_karac_park_on_timer")
                && ir.contains("__kara_state_new_karac_park_on_timer"),
            "expected the karac_park_on_timer poll-fn + constructor in IR:\n{ir}"
        );
        // The call site composes with the primitive: ms→ns convert (survives
        // because `ms` is runtime-valued), alloc the state, drive the poll,
        // and block on the completion slot (dispatcher-yield model).
        let nap_body = function_body(&ir, "nap").unwrap_or_else(|| {
            panic!("nap body not found in IR:\n{ir}");
        });
        assert!(
            nap_body.contains("kara.timer.ms_to_nanos"),
            "expected the call site to convert ms→ns; nap body:\n{nap_body}"
        );
        assert!(
            nap_body.contains("kara.timer.dur.field") && nap_body.contains("kara.timer.poll_wait"),
            "expected the call site to store the duration + block on the \
             completion slot; nap body:\n{nap_body}"
        );
        // Unlike the fd park, sleep_ms performs NO fd deregister (timers
        // have no fd / no epoll registration; the dispatcher claims its own).
        assert!(
            !nap_body.contains("karac_runtime_event_loop_deregister_fd"),
            "sleep_ms must NOT deregister an fd (timers have none); nap body:\n{nap_body}"
        );
    }

    #[test]
    fn e2e_sleep_ms_resumes_in_order() {
        // A short async sleep runs to completion and resumes the caller in
        // program order — proving the full arm→park→dispatcher-signal→resume
        // path works end-to-end (not just that the IR shape is right).
        if let Some(out) = run_program(
            "fn main() {\n\
                 println(\"a\");\n\
                 sleep_ms(20);\n\
                 println(\"b\");\n\
                 sleep_ms(20);\n\
                 println(\"c\");\n\
             }",
        ) {
            assert_eq!(out, "a\nb\nc\n");
        }
    }

    #[test]
    fn e2e_par_sleeps_both_branches_complete() {
        // Two `sleep_ms` calls inside `par {}` each run to completion (the
        // overlap *timing* win is measured by the bench harness
        // `bench/auto_par_io`; here we pin that the par+suspend composition
        // resumes BOTH branches rather than wedging one). Each branch prints
        // after its nap; both lines must appear.
        if let Some(out) = run_program(
            "fn main() {\n\
                 par {\n\
                     { sleep_ms(20); println(\"left\"); }\n\
                     { sleep_ms(20); println(\"right\"); }\n\
                 }\n\
             }",
        ) {
            assert!(
                out.contains("left") && out.contains("right"),
                "expected both par branches to complete after their naps; got:\n{out}"
            );
        }
    }

    #[test]
    fn e2e_auto_par_sleeps_run_correctly() {
        // A2b: two independent `sleep_ms` timer waits AUTO-parallelize (no
        // explicit `par {}` — the conflict model exempts a standalone `sleep_ms`
        // from the `suspends` boundary gate and lifts `(Suspends,Suspends)`).
        // They overlap on the par thread-block path; here we pin output
        // correctness and termination (the timing win is the bench's job).
        if let Some(out) = run_program(
            "fn main() {\n\
                 sleep_ms(20);\n\
                 sleep_ms(20);\n\
                 println(\"done\");\n\
             }",
        ) {
            assert_eq!(out, "done\n", "auto-par sleeps complete; got:\n{out}");
        }
    }

    #[test]
    fn e2e_auto_par_allocating_calls_run_correctly() {
        // A3: two independent statements that each only `allocates(Heap)` (each
        // builds a fresh Vec) AUTO-parallelize — the conflict model no longer
        // treats allocates+allocates as a conflict (heap is thread-safe;
        // `allocates` is informational per design.md). They run on the par
        // fan-out path; pin that each branch's heap allocation is independent
        // and the combined result is correct (no cross-branch corruption).
        if let Some(out) = run_program(
            "fn make(n: i64) -> Vec[i64] {\n\
                 let mut v: Vec[i64] = Vec.new();\n\
                 v.push(n);\n\
                 v.push(n + 1);\n\
                 return v;\n\
             }\n\
             fn main() {\n\
                 let a = make(10);\n\
                 let b = make(20);\n\
                 println(a[0] + a[1] + b[0] + b[1]);\n\
             }",
        ) {
            assert_eq!(
                out, "62\n",
                "auto-par allocating calls must each build their Vec correctly; got:\n{out}"
            );
        }
    }

    #[test]
    fn e2e_auto_par_panicking_calls_run_correctly() {
        // A3b: two independent statements that each only `panics` (each calls a
        // dividing helper — `/` infers `panics`) AUTO-parallelize now that the
        // conflict model treats panics+panics as non-conflicting. Neither
        // actually divides by zero, so this is the common, beneficial case:
        // ordinary arithmetic runs concurrently. Pin output correctness.
        if let Some(out) = run_program(
            "fn divmod(n: i64, d: i64) -> i64 { return n / d; }\n\
             fn main() {\n\
                 let a = divmod(100, 5);\n\
                 let b = divmod(200, 4);\n\
                 println(a + b);\n\
             }",
        ) {
            assert_eq!(
                out, "70\n",
                "auto-par panicking-effect calls must compute correctly; got:\n{out}"
            );
        }
    }

    #[test]
    fn e2e_auto_par_branch_panic_fails_fast() {
        // A3b soundness gate: when one of two grouped panic-capable statements
        // ACTUALLY panics inside a `__par_branch` worker (here a real divide by
        // zero), the program must FAIL FAST — a Kāra panic lowers to `exit(1)`
        // (a direct process exit, not a Rust unwind), so the worker terminates
        // the whole process. We assert a non-zero exit and the panic message,
        // and the `output_with_hang_watchdog` wrapper makes this double as a
        // deadlock guard: a regression that hung on the worker exit (e.g. exit
        // while another thread holds the output lock) would trip the watchdog
        // rather than pass.
        if let Some(c) = run_program_capturing(
            "fn divmod(n: i64, d: i64) -> i64 { return n / d; }\n\
             fn main() {\n\
                 let zero = 0;\n\
                 let a = divmod(100, 5);\n\
                 let b = divmod(200, zero);\n\
                 println(a + b);\n\
             }",
        ) {
            assert_eq!(
                c.status.code(),
                Some(1),
                "a branch panic must fail fast with exit 1; stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                c.stdout.contains("division by zero"),
                "expected the div-by-zero panic message; stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
        }
    }

    #[test]
    fn e2e_auto_par_channel_consumer_terminates() {
        // Regression (A2b): the producer/consumer channel program must TERMINATE
        // under default auto-par. `consume(rx)` carries a `suspends` effect (from
        // `rx.recv()`) that is indistinguishable at the effect level from a
        // `sleep_ms` timer wait, but a channel recv has a happens-before with its
        // producer — lifting `consume(rx)` into a `__par_branch` worker alongside
        // the `spawn` deadlocks (the recv loop never observes the channel close).
        // The conservative boundary gate keeps it serial (only direct `sleep_ms`
        // is exempt). A regression here would HANG, not just misprint, so the
        // test doubles as the deadlock guard.
        if let Some(out) = run_program(
            "fn producer(tx: Sender[i64]) -> i64 {\n\
                 tx.send(10);\n\
                 tx.send(20);\n\
                 0\n\
             }\n\
             fn consume(rx: Receiver[i64]) -> i64 {\n\
                 let mut sum = 0;\n\
                 let mut go = true;\n\
                 while go {\n\
                     let v = rx.recv();\n\
                     if v == 0 { go = false; } else { sum = sum + v; }\n\
                 }\n\
                 sum\n\
             }\n\
             fn main() {\n\
                 let (tx, rx): (Sender[i64], Receiver[i64]) = Channel.new();\n\
                 let h: TaskHandle[i64] = spawn(|| producer(tx));\n\
                 println(consume(rx));\n\
                 h.join();\n\
             }",
        ) {
            assert_eq!(
                out, "30\n",
                "channel consumer must terminate with 30; got:\n{out}"
            );
        }
    }

    // ── Move-suppression for user-Drop bindings (let-rebind) ──
    //
    // `let g = f;` where `f` has a user `impl Drop` moves the value
    // out of `f` into `g`. Without suppression both bindings would
    // fire their UserDrop at scope exit, double-closing fds /
    // double-calling user Drop bodies. The codegen `stmts.rs`
    // let-binding tracking calls `suppress_user_drop_for_var` on the
    // source name before tracking the destination, removing the
    // source's CleanupAction::UserDrop. These tests pin the
    // observable IR shape: exactly one `call @karac_drop_<Type>`
    // remains in main.

    #[test]
    fn test_ir_let_rebind_suppresses_source_user_drop() {
        let ir = ir_for(
            r#"
struct Foo { x: i64 }
impl Drop for Foo {
    fn drop(mut ref self) {}
}
fn main() {
    let f = Foo { x: 1 };
    let g = f;
    println(g.x);
}
"#,
        );
        let main_body = function_body(&ir, "main").unwrap_or_else(|| {
            panic!("main body not found in IR:\n{}", ir);
        });
        let count = main_body.matches("call void @karac_drop_Foo(").count();
        assert_eq!(
            count, 1,
            "expected exactly ONE `@karac_drop_Foo` call in main \
             (source `f` should be move-suppressed; only destination \
             `g` drops at scope exit); got {} calls; body was:\n{}",
            count, main_body
        );
    }

    #[test]
    fn test_ir_let_rebind_tcp_listener_suppresses_double_close() {
        // Production motivation: `let l2 = l1` for TcpListener should
        // close the fd exactly once at scope exit, not twice. The IR
        // pins the same shape: one `@karac_drop_TcpListener` call.
        let ir = ir_for(
            r#"
fn main() {
    let l1 = TcpListener.bind("127.0.0.1:0").unwrap();
    let l2 = l1;
    println(l2.fd);
}
"#,
        );
        let main_body = function_body(&ir, "main").unwrap_or_else(|| {
            panic!("main body not found in IR:\n{}", ir);
        });
        let count = main_body
            .matches("call void @karac_drop_TcpListener(")
            .count();
        assert_eq!(
            count, 1,
            "expected exactly ONE `@karac_drop_TcpListener` call in main \
             after `let l2 = l1` (source `l1` move-suppressed); got {} \
             calls; body was:\n{}",
            count, main_body
        );
    }

    // ── Move-suppression for return-by-value of user-Drop bindings ──
    //
    // `fn make() -> T { let l = T::new(); l }` — `l`'s value moves
    // out as the function's return value. Without suppression, the
    // function-scope cleanup would fire `l`'s UserDrop (close the
    // fd) before the return happens, leaving the caller with a stale
    // fd. The fix in `suppress_cleanup_for_tail_return` removes `l`'s
    // UserDrop from the scope-cleanup stack right before
    // `emit_scope_cleanup` runs; the caller then closes the fd
    // exactly once when its own binding goes out of scope.

    #[test]
    fn test_ir_return_by_value_suppresses_source_user_drop() {
        let ir = ir_for(
            r#"
struct Foo { x: i64 }
impl Drop for Foo {
    fn drop(mut ref self) {}
}
fn make() -> Foo {
    let f = Foo { x: 7 };
    f
}
fn main() {
    let r = make();
    println(r.x);
}
"#,
        );
        let make_body = function_body(&ir, "make").unwrap_or_else(|| {
            panic!("make body not found in IR:\n{}", ir);
        });
        assert!(
            !make_body.contains("call void @karac_drop_Foo("),
            "expected `make` to NOT contain `@karac_drop_Foo` — `f` is \
             moved out as the return value and its UserDrop should be \
             suppressed before scope-exit cleanup. body was:\n{}",
            make_body
        );
        // The caller still drops the value at its own scope exit.
        let main_body = function_body(&ir, "main").unwrap_or_else(|| {
            panic!("main body not found in IR:\n{}", ir);
        });
        assert!(
            main_body.contains("call void @karac_drop_Foo("),
            "expected `main` to drop `r` at scope exit (caller owns \
             the returned value); body was:\n{}",
            main_body
        );
    }

    #[test]
    fn test_ir_explicit_return_suppresses_source_user_drop() {
        // `return f;` is an explicit return that takes the
        // Return-statement path in `compile_expr`. The companion
        // suppression in `src/codegen/exprs.rs`'s `ExprKind::Return`
        // arm pins this case.
        let ir = ir_for(
            r#"
struct Foo { x: i64 }
impl Drop for Foo {
    fn drop(mut ref self) {}
}
fn make() -> Foo {
    let f = Foo { x: 7 };
    return f;
}
fn main() {
    let r = make();
    println(r.x);
}
"#,
        );
        let make_body = function_body(&ir, "make").unwrap_or_else(|| {
            panic!("make body not found in IR:\n{}", ir);
        });
        assert!(
            !make_body.contains("call void @karac_drop_Foo("),
            "expected `make` to NOT contain `@karac_drop_Foo` — \
             explicit `return f` move-suppresses `f`. body was:\n{}",
            make_body
        );
    }

    // Note: production-shaped `fn make_listener() -> TcpListener {
    // let l = TcpListener.bind(...); l }` is the natural Slice 9d
    // motivating example, but is NOT currently testable end-to-end:
    // TcpListener-as-a-function-return-type fails LLVM module
    // verification with "Function return type does not match
    // operand type of return inst!" because the codegen's stdlib
    // struct-return ABI lowering doesn't yet wire the
    // single-i32-field shape through a function's return slot.
    // The user-struct case above (`fn make() -> Foo`) exercises the
    // same move-suppression mechanism; once the stdlib return-ABI
    // gap closes, the TcpListener case will compile and the move-
    // suppression machinery already wired here will make it
    // correct. Filed as a follow-on in phase-7-codegen.md's
    // move-suppression entry.

    #[test]
    fn test_ir_no_wrapper_without_impl_drop() {
        // No `impl Drop` → no entry in `program.drop_method_keys` →
        // `emit_user_drop_wrappers` synthesizes nothing.
        let ir = ir_for(
            r#"
struct Foo { x: i64 }
fn main() {
    let f = Foo { x: 1 };
}
"#,
        );
        assert!(
            !ir.contains("@karac_drop_Foo"),
            "wrapper `karac_drop_Foo` must NOT be emitted when `Foo` has \
             no `impl Drop`; found in:\n{}",
            ir
        );
    }

    #[test]
    fn test_e2e_struct_owning_map_shared_drops_cleanly() {
        // E2E: an `Owner` struct owns a `Map[i64, Node]` where
        // `Node` is a shared struct. Constructing the field with
        // `Map.new()` inline (no source local to double-track)
        // and letting scope-exit run the synthesized struct drop
        // is the contained surface for item 4 — the local-then-
        // place pattern would trip a pre-existing Map-handle
        // move-suppression gap (struct-field construction
        // suppresses Vec/String/struct source cleanups but not
        // Map handles; double-free on the local's FreeMapHandle
        // + the struct's drop). The IR test above pins the
        // structural assertion (walk emitted in the drop fn);
        // this test exercises it at runtime on the empty-Map
        // path so a future regression that breaks the drop fn's
        // IR shape surfaces as a crash here.
        let out = run_program(
            r#"
shared struct Node { val: i64 }
struct Owner { m: Map[i64, Node] }
fn main() {
    let _o = Owner { m: Map.new() };
    println(42);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "42");
        }
    }

