    // Anonymous array literals in Slice contexts (phase-8 / kata-393 audit).
    // Named arrays already coerced to `Slice[T]` params and range-sliced;
    // bare literals did not. `f([1,2,3])` failed LLVM verification
    // (`[N x i8]` vs `{ptr,i64}` param mismatch) and `f([1,2,3][a..b])`
    // errored "range-slice requires a named source variable". Both now
    // materialize the literal to a temp alloca and build a slice header.
    // The interpreter always accepted these forms; codegen now matches.

    #[test]
    fn test_e2e_array_literal_arg_to_slice_param() {
        let out = run_program(
            r#"
fn sum(xs: Slice[u8]) -> i64 {
    let mut s = 0_i64;
    for x in xs { s = s + (x as i64); }
    s
}
fn main() {
    println(sum([4u8, 5u8, 6u8]));
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "15");
        }
    }

    #[test]
    fn test_e2e_empty_array_binding_to_slice_param() {
        // B-2026-06-14-30: `let a: Array[T, 0] = []` passed to a `Slice[T]`
        // param used to lower as a scalar `i64 0` (compile_array_literal's
        // empty fallback), so the Array → Slice coercion was skipped and the
        // raw i64 failed LLVM verification (`{ptr,i64}` vs `i64`). The fix
        // allocates a real `[0 x T]` slot from the annotation; the empty array
        // now coerces to a zero-length slice header. The non-empty binding
        // alongside it confirms the ordinary array path is unaffected.
        let out = run_program(
            r#"
fn take(s: Slice[i64], len: i64) -> i64 {
    let mut sum = 0i64;
    for i in 0..len { sum = sum + s[i]; }
    sum
}
fn main() {
    let a: Array[i64, 0] = [];
    println(take(a, 0));
    let b: Array[i64, 3] = [1, 2, 3];
    println(take(b, 3));
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "0\n6");
        }
    }

    #[test]
    fn test_e2e_array_arg_to_ref_slice_param() {
        // Regression for B-2026-06-19-1: an `Array[T, N]` passed to a
        // `ref Slice[T]` param mis-built. `ref Slice` was classified as a bare
        // ref param (extract_slice_elem_type returned None through the `Ref`
        // wrapper), so the call site's `get_data_ptr` identifier fast-path
        // passed the array's raw element storage as the slice arg; the callee
        // read `{ptr,len}` out of the array's first two elements — a bogus slice
        // (ptr = elem0, len = elem1) → out-of-bounds / segfault. The interpreter
        // always built a real header, so it was a run/build divergence. The fix
        // synthesizes a `{ptr,len}` header for an Array source and passes a
        // pointer to it.
        //
        // Three shapes, all of which segfaulted/OOB'd before the fix:
        //   - direct Array -> ref Slice, indexed read;
        //   - FORWARDING a ref-slice binding to another ref-slice param (must
        //     keep using get_data_ptr, NOT re-coerce — the narrowing guard);
        //   - the same forward, where the callee also builds a `Vec[bool]` sized
        //     by `n` and indexes it by a slice value (the kata-41 seen shape) —
        //     a corrupted slice made `n`/the read value wrong and OOB'd the Vec.
        let out = run_program(
            r#"
fn sum_ref(nums: ref Slice[i64], n: i64) -> i64 {
    let mut s = 0i64;
    let mut i = 0i64;
    while i < n { s = s + nums[i]; i = i + 1i64; }
    s
}
fn forward(nums: ref Slice[i64], n: i64) -> i64 {
    sum_ref(nums, n)
}
fn first_missing(nums: ref Slice[i64], n: i64) -> i64 {
    let mut seen: Vec[bool] = Vec.new();
    let mut k = 0i64;
    while k <= n { seen.push(false); k = k + 1i64; }
    let mut i = 0i64;
    while i < n {
        let v = nums[i];
        if v >= 1i64 and v <= n { seen[v] = true; }
        i = i + 1i64;
    }
    let mut v = 1i64;
    while v <= n {
        if not seen[v] { return v; }
        v = v + 1i64;
    }
    n + 1i64
}
fn main() {
    let a: Array[i64, 4] = [10, 20, 30, 40];
    println(sum_ref(a, 4));      // 100 — direct Array -> ref Slice
    println(forward(a, 4));      // 100 — forwarded ref-slice binding
    let b: Array[i64, 5] = [3, 4, -1, 1, 9];
    println(first_missing(b, 5)); // 2 — ref-slice forward + Vec[bool] index
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "100\n100\n2");
        }
    }

    #[test]
    fn test_ir_binsearch_midpoint_emits_assumes() {
        // Binary-search midpoint BCE (control_flow_bce.rs § midpoint): a
        // `let mid = lo + (hi - lo) / 2` under a strict `while lo < hi`
        // guard emits `assume(mid >= lo)` + `assume(mid < hi)` so LLVM
        // folds the `nums[mid]` bounds check. Pin both `llvm.assume`s and
        // the named comparisons appear.
        let ir = ir_for(
            r#"
fn lower_bound(nums: ref Vec[i64], len: i64, target: i64) -> i64 {
    let mut lo = 0i64;
    let mut hi = len;
    while lo < hi {
        let mid = lo + (hi - lo) / 2i64;
        if nums[mid] < target { lo = mid + 1i64; } else { hi = mid; }
    }
    lo
}
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(1i64); v.push(3i64); v.push(5i64);
    println(f"{lower_bound(v, 3i64, 3i64)}");
}
"#,
        );
        assert!(
            ir.contains("bs.mid.ge.lo"),
            "expected midpoint lower-bound assume (mid >= lo); IR had none"
        );
        assert!(
            ir.contains("bs.mid.lt.hi"),
            "expected midpoint upper-bound assume (mid < hi); IR had none"
        );
        assert!(
            ir.contains("@llvm.assume"),
            "expected an llvm.assume call for the midpoint facts"
        );
    }

    #[test]
    fn test_ir_non_midpoint_binding_no_binsearch_assume() {
        // Negative gate: a non-midpoint `let` under a `while lo < hi` guard
        // (`mid = lo + 1`, not the midpoint form) must NOT emit the
        // binary-search assumes — the recognition is shape-exact.
        let ir = ir_for(
            r#"
fn scan(nums: ref Vec[i64], len: i64) -> i64 {
    let mut lo = 0i64;
    let mut hi = len;
    let mut acc = 0i64;
    while lo < hi {
        let mid = lo + 1i64;
        acc = acc + nums[lo];
        lo = mid;
    }
    acc
}
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(7i64); v.push(9i64);
    println(f"{scan(v, 2i64)}");
}
"#,
        );
        assert!(
            !ir.contains("bs.mid.ge.lo") && !ir.contains("bs.mid.lt.hi"),
            "non-midpoint binding must not emit binary-search midpoint assumes"
        );
    }

    #[test]
    fn test_e2e_binsearch_midpoint_assume_is_sound() {
        // Soundness E2E: the midpoint assumes must not corrupt results. A
        // lower/upper-bound search over a sorted Vec with duplicate runs is
        // exercised across hit / miss / boundary targets; output must match
        // the hand-computed [first, last] pairs exactly.
        let out = run_program(
            r#"
fn lower_bound(nums: ref Vec[i64], len: i64, target: i64) -> i64 {
    let mut lo = 0i64;
    let mut hi = len;
    while lo < hi {
        let mid = lo + (hi - lo) / 2i64;
        if nums[mid] < target { lo = mid + 1i64; } else { hi = mid; }
    }
    lo
}
fn upper_bound(nums: ref Vec[i64], len: i64, target: i64) -> i64 {
    let mut lo = 0i64;
    let mut hi = len;
    while lo < hi {
        let mid = lo + (hi - lo) / 2i64;
        if nums[mid] <= target { lo = mid + 1i64; } else { hi = mid; }
    }
    lo
}
fn report(nums: ref Vec[i64], len: i64, target: i64) {
    let lo = lower_bound(nums, len, target);
    if lo == len or nums[lo] != target {
        println(f"{target}: -1 -1");
    } else {
        println(f"{target}: {lo} {upper_bound(nums, len, target) - 1i64}");
    }
}
fn main() {
    let mut v: Vec[i64] = Vec.new();
    // [5, 7, 7, 8, 8, 10]
    v.push(5i64); v.push(7i64); v.push(7i64); v.push(8i64); v.push(8i64); v.push(10i64);
    report(v, 6i64, 8i64);   // 3 4
    report(v, 6i64, 7i64);   // 1 2
    report(v, 6i64, 5i64);   // 0 0
    report(v, 6i64, 10i64);  // 5 5
    report(v, 6i64, 6i64);   // -1 -1
    report(v, 6i64, 11i64);  // -1 -1
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(
                out.trim(),
                "8: 3 4\n7: 1 2\n5: 0 0\n10: 5 5\n6: -1 -1\n11: -1 -1"
            );
        }
    }

