    fn test_e2e_soa_pop_on_empty_returns_none() {
        // Empty SoA: `pop` must return `None` and leave len untouched
        // (= 0). Exercises the cap=0 / len=0 short-circuit alongside
        // the Option-tag merge.
        let src = r#"
struct Entity { x: i64, y: i64 }
layout entities: Vec[Entity] {
    group physics { x, y }
}
fn main() {
    let mut entities: Vec[Entity] = Vec.new();
    match entities.pop() {
        Some(e) => println(e.x),
        None => println(-1),
    }
    println(entities.len());
}
"#;
        if let Some(out) = run_program(src) {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["-1", "0"]);
        }
    }

    #[test]
    fn test_e2e_soa_pop_front_shifts_each_group() {
        // `pop_front` materializes the head element, then memmoves the
        // tail of every hot group + cold group left by one slot. After
        // the shift, the new head must match what was at index 1.
        // Multiple pops verify the per-group shift is consistent across
        // calls (a bug that shifted only the first group would surface
        // as misaligned reads on later pops).
        let src = r#"
struct Entity { x: i64, y: i64, label: i64 }
layout entities: Vec[Entity] {
    group physics { x, y }
    cold { label }
}
fn main() {
    let mut entities: Vec[Entity] = Vec.new();
    entities.push(Entity { x: 1, y: 10, label: 100 });
    entities.push(Entity { x: 2, y: 20, label: 200 });
    entities.push(Entity { x: 3, y: 30, label: 300 });
    entities.push(Entity { x: 4, y: 40, label: 400 });
    match entities.pop_front() {
        Some(e) => println(e.x),
        None => println(-1),
    }
    let head = entities[0];
    println(head.x);
    println(head.y);
    println(head.label);
    match entities.pop_front() {
        Some(e) => println(e.x),
        None => println(-1),
    }
    let head2 = entities[0];
    println(head2.x);
    println(head2.label);
    println(entities.len());
}
"#;
        if let Some(out) = run_program(src) {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["1", "2", "20", "200", "2", "3", "300", "2"]);
        }
    }

    #[test]
    fn test_e2e_soa_remove_at_index_shifts_tail() {
        // `remove(idx)` materializes the element at idx, then memmoves
        // the (len-1-idx) tail elements down by one across every group
        // + cold. Returns the removed element directly (no Option
        // wrap) per plain `Vec.remove`'s contract.
        let src = r#"
struct Entity { x: i64, y: i64, label: i64 }
layout entities: Vec[Entity] {
    group physics { x, y }
    cold { label }
}
fn main() {
    let mut entities: Vec[Entity] = Vec.new();
    entities.push(Entity { x: 1, y: 10, label: 100 });
    entities.push(Entity { x: 2, y: 20, label: 200 });
    entities.push(Entity { x: 3, y: 30, label: 300 });
    entities.push(Entity { x: 4, y: 40, label: 400 });
    let removed = entities.remove(1);
    println(removed.x);
    println(removed.y);
    println(removed.label);
    let now0 = entities[0];
    let now1 = entities[1];
    let now2 = entities[2];
    println(now0.x);
    println(now1.x);
    println(now1.label);
    println(now2.x);
    println(now2.label);
    println(entities.len());
}
"#;
        if let Some(out) = run_program(src) {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(
                lines,
                vec!["2", "20", "200", "1", "3", "300", "4", "400", "3"]
            );
        }
    }

    #[test]
    fn test_e2e_vec_of_vec_index_ref_arg() {
        // Regression: passing `stake[idx]` (an aggregate element of a
        // Vec[Vec[T]]) to a `ref Vec[T]` parameter shallow-copied the
        // element struct and dropped the copy as a call-temp, double-
        // freeing the buffer the outer Vec still owned. Symptom was a
        // hang/SIGTRAP once the loop count grew (heap corruption). The
        // fix passes a pointer to the element in place (borrow, no drop).
        // Loop to 200 so any double-free corrupts the allocator.
        let out = run_program(
            r#"
fn make() -> Vec[char] {
    let mut v: Vec[char] = Vec.with_capacity(4);
    v.push('a');
    v.push('b');
    v
}
fn sumlen(r: ref Vec[char]) -> i64 {
    r.len()
}
fn main() {
    let mut stake: Vec[Vec[char]] = Vec.with_capacity(2);
    stake.push(make());
    stake.push(make());
    let mut sum: i64 = 0;
    let mut k: i64 = 0;
    while k < 200 {
        let idx: i64 = k % 2;
        sum = sum + sumlen(stake[idx]);
        k = k + 1;
    }
    println(sum);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "400");
        }
    }

    #[test]
    fn test_e2e_vec_pop_returns_option() {
        // `Vec.pop` now returns `Option[T]` per design.md (was raw
        // element pre-2026-05-10). Match destructure unwraps Some,
        // None on empty. Previous test asserted raw shape; the
        // semantic upgrade aligns codegen with the spec + interpreter.
        let out = run_program(
            r#"
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(10);
    v.push(20);
    match v.pop() {
        Some(x) => println(x),
        None => println(0),
    }
    println(v.len());
    match v.pop() {
        Some(x) => println(x),
        None => println(0),
    }
    match v.pop() {
        Some(_) => println(99),
        None => println(0),
    }
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["20", "1", "10", "0"]);
        }
    }

    #[test]
    fn test_e2e_option_narrow_int_payload_narrows_to_surface_width() {
        // Regression: `Vec[u8].pop()` returns `Option[u8]`, whose payload
        // word is i64 in the variant word stream. The `Some(top)` binding
        // must narrow that word back to i8 (u8's LLVM width) — otherwise
        // `top == b` (b: u8 → i8) emits `icmp i64, i8` and module
        // verification fails with "Both operands to ICmp instruction are
        // not of the same type!". Exercises the valid-parentheses stack
        // shape (LeetCode #20) that surfaced the bug: push the matching
        // closer, pop + compare on a closer. Also covers `char` (i32) and
        // `u32` to confirm the narrowing keys off the recorded surface
        // width, not just u8.
        let out = run_program(
            r#"
fn is_valid(s: ref String) -> bool {
    let bytes = s.bytes();
    let n = bytes.len();
    let mut stack: Vec[u8] = Vec.new();
    let mut i = 0i64;
    while i < n {
        let b = bytes[i];
        if b == b'(' or b == b'[' or b == b'{' {
            if b == b'(' { stack.push(b')'); }
            else if b == b'[' { stack.push(b']'); }
            else { stack.push(b'}'); }
        } else {
            match stack.pop() {
                Some(top) => { if top != b { return false; } }
                None => { return false; }
            }
        }
        i = i + 1i64;
    }
    stack.is_empty()
}

fn main() {
    if is_valid("([{}])") { println(1); } else { println(0); }
    if is_valid("(]") { println(1); } else { println(0); }

    // char payload (i32) narrowed from the i64 word.
    let mut cs: Vec[char] = Vec.new();
    cs.push('x');
    match cs.pop() {
        Some(c) => { if c == 'x' { println(2); } else { println(0); } }
        None => { println(0); }
    }

    // u32 payload narrowed from the i64 word.
    let mut ns: Vec[u32] = Vec.new();
    ns.push(7u32);
    if let Some(v) = ns.pop() {
        let w: u32 = 7u32;
        if v == w { println(3); }
    }
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["1", "0", "2", "3"]);
        }
    }

    #[test]
    fn test_e2e_vec_deque_pop_front_returns_option_with_tuple_payload() {
        // The LeetCode 3629 kata's blocking shape: VecDeque[(i64, i64)]
        // BFS frontier with `pop_front()` returning `Option[(i64,i64)]`.
        // Multi-word Option payload via the bumped layout +
        // `coerce_to_payload_words(val, 3)` construction; destructure
        // uses the direct-pattern form `Some((i, d))` which routes
        // through the existing tuple-payload reconstruction machinery.
        let out = run_program(
            r#"
fn main() {
    let mut q: VecDeque[(i64, i64)] = VecDeque.new();
    q.push_back((0, 0));
    let mut sum = 0i64;
    loop {
        match q.pop_front() {
            None => { break; },
            Some((i, d)) => {
                sum = sum + i + d;
                if i < 3 {
                    q.push_back((i + 1, d + 1));
                }
            },
        }
    }
    println(sum);
}
"#,
        );
        if let Some(out) = out {
            // BFS: pop (0,0) sum+=0; push (1,1) → pop sum+=2 (2);
            // push (2,2) → pop sum+=4 (6); push (3,3) → pop sum+=6 (12);
            // i==3 no push; empty → break. Total 12.
            assert_eq!(out.trim(), "12");
        }
    }

    #[test]
    fn test_e2e_par_group_serializes_for_iter_with_outer_mutable_write() {
        // The concurrency analyzer's per-stmt info now collects
        // nested-block writes (Assign / CompoundAssign) into
        // `info.defines`. Without this, a `for v in nums.iter()`
        // expression-stmt that writes to outer `cap` was treated as
        // "no dependencies" against a subsequent `let f =
        // dummy(cap)` — the analyzer grouped them and the par-branch
        // fn's local copy of `cap` never propagated back, so the
        // function call read the initial value of `cap`.
        //
        // Repro:
        let out = run_program(
            r#"
fn dummy(n: i64) -> Vec[i64] {
    let mut v: Vec[i64] = Vec.new();
    let mut i = 0i64;
    while i < n { v.push(i); i = i + 1; }
    v
}
fn helper(nums: Slice[i64]) -> i64 {
    let mut cap = 1i64;
    for v in nums.iter() {
        if v > cap { cap = v; }
    }
    let f: Vec[i64] = dummy(cap);
    println(cap);
    println(f.len());
    cap
}
fn main() {
    let a: Array[i64, 4] = [1, 2, 4, 6];
    println(helper(a));
}
"#,
        );
        if let Some(out) = out {
            // cap finds max = 6 from [1,2,4,6]; dummy(6) yields a
            // 6-element Vec; helper returns 6.
            assert_eq!(out.trim(), "6\n6\n6");
        }
    }

    #[test]
    fn test_e2e_for_in_indexed_iter() {
        // `for p in coll[i].iter()` — the iter peel-off in
        // `compile_for` recurses on the receiver, but for an
        // indexed receiver the recursion would land on an Index
        // expression which falls through to the silent `_ =>` arm.
        // Fix: synthesize a temp identifier for the indexed
        // element and recurse with it, mirroring
        // `compile_nested_index_read`. Pins the kata's
        // `for p in factors[v].iter() { bucket.entry(p)... }` shape.
        let out = run_program(
            r#"
fn main() {
    let mut factors: Vec[Vec[i64]] = Vec.filled(7, Vec.new());
    factors[6].push(2);
    factors[6].push(3);
    let mut sum = 0i64;
    for p in factors[6].iter() {
        sum = sum + p;
    }
    println(sum);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "5");
        }
    }

    #[test]
    fn test_e2e_function_returning_vec_of_vec_no_double_free() {
        // Move-aware scope-exit cleanup: when a function returns a
        // tracked Vec / String binding via the tail expression, the
        // let-site's `track_vec_var` cleanup is suppressed (by
        // zeroing the source's `cap` field) so the caller's
        // `f.data` isn't pointing at a freed buffer. Without this,
        // `Vec[Vec[i64]]` returns SIGSEGV at the first inner indexed
        // access (the inner Vec's data pointer GEPs through a freed
        // outer slot).
        let out = run_program(
            r#"
fn make_grid(n: i64) -> Vec[Vec[i64]] {
    let mut g: Vec[Vec[i64]] = Vec.filled(n, Vec.new());
    g[0].push(99);
    g[0].push(11);
    g[2].push(42);
    g
}
fn main() {
    let f: Vec[Vec[i64]] = make_grid(3);
    println(f.len());
    println(f[0].len());
    println(f[0][0]);
    println(f[0][1]);
    println(f[2][0]);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "3\n2\n99\n11\n42");
        }
    }

