    fn test_e2e_function_returning_vec_i64_no_double_free() {
        // Sibling: `Vec[i64]` return — same fix applies. The
        // primitive case happened to work pre-fix due to
        // use-after-free reading stable data, but is now correct
        // by construction (cleanup skipped at the move site, caller
        // owns the buffer cleanly).
        let out = run_program(
            r#"
fn make_vec(n: i64) -> Vec[i64] {
    let mut v: Vec[i64] = Vec.new();
    let mut i = 0i64;
    while i < n {
        v.push(i * 10);
        i = i + 1;
    }
    v
}
fn main() {
    let f: Vec[i64] = make_vec(4);
    println(f.len());
    println(f[3]);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "4\n30");
        }
    }

    #[test]
    fn test_e2e_struct_field_move_no_double_free() {
        // Move-aware suppression at struct-construction sites. When
        // a struct field's initializer is an Identifier naming a
        // tracked Vec / String, the field captures the binding's
        // data pointer — but the source's let-site `track_vec_var`
        // unconditionally schedules a scope-exit free that would
        // free the buffer the caller now reads through the struct.
        // This is the shape Parallax/HTTP hits via
        // `Response { body: my_string }` — without suppression,
        // the caller reads NUL bytes (or SIGSEGVs) downstream of
        // FFI consumption.
        let out = run_program(
            r#"
struct Holder {
    tag: i64,
    body: String,
}
fn build() -> Holder {
    let mut s: String = String.new();
    s.push_str("hello, world");
    Holder { tag: 7, body: s }
}
fn main() {
    let h: Holder = build();
    println(h.tag);
    println(h.body);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "7\nhello, world");
        }
    }

    #[test]
    fn test_e2e_struct_param_field_move_out() {
        // B-2026-06-10-2: moving a Vec field OUT of a by-value struct PARAM
        // (`let inner = h.v`) deep-copies the field buffer so the moved-out
        // local is independent of the caller's (the caller's struct-drop frees
        // the original). Pre-fix this double-freed (the buffer was shallow-
        // shared; ASAN coverage in `tests/memory_sanitizer.rs`). Output
        // correctness on the codegen lane is the non-ASAN guard: reuse + the
        // original both stay valid.
        let out = run_program(
            "struct Holder { v: Vec[i64] }\n\
             fn build() -> Holder {\n\
             \x20   let mut inner: Vec[i64] = Vec.new();\n\
             \x20   inner.push(10i64); inner.push(20i64);\n\
             \x20   Holder { v: inner }\n\
             }\n\
             fn first_elem(h: Holder) -> i64 { let inner = h.v; inner[0] }\n\
             fn main() {\n\
             \x20   let h = build();\n\
             \x20   let a = first_elem(h);\n\
             \x20   let b = first_elem(h);\n\
             \x20   println(a + b);\n\
             }\n",
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "20");
        }
    }

    #[test]
    fn test_e2e_struct_pattern_destructure_heap_field() {
        // #16 (phase-12 self-hosting): a plain struct-pattern match destructure of
        // an OWNED local struct (`match v { S { a, b: _ } => … }`) moves each
        // consumed field's heap payload into the new binding. Without
        // `suppress_destructured_struct_pattern_cleanup` the source struct's drop
        // re-frees the moved buffer (double-free; exit 134 under guardmalloc / ASAN
        // — see `tests/memory_sanitizer.rs::asan_struct_pattern_destructure_no_
        // double_free`). Output correctness is the codegen-lane guard: the
        // partial-bind field (`b: _`) is left to the source drop, the bound fields
        // (including a nested-struct field and an enum field moved whole) read back
        // intact.
        let out = run_program(
            r#"
struct Inner { s: String }
enum Tok { Id(String), Eof }
struct S { a: String, b: String, inner: Inner, tok: Tok, n: i64 }
fn main() {
    let v = S {
        a: "aa".to_string(),
        b: "bb".to_string(),
        inner: Inner { s: "deep".to_string() },
        tok: Tok.Id("tok".to_string()),
        n: 7,
    };
    match v {
        S { a, b: _, inner, tok, n } => {
            let Inner { s } = inner;
            println(a);
            println(s);
            match tok { Id(t) => println(t), Eof => println("eof") }
            println(n.to_string());
        }
    }
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "aa\ndeep\ntok\n7");
        }
    }

    #[test]
    fn test_e2e_let_rebind_move_no_double_free() {
        // `let outer = inner;` where `inner` is a tracked Vec /
        // String is a move — both slots end up holding the same
        // {ptr, len, cap}. Without source-cap suppression at the
        // let-rebind site, both `track_vec_var`-queued cleanups
        // fire and double-free the heap buffer. The LHS's track
        // becomes the unique cleanup owner.
        let out = run_program(
            r#"
fn build() -> String {
    let mut inner: String = String.new();
    inner.push_str("relayed");
    let outer: String = inner;
    outer
}
fn main() {
    let s: String = build();
    println(s);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "relayed");
        }
    }

    #[test]
    fn test_e2e_assign_rebind_move_no_double_free() {
        // `acc = extra;` where both `acc` and `extra` are tracked
        // Vec / String bindings is an assign-rebind. The old
        // `acc` buffer leaks (no RAII drop in v1), but without
        // source-cap suppression on `extra`, both queued cleanups
        // fire against the same post-assign buffer → double-free.
        let out = run_program(
            r#"
fn build() -> String {
    let mut acc: String = String.new();
    acc.push_str("first");
    let mut extra: String = String.new();
    extra.push_str("second");
    acc = extra;
    acc
}
fn main() {
    let s: String = build();
    println(s);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "second");
        }
    }

    #[test]
    fn test_e2e_for_range_step_by_codegen() {
        // `for j in (start..=end).step_by(n)` — the iterator-adaptor
        // chain previously fell through `compile_for`'s match to the
        // silent `_ =>` arm, skipping the body entirely. Now lowers
        // to a Range loop with the step expr evaluated once before
        // the loop and used as the increment. Pins the sieve / strided
        // iteration pattern that the LeetCode 3629 kata uses.
        let out = run_program(
            r#"
fn main() {
    let mut sum = 0i64;
    for j in (2..=10).step_by(2) {
        sum = sum + j;
    }
    println(sum);
    let mut count = 0i64;
    for _ in (0..20).step_by(5) {
        count = count + 1;
    }
    println(count);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "30\n4");
        }
    }

    #[test]
    fn test_e2e_for_range_step_by_with_runtime_step() {
        // The kata's actual usage: the step expression refers to an
        // outer variable. The step is evaluated once per loop entry
        // and captured into the increment block.
        let out = run_program(
            r#"
fn main() {
    let cap = 12i64;
    for i in 2..=cap {
        let mut count = 0i64;
        for _j in (i..=cap).step_by(i) {
            count = count + 1;
        }
        println(count);
    }
}
"#,
        );
        // For each i in 2..=12, count multiples of i up to cap=12:
        //   i=2 → 2,4,6,8,10,12 → 6
        //   i=3 → 3,6,9,12 → 4
        //   i=4 → 4,8,12 → 3
        //   i=5 → 5,10 → 2
        //   i=6 → 6,12 → 2
        //   i=7 → 7 → 1
        //   i=8 → 8 → 1
        //   i=9 → 9 → 1
        //   i=10 → 10 → 1
        //   i=11 → 11 → 1
        //   i=12 → 12 → 1
        if let Some(out) = out {
            assert_eq!(out.trim(), "6\n4\n3\n2\n2\n1\n1\n1\n1\n1\n1");
        }
    }

