    #[test]
    fn test_e2e_enum_display_payload_variants() {
        // Payload-bearing `#[derive(Display)]` enum (phase-8 main()-entry-point
        // prerequisite, Slice A): tuple + struct variants render via the
        // value-driven `emit_enum_display_fn` as `Variant(f0, f1)` /
        // `Variant { name: v }`, including a heap (String) payload rendered
        // read-only (no move/free) — the `IoError.Other(String)` shape. Matches
        // the interpreter byte-for-byte. (`let b = E.S { .. }` is now
        // UNANNOTATED — B-2026-06-13-9 fixed: `type_name_of` resolves an enum
        // struct-variant construction to the ENUM, so the binding registers in
        // `var_type_names` and the f-string / println Display routing finds it.)
        if let Some(out) = run_program(
            r#"
#[derive(Display)]
enum Shape { Circle(i64), Rect { w: i64, h: i64 }, Dot }
#[derive(Display)]
enum Msg { Text(String), Code(i64) }
fn main() {
    let a = Shape.Circle(5);
    let b = Shape.Rect { w: 3, h: 4 };
    let c = Shape.Dot;
    println(a);
    println(b);
    println(c);
    println(f"x={a} y={b} z={c}");
    let m = Msg.Text("hi".to_string());
    println(m);
    println(f"m={m}");
}
"#,
        ) {
            assert_eq!(
                out,
                "Circle(5)\nRect { w: 3, h: 4 }\nDot\nx=Circle(5) y=Rect { w: 3, h: 4 } z=Dot\nText(hi)\nm=Text(hi)\n"
            );
        }
    }

    #[test]
    fn test_e2e_let_bound_enum_heap_payload_moved_out() {
        // #9 (phase-12 self-hosting): a bare `let`-bound enum with a heap
        // payload, moved out by `return`, must reach the consumer intact (the
        // source's `EnumDrop` is suppressed so the payload isn't freed before
        // use). Value-correctness twin of the ASAN regression — `make()`
        // returns `let e = E.Id(...); e` and the caller reads the String back.
        if let Some(out) = run_program(
            r#"
enum E { Id(String), N(i64) }
fn make() -> E {
    let e = E.Id("hello".to_string());
    e
}
fn main() {
    let r = make();
    match r {
        Id(s) => println(s),
        N(n) => println(n.to_string()),
    }
}
"#,
        ) {
            assert_eq!(out, "hello\n");
        }
    }

    #[test]
    fn test_e2e_byvalue_aggregate_param_transferred_out_enum() {
        // #14 (phase-12 self-hosting): an owned by-value ENUM param moved into a
        // call that transfers it OUT (the callee returns it) must reach the
        // consumer intact and free exactly once. `wrap(f)` returns its param;
        // both the caller's source `f` and the result `g` previously aliased and
        // double-freed the same payload buffer. The param is now entry
        // deep-copied + callee-owned (param_own.rs), so the two own independent
        // buffers.
        if let Some(out) = run_program(
            r#"
enum E { A(String), N(i64) }
fn wrap(e: E) -> E { e }
fn main() {
    let f = E.A("hi".to_string());
    let g = wrap(f);
    match g {
        A(s) => println(s),
        N(n) => println(n.to_string()),
    }
}
"#,
        ) {
            assert_eq!(out, "hi\n");
        }
    }

    #[test]
    fn test_e2e_byvalue_aggregate_param_transferred_out_struct() {
        // #14: the STRUCT half — proves the gap was never enum-specific. An owned
        // by-value struct param consumed into a returned struct literal
        // (`Wrap { t: t }`) previously double-freed the inner String buffer the
        // caller's source `x` also frees.
        if let Some(out) = run_program(
            r#"
struct Inner { s: String }
struct Wrap { t: Inner }
fn wrap(t: Inner) -> Wrap { Wrap { t: t } }
fn main() {
    let x = Inner { s: "hi".to_string() };
    let w = wrap(x);
    println(w.t.s);
}
"#,
        ) {
            assert_eq!(out, "hi\n");
        }
    }

    #[test]
    fn test_e2e_byvalue_enum_param_wrapped_into_struct_and_destructured() {
        // #14: the bootstrap shape — an enum param moved into a returned struct
        // literal (`Spanned { tok: t, .. }`, mirroring the self-hosted lexer's
        // `make_spanned(token)`), then destructured by the caller. The flowed
        // copy and the caller's source must be independent.
        if let Some(out) = run_program(
            r#"
enum Token { Ident(String), Int(i64) }
struct Spanned { tok: Token, off: i64 }
fn make_spanned(t: Token, o: i64) -> Spanned { Spanned { tok: t, off: o } }
fn main() {
    let t = Token.Ident("hello".to_string());
    let s = make_spanned(t, 3);
    match s.tok {
        Ident(name) => println(name),
        Int(n) => println(n.to_string()),
    }
}
"#,
        ) {
            assert_eq!(out, "hello\n");
        }
    }

    #[test]
    fn test_e2e_byvalue_aggregate_param_read_then_reused() {
        // #14 guard: passing an owned aggregate by value to a function that only
        // READS it must NOT break re-use of the source (`take(x); take(x)`).
        // Entry deep-copy keeps this correct (each call copies at entry; the
        // caller retains and frees its original once) — the reason the fix is
        // entry-copy rather than a caller-side move (which would use-after-free
        // here, since Kāra's move-checker does not reject double-consume).
        if let Some(out) = run_program(
            r#"
struct S { s: String }
fn take(v: S) { println(v.s) }
fn main() {
    let x = S { s: "hi".to_string() };
    take(x);
    take(x);
    println(x.s);
}
"#,
        ) {
            assert_eq!(out, "hi\nhi\nhi\n");
        }
    }

    #[test]
    fn test_e2e_struct_with_direct_enum_field_heap_payload() {
        // #15 (phase-12 self-hosting): a struct whose field is a heap-bearing
        // user enum (`Span { tok: Tok, .. }`, the bootstrap's `SpannedToken`
        // shape). The enum payload (`Tok.Id(String)`) must survive being built,
        // transferred out of a by-value param (`wrap`), and destructured — and
        // the struct's synthesized drop must free the enum field exactly once
        // (no double-free / corruption). Correctness is observed via the
        // round-tripped String payloads; the leak itself is covered by the
        // ASAN test on Linux.
        //
        // #19 FIXED 2026-06-12 — transfer-out of an enum-field struct followed by
        // a destructure that *uses* the bound payload is now sound. The fix is
        // entry-copy for enum-field structs (`field_copy_supported` user-enum arm
        // → true; `deep_copy_one_aggregate_field` deep-copies the enum payload via
        // `deep_copy_enum_heap_payload_in_place`): the callee owns a copy
        // independent of the caller's retained original, so `let b = wrap(a)` no
        // longer aliases `a`'s enum buffer and the two struct drops free distinct
        // buffers. `e1`/`e2` below exercise the previously-excised shape — a
        // transfer-out then a BORROW arm (`match b.tok { Id(s) => println(s) }`)
        // and a CONSUME arm — both guardmalloc-clean at O0 and O2. Earlier this
        // double-freed (the source and the transferred result aliased one enum
        // buffer); it passed on normal malloc only by allocation luck, which #20's
        // layout shift removed.
        if let Some(out) = run_program(
            r#"
enum Tok { Id(String), Int(i64) }
struct Span { tok: Tok, off: i64 }
fn wrap(s: Span) -> Span { s }
fn sink(x: String) { if x.len() > 9000 { println(x) } }
fn main() {
    let a = Span { tok: Tok.Id("hello".to_string()), off: 1 };
    let b = wrap(a);
    println(b.off.to_string());
    let c = Span { tok: Tok.Int(42_i64), off: 2 };
    match c.tok { Id(s) => println(s), Int(n) => println(n.to_string()) }
    let d = Span { tok: Tok.Id("world".to_string()), off: 3 };
    match d.tok { Id(s) => println(s), Int(n) => println(n.to_string()) }
    // #19: transfer-out then destructure-and-USE the bound payload.
    let e1 = Span { tok: Tok.Id("xfer".to_string()), off: 4 };
    let f1 = wrap(e1);
    match f1.tok { Id(s) => println(s), Int(n) => println(n.to_string()) }
    let e2 = Span { tok: Tok.Id("cons".to_string()), off: 5 };
    let f2 = wrap(e2);
    match f2.tok { Id(s) => sink(s), Int(n) => println(n.to_string()) }
    println("ok");
}
"#,
        ) {
            assert_eq!(out, "1\n42\nworld\nxfer\nok\n");
        }
    }

    #[test]
    fn test_e2e_struct_nested_enum_leaf_heap_payload() {
        // #18 (phase-12 self-hosting): a struct whose only heap is TRANSITIVELY
        // inside an enum nested under ANOTHER struct field — `Wrap { sp: Span }`
        // with `Span { tok: Tok }` and `Tok` heap-bearing. #15 freed only a
        // DIRECT enum field; `emit_struct_drop_synthesis` now routes a NAMED
        // nested struct field through its own `__karac_drop_struct_<S>` (which
        // post-#15 frees its enum fields). Correctness here is the round-tripped
        // payloads through a struct-literal move into a Wrap then a two-level
        // (`w.sp.tok`) match-BORROW, a three-level (`Deep -> Wrap -> Span ->
        // Tok`) undestructured drop, and a two-level Int-variant match. The leak
        // is covered by `asan_struct_nested_enum_leaf_no_leak_no_double_free`.
        //
        // #19 FIXED 2026-06-12 — the nested-struct TRANSFER-out then two-level
        // match-BORROW (`let b = fwd(a); match b.sp.tok { Id(s) => println(s) }`)
        // is now sound (entry-copy for enum-field structs recurses through the
        // nested `Wrap { sp: Span { tok } }`, so `fwd`'s result owns a copy
        // independent of the source). Exercised by `t1` below; guardmalloc-clean
        // at O0 and O2. Previously double-freed on the caller-retains path.
        if let Some(out) = run_program(
            r#"
enum Tok { Id(String), Int(i64) }
struct Span { tok: Tok, off: i64 }
struct Wrap { sp: Span, hi: i64 }
struct Deep { w: Wrap, tag: i64 }
fn mk(n: i64, s: String) -> Wrap { Wrap { sp: Span { tok: Tok.Id(s), off: n }, hi: n } }
fn fwd(w: Wrap) -> Wrap { w }
fn main() {
    let span = Span { tok: Tok.Id("beta".to_string()), off: 2 };
    let w = Wrap { sp: span, hi: 2 };
    match w.sp.tok { Id(s) => println(s), Int(n) => println(n.to_string()) }

    let deep = Deep { w: mk(3, "gamma".to_string()), tag: 7 };
    println(deep.tag.to_string());

    let c = Wrap { sp: Span { tok: Tok.Int(42_i64), off: 4 }, hi: 4 };
    match c.sp.tok { Id(s) => println(s), Int(n) => println(n.to_string()) }
    // #19: nested transfer-out then two-level match-BORROW of the payload.
    let a1 = Wrap { sp: Span { tok: Tok.Id("xfer".to_string()), off: 5 }, hi: 5 };
    let t1 = fwd(a1);
    match t1.sp.tok { Id(s) => println(s), Int(n) => println(n.to_string()) }
    println("ok");
}
"#,
        ) {
            assert_eq!(out, "beta\n7\n42\nxfer\nok\n");
        }
    }

    #[test]
    fn test_e2e_struct_tuple_enum_leaf_heap_payload() {
        // #21 (phase-12 self-hosting): a struct field that is an anonymous TUPLE
        // whose only heap is inside an enum leaf — `struct H { pe: (Tok, i64) }`
        // with heap enum `Tok`. The struct drop's `NestedTuple` path frees the
        // enum leaf; paired cap-zero suppression at the destructure / tuple-index
        // match / tuple-index let sites and entry-copy of heap-bearing tuple
        // params keep every CONSUME shape single-free. Correctness here is the
        // payloads round-tripping through: a full-tuple destructure + match
        // (`let (t, n) = h.pe; match t`), a direct tuple-index match
        // (`match h.pe.0`), a tuple-index let-move (`let x = h.pe.0`), and a
        // whole-tuple by-value arg whose callee matches an element internally
        // (`sinkt(h.pe)` — the cross-boundary case the param entry-copy closes).
        // The leak + double-free are covered by
        // `asan_struct_tuple_enum_leaf_no_leak_no_double_free`.
        if let Some(out) = run_program(
            r#"
enum Tok { Id(String), Int(i64) }
struct H { pe: (Tok, i64), tag: i64 }
fn sinkt(p: (Tok, i64)) -> String { match p.0 { Id(s) => s, Int(n) => n.to_string() } }
fn main() {
    let a = H { pe: (Tok.Id("alpha".to_string()), 1), tag: 1 };
    let (t, n) = a.pe;
    match t { Id(s) => println(s), Int(x) => println(x.to_string()) }
    println(n.to_string());

    let b = H { pe: (Tok.Id("beta".to_string()), 2), tag: 2 };
    match b.pe.0 { Id(s) => println(s), Int(x) => println(x.to_string()) }

    let c = H { pe: (Tok.Id("gamma".to_string()), 3), tag: 3 };
    let x = c.pe.0;
    match x { Id(s) => println(s), Int(z) => println(z.to_string()) }

    let d = H { pe: (Tok.Id("delta".to_string()), 4), tag: 4 };
    println(sinkt(d.pe));

    let e = H { pe: (Tok.Int(5_i64), 5), tag: 5 };
    match e.pe.0 { Id(s) => println(s), Int(z) => println(z.to_string()) }
    println("ok");
}
"#,
        ) {
            assert_eq!(out, "alpha\n1\nbeta\ngamma\ndelta\n5\nok\n");
        }
    }

    #[test]
    fn test_e2e_inline_enum_field_struct_arg() {
        // #22 (phase-12 self-hosting) — the #19 fresh-temp tail. An enum-field
        // struct constructed INLINE as a call argument (`consume(W { tok: Tok.Id(..) })`,
        // no caller binding) whose callee consumes the enum internally entry-copies
        // the param; the inline temp's original payload had no caller owner and
        // leaked. Correctness here is the payloads round-tripping through the bare
        // arg (free fn + method site), an enum leaf nested one struct deeper, and a
        // direct-Vec struct arg (regression). The leak is covered by
        // `asan_inline_enum_field_struct_arg_no_leak`.
        if let Some(out) = run_program(
            r#"
enum Tok { Id(String), Int(i64) }
struct W { tok: Tok, n: i64 }
struct Inner { tok: Tok, k: i64 }
struct Outer { inner: Inner, n: i64 }
struct V { xs: Vec[i64], n: i64 }
struct Sink { total: i64 }
fn consume(w: W) -> String { match w.tok { Id(s) => s, Int(z) => z.to_string() } }
fn consume_outer(o: Outer) -> String { match o.inner.tok { Id(s) => s, Int(z) => z.to_string() } }
fn consume_vec(v: V) -> i64 { v.xs.len() }
fn mkv(n: i64) -> Vec[i64] { let mut a: Vec[i64] = Vec.new(); a.push(n); a.push(n + 1); a }
impl Sink {
    fn take(mut ref self, w: W) -> String { match w.tok { Id(s) => s, Int(z) => z.to_string() } }
}
fn main() {
    println(consume(W { tok: Tok.Id("alpha".to_string()), n: 1 }));
    let mut sk = Sink { total: 0 };
    println(sk.take(W { tok: Tok.Id("mike".to_string()), n: 2 }));
    println(consume_outer(Outer { inner: Inner { tok: Tok.Id("oscar".to_string()), k: 3 }, n: 3 }));
    println(consume_vec(V { xs: mkv(10), n: 4 }).to_string());
    println(consume(W { tok: Tok.Int(7_i64), n: 5 }));
    println("ok");
}
"#,
        ) {
            assert_eq!(out, "alpha\nmike\noscar\n2\n7\nok\n");
        }
    }

    #[test]
    fn test_e2e_struct_tuple_map_leaf_drop_flags() {
        // #23 (phase-12 self-hosting) — a `Map` leaf inside a tuple inside a struct
        // field. Two coupled fixes land here: (1) a `Map` folded into a tuple
        // transfers its handle to the tuple's owner — the source binding's
        // `FreeMapHandle` is dropped at tuple construction (Part B) and a Map-owning
        // tuple VAR gets a `TypeExpr`-driven drop (Part A) / is suppressed when moved
        // into a struct field (Part C1) — so the owning struct's #21 `NestedTuple`
        // drop is the SOLE freer (was a double-free against the caller-retains source
        // binding that still freed); (2) the `NestedTuple` Map drop AND the regular
        // struct-field Map drop now compute the `karac_map_free_with_drop_vec` K/V
        // flags from the element types instead of hardcoding `(1, 1)` — the old flags
        // read offset-16 of an 8-byte scalar key as a bogus `cap` and freed the key
        // VALUE as a pointer, corrupting any occupied `Map[i64, i64]`
        // (`B-2026-06-13-18`). Correctness here is the map contents round-tripping
        // for scalar / String-key / Vec-value maps (read via the whole-tuple by-value
        // path, which is sound — `struct.tuple.0` element reads are a separate
        // pre-existing place-chain gap, see #25), a tuple var moved into a struct
        // field, and a plain `Map` struct field (the regular drop path). The leak +
        // double-free are covered by `asan_struct_tuple_map_leaf_no_double_free`.
        if let Some(out) = run_program(
            r#"
struct Hi { m: (Map[i64, i64], i64) }
struct Hs { m: (Map[String, i64], i64) }
struct Hv { m: (Map[i64, Vec[i64]], i64) }
struct Sp { m: Map[i64, i64] }
fn ci(p: (Map[i64, i64], i64)) -> i64 { let (mm, n) = p; mm.len() + n }
fn cs(p: (Map[String, i64], i64)) -> i64 { let (mm, n) = p; mm.len() + n }
fn cv(p: (Map[i64, Vec[i64]], i64)) -> i64 { let (mm, n) = p; mm.len() + n }
fn main() {
    // Scalar tuple-Map field, local source (the #23 double-free shape) + by-value consume.
    let mut a: Map[i64, i64] = Map.new();
    a.insert(1, 10); a.insert(2, 20);
    let hi = Hi { m: (a, 3) };
    println(ci(hi.m).to_string());
    // String-key tuple-Map field (drop_key must be 1 — free the key buffers).
    let mut s: Map[String, i64] = Map.new();
    s.insert("alpha".to_string(), 1); s.insert("beta".to_string(), 2);
    let hs = Hs { m: (s, 7) };
    println(cs(hs.m).to_string());
    // Vec-value tuple-Map field (drop_val must be 1 — free the value buffers).
    let mut v: Map[i64, Vec[i64]] = Map.new();
    let mut vv: Vec[i64] = Vec.new(); vv.push(9);
    v.insert(5, vv);
    let hv = Hv { m: (v, 0) };
    println(cv(hv.m).to_string());
    // Tuple VAR moved into a struct field (Part A registers its drop, Part C1
    // suppresses it on the move so only the struct's NestedTuple drop frees).
    let mut b: Map[i64, i64] = Map.new();
    b.insert(4, 40);
    let pair = (b, 8);
    let hi2 = Hi { m: pair };
    println(ci(hi2.m).to_string());
    // Plain Map[i64,i64] struct field — the regular MapOrSet drop path + flag fix.
    let mut c: Map[i64, i64] = Map.new();
    c.insert(6, 60);
    let sp = Sp { m: c };
    println(sp.m.len().to_string());
    println("ok");
}
"#,
        ) {
            assert_eq!(out, "5\n9\n1\n9\n1\nok\n");
        }
    }

    #[test]
    fn test_e2e_deep_tuple_index_field_read_and_match() {
        // #25 (phase-12 self-hosting, B-2026-06-14-4) — reading a struct field
        // through a `<struct>.tuplefield.0.<field>` place chain. The element-0
        // struct's type wasn't resolved by `type_name_of_expr`'s `TupleIndex`
        // arm (Identifier-rooted only), so `field_index_for` found no field and
        // `compile_field_access` returned the `i64 0` placeholder — a scalar
        // field `h.ps.0.n` read 0 instead of 42, and an enum field
        // `match h.ps.0.tok { Id(s) => s.len() }` build-failed because the
        // scrutinee never resolved to its enum (so the arm binding `s` got no
        // String dispatch — "no handler for method 'len' on variable 's'"). Fix:
        // resolve the element struct type via the deep-chain walk
        // (`place_chain_tuple_tes`) for a non-Identifier-rooted tuple. The
        // match-arm payload consume is guardmalloc-clean (the existing #21
        // tuple-index match suppression cap-zeros the source); see
        // `asan_deep_tuple_index_match_no_double_free`. Element 1 (`h.ps.1`, a
        // scalar) always read correctly — only element-0-as-aggregate was broken.
        if let Some(out) = run_program(
            r#"
enum Tok { Id(String), Num(i64) }
struct Inner { tok: Tok, n: i64 }
struct Hs { ps: (Inner, i64) }
fn main() {
    let h = Hs { ps: (Inner { tok: Tok.Id("hello".to_string()), n: 42 }, 7) };
    // Scalar field through the tuple chain (was 0).
    println(h.ps.0.n.to_string());
    // Scalar second element (always worked — regression guard).
    println(h.ps.1.to_string());
    // Enum field as a match scrutinee — the arm binding dispatch (was build-fail).
    match h.ps.0.tok {
        Id(s) => { println(s.len().to_string()); }
        Num(n) => { println(n.to_string()); }
    }
    // Borrow arm (prints the payload directly).
    let h2 = Hs { ps: (Inner { tok: Tok.Id("world".to_string()), n: 1 }, 2) };
    match h2.ps.0.tok {
        Id(s) => { println(s); }
        Num(n) => { println(n.to_string()); }
    }
}
"#,
        ) {
            assert_eq!(out, "42\n7\n5\nworld\n");
        }
    }

    #[test]
    fn test_e2e_tuple_index_map_set_receiver_method() {
        // #26 (phase-12 self-hosting, B-2026-06-14-6) — a method on a Map/Set
        // TUPLE element (`h.m.0.len()`). `Map`/`Set` lower to an opaque `ptr`
        // handle, and their runtime methods (`karac_map_*`) resolve the handle
        // via a NAMED slot (`compile_map_method` → `get_data_ptr`) — so only an
        // identifier receiver dispatched correctly. A tuple-index receiver fell
        // through to a generic path and read a GARBAGE handle (`h.m.0.len()`
        // printed e.g. `6132656048`); the FieldAccess peer `s.m.len()` already
        // worked. Fix: a `TupleIndex` sibling of `try_compile_field_receiver_method`
        // that GEPs to the element handle slot (`field_chain_place_ptr`) and
        // re-dispatches through a synth identifier — so len/get/contains_key/
        // is_empty AND in-place insert all resolve. Vec/scalar tuple elements are
        // unaffected (they already work via value extraction). The scalar second
        // element (`h.m.1`) is the regression guard.
        if let Some(out) = run_program(
            r#"
struct H { m: (Map[i64, i64], i64) }
struct Hs { s: (Set[i64], i64) }
fn mkm() -> Map[i64, i64] {
    let mut m: Map[i64, i64] = Map.new();
    m.insert(1, 10); m.insert(2, 20);
    return m;
}
fn mks() -> Set[i64] {
    let mut s: Set[i64] = Set.new();
    s.insert(3); s.insert(4);
    return s;
}
fn main() {
    let mut h = H { m: (mkm(), 7) };
    println(h.m.0.len().to_string());                 // 2
    println(h.m.0.get(1).unwrap_or(0).to_string());   // 10
    println(h.m.0.contains_key(2).to_string());       // true
    println(h.m.1.to_string());                       // 7 (scalar elem regression)
    // In-place mutation through the tuple element.
    h.m.0.insert(9, 90);
    println(h.m.0.len().to_string());                 // 3
    println(h.m.0.get(9).unwrap_or(0).to_string());   // 90
    // Set element methods.
    let hs = Hs { s: (mks(), 1) };
    println(hs.s.0.len().to_string());                // 2
    println(hs.s.0.contains(3).to_string());          // true
}
"#,
        ) {
            assert_eq!(out, "2\n10\ntrue\n7\n3\n90\n2\ntrue\n");
        }
    }

    #[test]
    fn test_e2e_map_set_local_bind_from_place() {
        // #28 (phase-12 self-hosting, B-2026-06-14-9) — a Map/Set bound to a
        // LOCAL from a PLACE source with no annotation (`let mm = s.m` /
        // `let mm = h.m.0`). The let-binding's unannotated fallback registered
        // only `var_type_names` (not the Map/Set dispatch side-tables), so
        // `mm.len()` build-failed (`no handler for method 'len' on variable
        // 'mm'`). Fix: a Map/Set arm in the fallback registers the side-tables
        // from the typechecker's `pattern_binding_inner_types`. `mm` aliases the
        // source handle (caller-retains — no second `FreeMapHandle`), so the
        // owner is the sole freer; an in-place mutation through `mm` mutates the
        // shared map. The annotated form (`let mm: Map[..] = s.m`) already worked.
        if let Some(out) = run_program(
            r#"
struct S { m: Map[i64, i64] }
struct Hz { z: Set[i64] }
struct Ht { t: (Map[i64, i64], i64) }
fn mkm() -> Map[i64, i64] { let mut m: Map[i64, i64] = Map.new(); m.insert(1, 10); m.insert(2, 20); return m; }
fn mks() -> Set[i64] { let mut s: Set[i64] = Set.new(); s.insert(3); s.insert(4); return s; }
fn main() {
    // Map field bound to a local, no annotation.
    let s = S { m: mkm() };
    let mm = s.m;
    println(mm.len().to_string());                  // 2
    println(mm.get(1).unwrap_or(0).to_string());    // 10
    // Mutation through the bound local (mutates the shared handle).
    let s2 = S { m: mkm() };
    let mut mm2 = s2.m;
    mm2.insert(9, 90);
    println(mm2.len().to_string());                 // 3
    // Set field bound to a local.
    let z = Hz { z: mks() };
    let ss = z.z;
    println(ss.len().to_string());                  // 2
    println(ss.contains(3).to_string());            // true
    // Map TUPLE element bound to a local.
    let h = Ht { t: (mkm(), 7) };
    let tm = h.t.0;
    println(tm.len().to_string());                  // 2
}
"#,
        ) {
            assert_eq!(out, "2\n10\n3\n2\ntrue\n2\n");
        }
    }

    #[test]
    fn test_e2e_tuple_elem_bind_move_out() {
        // #27 (phase-12 self-hosting, B-2026-06-14-8) — binding a heap-bearing
        // value OUT of a tuple element. `let inr = h.ps.0` (a heap-bearing struct
        // moved out of a tuple element) and `let tk = h.ps.0.tok` (an enum field
        // moved out of a tuple-element struct) each registered the binding's drop
        // but did NOT suppress the SOURCE — so both the binding's drop and the
        // owning `h`'s `NestedTuple` tuple drop freed the same buffer
        // (double-free). Fix: call `suppress_tuple_index_move_source` in the
        // struct-binding path (cap-zeros the struct element via
        // `zero_struct_move_caps`), and add `suppress_place_field_enum_move_source`
        // for the `<tupleindex>.field` enum form (place-chain GEP +
        // `zero_enum_payload_caps`). Correctness here is the moved-out value
        // surviving + reading right (consume + read forms); the double-free is in
        // `asan_tuple_elem_bind_move_out_no_double_free`. A heapless tuple element
        // (`Plain`) is the regression guard.
        if let Some(out) = run_program(
            r#"
enum Tok { Id(String), Num(i64) }
struct Inner { tok: Tok, n: i64 }
struct Hs { ps: (Inner, i64) }
struct Plain { a: i64, b: i64 }
struct Hp { ps: (Plain, i64) }
fn main() {
    // Struct element moved out, then read a field.
    let h1 = Hs { ps: (Inner { tok: Tok.Id("alpha".to_string()), n: 42 }, 7) };
    let inr = h1.ps.0;
    println(inr.n.to_string());                 // 42
    // Struct element moved out, then CONSUME its enum field via match.
    let h2 = Hs { ps: (Inner { tok: Tok.Id("beta".to_string()), n: 1 }, 2) };
    let inr2 = h2.ps.0;
    match inr2.tok { Id(s) => { println(s); } Num(n) => { println(n.to_string()); } }  // beta
    // Enum field moved out THROUGH the tuple element, then consumed.
    let h3 = Hs { ps: (Inner { tok: Tok.Id("gamma".to_string()), n: 9 }, 3) };
    let tk = h3.ps.0.tok;
    match tk { Id(s) => { println(s); } Num(n) => { println(n.to_string()); } }        // gamma
    // Heapless tuple element — regression guard (reads the right field).
    let hp = Hp { ps: (Plain { a: 5, b: 6 }, 7) };
    let p = hp.ps.0;
    println(p.a.to_string());                   // 5
}
"#,
        ) {
            assert_eq!(out, "42\nbeta\ngamma\n5\n");
        }
    }

    #[test]
    fn test_e2e_call_result_tuple_var_drop() {
        // #24 (phase-12 self-hosting) — a let-bound tuple VAR sourced from a CALL
        // (`let p = ret_tuple(i)`, RHS a `Call`, not a tuple literal, no annotation)
        // whose only heap is an enum / Map leaf. `track_tuple_var` is enum/Map-blind
        // (the leaf is all-i64 words), and the call-result source missed the
        // annotation/literal arms of `tuple_binding_elem_tes`, so NO drop was
        // registered and the leaf leaked. The fix recovers the element `TypeExpr`s
        // from the callee's recorded return type (`fn_return_type_exprs`) so the
        // `TypeExpr`-driven tuple drop runs. Coupled (`B-2026-06-14-1`): the drop-fn
        // memoization key (`type_expr_sig`) now folds in generic args, so
        // `Map[i64,i64]` ((0,0) flags) and `Map[String,i64]` ((1,0) flags) get
        // distinct drop fns rather than aliasing (a scalar-first program had leaked
        // a later `Map[String,_]`'s keys). Correctness is the call-sourced tuple
        // still round-tripping when later consumed, across enum / scalar-map /
        // String-key-map leaves; the leak fix itself is in
        // `asan_call_result_tuple_var_no_leak`.
        if let Some(out) = run_program(
            r#"
enum Tok { Id(String), Num(i64) }
fn ret_tuple(i: i64) -> (Tok, i64) { return (Tok.Id(f"id{i}"), i); }
fn ret_imap(i: i64) -> (Map[i64, i64], i64) {
    let mut m: Map[i64, i64] = Map.new();
    m.insert(i, i * 10);
    return (m, i);
}
fn ret_smap(i: i64) -> (Map[String, i64], i64) {
    let mut m: Map[String, i64] = Map.new();
    m.insert(f"k{i}", i);
    return (m, i);
}
fn use_tok(t: Tok) -> String {
    match t { Id(s) => s, Num(n) => n.to_string() }
}
fn main() {
    // Call-sourced enum-leaf tuple var, then destructure + consume.
    let p = ret_tuple(2);
    let (t, n) = p;
    println(f"{use_tok(t)}-{n}");
    // Call-sourced scalar-map tuple var, consumed by-value.
    let q = ret_imap(4);
    let (m1, a) = q;
    println(f"{m1.len()}-{a}");
    // Call-sourced String-key-map tuple var (distinct memo key from scalar map).
    let r = ret_smap(6);
    let (m2, b) = r;
    println(f"{m2.len()}-{b}");
    println("ok");
}
"#,
        ) {
            assert_eq!(out, "id2-2\n1-4\n1-6\nok\n");
        }
    }

    #[test]
    fn test_e2e_enum_field_struct_field_move_out_loop() {
        // #19 FIXED 2026-06-12 — the bootstrap lexer's `render()` shape: iterate a
        // `Vec[SpannedToken]` and pass each element BY VALUE to a fn that moves the
        // enum field OUT of its (now entry-copied) param into a local
        // (`let tk = t.token; match tk { … }`). Entry-copy makes the param
        // callee-owned, and the enum-field move-out cap-zeros the source field in
        // the owning struct's slot (`suppress_struct_field_move_into_literal`'s
        // enum arm, wired from the enum let-binding site) so the param's struct
        // drop and the moved-out local's drop free distinct buffers. Without the
        // cap-zero this double-freed (exit 133); the leak/double-free is covered by
        // `asan_enum_field_struct_field_move_out_no_double_free`.
        if let Some(out) = run_program(
            r#"
enum Tok { Id(String), Eof }
struct Span2 { offset: i64, length: i64 }
struct Span { token: Tok, span: Span2 }
fn render(t: Span) -> String {
    let off = t.span.offset;
    let mut line = f"{off} ";
    let tk = t.token;
    match tk {
        Id(s) => line.push_str(s),
        Eof => line.push_str("eof"),
    }
    line
}
fn build() -> Vec[Span] {
    let mut out: Vec[Span] = Vec.new();
    out.push(Span { token: Tok.Id("alpha".to_string()), span: Span2 { offset: 1, length: 5 } });
    out.push(Span { token: Tok.Id("beta".to_string()), span: Span2 { offset: 7, length: 4 } });
    out.push(Span { token: Tok.Eof, span: Span2 { offset: 11, length: 0 } });
    out
}
fn main() {
    let toks = build();
    for t in toks {
        println(render(t));
    }
}
"#,
        ) {
            assert_eq!(out, "1 alpha\n7 beta\n11 eof\n");
        }
    }

    #[test]
    fn test_e2e_enum_field_in_struct_display() {
        // A struct whose field is an all-unit enum renders the enum field as
        // its variant name (recursing through the struct Display path).
        if let Some(out) = run_program(
            r#"
#[derive(Display)]
enum Color { Red, Green, Blue }
#[derive(Display)]
struct Tagged { c: Color, n: i64 }
fn main() {
    let t = Tagged { c: Color.Blue, n: 9 };
    println(t);
    let t2 = Tagged { c: Color.Red, n: 1 };
    println(t2.to_string());
    let t3 = Tagged { c: Color.Green, n: 2 };
    println(f"t={t3}");
}
"#,
        ) {
            assert_eq!(
                out,
                "Tagged { c: Blue, n: 9 }\n\
                 Tagged { c: Red, n: 1 }\n\
                 t=Tagged { c: Green, n: 2 }\n"
            );
        }
    }

    // ── Arithmetic fault traps (design.md § Arithmetic Overflow) ───────
    // AOT parity with the interpreter's checked arithmetic
    // (src/interpreter/eval_ops.rs): + - * trap "integer overflow",
    // / and % by zero trap "division by zero", iN::MIN / -1 and % -1
    // trap "integer overflow" (same family), unary -iN::MIN traps.
    // Before 2026-06-07 these were nsw/raw ops — IR-level UB that
    // happened to wrap (or print garbage, for div) on arm64. Operands
    // are built via `let mut` + reassignment so neither const-eval nor
    // instcombine folds the fault away before the runtime check.

    #[test]
    fn test_e2e_int_overflow_add_traps() {
        let captured = run_program_capturing(
            r#"
fn main() {
    let mut x = 9223372036854775806;
    x = x + 1;
    x = x + 1;
    println(x);
}
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("integer overflow"),
                "expected integer-overflow panic, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                !c.stdout.contains("-9223372036854775808"),
                "wrapped value must not print"
            );
        }
    }

    #[test]
    fn test_e2e_int_overflow_sub_traps() {
        let captured = run_program_capturing(
            r#"
fn main() {
    let mut x = -9223372036854775807;
    x = x - 1;
    x = x - 1;
    println(x);
}
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("integer overflow"),
                "expected integer-overflow panic on MIN - 1, got stdout={:?}",
                c.stdout
            );
        }
    }

    #[test]
    fn test_e2e_int_overflow_mul_traps() {
        let captured = run_program_capturing(
            r#"
fn main() {
    let mut x = 4611686018427387904;
    x = x * 2;
    println(x);
}
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("integer overflow"),
                "expected integer-overflow panic on 2^62 * 2, got stdout={:?}",
                c.stdout
            );
        }
    }

