    #[test]
    fn test_e2e_negative_min_literal_folds_without_trap() {
        // `-2147483648i32` parses as Neg(Integer(2147483648)) and is
        // range-valid as a UNIT. Codegen folds it to one constant; without
        // the fold, the positive half wraps at i32 width and the checked
        // neg spuriously traps (caught by asan_kata_8 atoi, 2026-06-07).
        let out = run_program(
            r#"
fn main() {
    let int_min: i32 = -2147483648i32;
    println(int_min);
    let i64_min = -9223372036854775807 - 1;
    println(i64_min);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out, "-2147483648\n-9223372036854775808\n");
        }
    }

    #[test]
    fn test_e2e_checked_arith_non_faulting_results_unchanged() {
        // The checked lowering must not perturb in-range arithmetic.
        let out = run_program(
            r#"
fn main() {
    let mut a = 20;
    a = a + 0;
    let b = 22;
    println(a + b);
    println(a - b);
    println(a * b);
    println(b / a);
    println(b % a);
    println(-a);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out, "42\n-2\n440\n1\n2\n-20\n");
        }
    }

    #[test]
    fn test_ir_add_emits_checked_overflow_intrinsic() {
        let ir = ir_for(
            r#"
fn main() {
    let mut x = 1;
    x = x + 41;
    println(x);
}
"#,
        );
        assert!(
            ir.contains("sadd.with.overflow"),
            "signed add must lower through llvm.sadd.with.overflow, IR:\n{ir}"
        );
        assert!(
            ir.contains("add.ovf.trap"),
            "overflow trap block must be emitted, IR:\n{ir}"
        );
    }

    #[test]
    fn test_ir_div_emits_zero_and_min_guards() {
        let ir = ir_for(
            r#"
fn main() {
    let mut z = 3;
    z = z + 0;
    let q = 7 / z;
    println(q);
}
"#,
        );
        assert!(
            ir.contains("div.zero.trap"),
            "division must emit a zero-guard trap block, IR:\n{ir}"
        );
        assert!(
            ir.contains("div.ovf.trap"),
            "signed division must emit the MIN/-1 overflow guard, IR:\n{ir}"
        );
    }

    // ── Monotone-variable BCE — llvm.assume range facts ────────────────
    // control_flow_bce.rs § monotone scan: a `let mut` cursor whose every
    // in-loop write is `x = x ± <non-negative literal>` gets
    // `llvm.assume(x >=/<= loop-entry value)` at body entry, letting LLVM
    // fold bounds checks on conditionally-updated write heads (the
    // kata-26/88 shape — docs/investigations/bce_monotonic_assume.md).
    // Sound because AOT arithmetic traps on overflow (the update panics
    // before a wrapped value could violate the assume).

    #[test]
    fn test_ir_monotone_index_var_emits_assume() {
        let ir = ir_for(
            r#"
fn dedup(v: mut Slice[i64], n: i64) -> i64 {
    let mut k = 1;
    for i in 1..n {
        if v[i] != v[k - 1] {
            v[k] = v[i];
            k = k + 1;
        }
    }
    k
}
"#,
        );
        assert!(
            ir.contains("llvm.assume"),
            "monotone index var must emit llvm.assume, IR:\n{ir}"
        );
        assert!(
            ir.contains("k.mono.fact"),
            "assume operand must carry the k.mono.fact label, IR:\n{ir}"
        );
        assert!(
            ir.contains("k.mono.init"),
            "preheader must load the loop-entry value, IR:\n{ir}"
        );
    }

    #[test]
    fn test_ir_mixed_direction_var_emits_no_assume() {
        // k moves both directions — not monotone, scan must reject.
        let ir = ir_for(
            r#"
fn wobble(v: mut Slice[i64], n: i64) -> i64 {
    let mut k = 1;
    for i in 1..n {
        if v[i] > 0 {
            k = k + 1;
        } else {
            k = k - 1;
        }
        v[k] = v[i];
    }
    k
}
"#,
        );
        assert!(
            !ir.contains("k.mono.fact"),
            "mixed-direction var must not get an assume, IR:\n{ir}"
        );
    }

    #[test]
    fn test_ir_mut_arg_escape_emits_no_assume() {
        // k escapes through a `mut` call-site marker — the callee may
        // write it arbitrarily; scan must poison.
        let ir = ir_for(
            r#"
fn bump(x: mut ref i64) {
    *x = *x + 1;
}
fn run(v: mut Slice[i64], n: i64) -> i64 {
    let mut k = 1;
    for i in 1..n {
        v[k] = v[i];
        k = k + 1;
        bump(mut k);
    }
    k
}
"#,
        );
        assert!(
            !ir.contains("k.mono.fact"),
            "mut-marked escape must poison the var, IR:\n{ir}"
        );
    }

    #[test]
    fn test_ir_plain_reassign_emits_no_assume() {
        // `k = v[i]` is a non-monotone write — scan must poison.
        let ir = ir_for(
            r#"
fn track(v: mut Slice[i64], n: i64) -> i64 {
    let mut k = 1;
    for i in 1..n {
        v[k] = v[i];
        k = v[i];
    }
    k
}
"#,
        );
        assert!(
            !ir.contains("k.mono.fact"),
            "plain reassignment must poison the var, IR:\n{ir}"
        );
    }

    #[test]
    fn test_e2e_monotone_dedup_results_unchanged() {
        // The kata-26 shape end-to-end: assumes must not perturb results.
        let out = run_program(
            r#"
fn remove_duplicates(nums: mut Slice[i64], len: i64) -> i64 {
    if len == 0 {
        return 0;
    }
    let mut k = 1;
    for i in 1..len {
        if nums[i] != nums[k - 1] {
            nums[k] = nums[i];
            k = k + 1;
        }
    }
    k
}
fn main() {
    let mut a: Array[i64, 10] = [0, 0, 1, 1, 1, 2, 2, 3, 3, 4];
    let k = remove_duplicates(mut a, 10);
    println(k);
    for i in 0..k {
        println(a[i]);
    }
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out, "5\n0\n1\n2\n3\n4\n");
        }
    }

    #[test]
    fn test_e2e_monotone_var_overflow_traps_before_assume_misleads() {
        // Soundness pin: the monotone update that would wrap MUST trap —
        // the assume is only sound because the wrapped value never exists.
        // k is index-used (so the assume IS emitted) and driven to
        // overflow by a large literal step.
        let captured = run_program_capturing(
            r#"
fn main() {
    let mut v: Vec[i64] = Vec.filled(4, 7);
    let mut k = 0;
    let mut i = 0;
    while i < 100 {
        if k < 4 {
            println(v[k]);
        }
        k = k + 4611686018427387904;
        i = i + 1;
    }
    println(k);
}
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("integer overflow"),
                "wrapping monotone update must trap, got stdout={:?}",
                c.stdout
            );
        }
    }

    #[test]
    fn test_e2e_monotone_decreasing_cursor_results_unchanged() {
        // Kata-88 shape: decreasing write head + decreasing read cursors.
        let out = run_program(
            r#"
fn merge(nums1: mut Slice[i64], m: i64, nums2: Slice[i64], n: i64) {
    let mut i = m - 1;
    let mut j = n - 1;
    let mut k = m + n - 1;
    while j >= 0 {
        if i >= 0 and nums1[i] > nums2[j] {
            nums1[k] = nums1[i];
            i = i - 1;
        } else {
            nums1[k] = nums2[j];
            j = j - 1;
        }
        k = k - 1;
    }
}
fn main() {
    let mut a: Array[i64, 6] = [1, 2, 3, 0, 0, 0];
    let b: Array[i64, 3] = [2, 5, 6];
    merge(mut a, 3, b, 3);
    for i in 0..6 {
        println(a[i]);
    }
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out, "1\n2\n2\n3\n5\n6\n");
        }
    }

    // ── Level 2 crash diagnostics (design.md § Crash diagnostics) ──────
    // When a source filename is threaded into codegen (the CLI build/run
    // path), panics report `panic at <file>:<line>:<col> in <fn>: <msg>`.
    // The location operands are compile-time constants — no runtime DWARF
    // walk / symbolizer (which would re-add the dead-stripped ~57 KiB
    // gimli/addr2line tree). Without a filename (most `run_program` tests),
    // the bare `panic: <msg>` form is preserved — see the existing
    // `test_e2e_vec_indexed_write_oob_panics` above.

    #[test]
    fn test_e2e_panic_location_vec_oob() {
        let captured = run_program_capturing_with_filename(
            r#"
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(1);
    v[5] = 99;
    println(42);
}
"#,
            "oob_demo.kara",
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("panic at "),
                "expected rich `panic at` prefix, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                c.stdout.contains("oob_demo.kara:"),
                "expected source filename in panic location, got stdout={:?}",
                c.stdout
            );
            assert!(
                c.stdout.contains(" in main:"),
                "expected enclosing function name in panic location, got stdout={:?}",
                c.stdout
            );
            assert!(
                c.stdout.contains("vec index out of bounds"),
                "expected the panic message, got stdout={:?}",
                c.stdout
            );
            assert!(
                !c.stdout.contains("42"),
                "code after the panicking store must not run"
            );
        }
    }

    #[test]
    fn test_e2e_panic_location_has_line_col() {
        // Pin the line:col so this is a real regression guard for the span
        // plumbing, not just a format check. With the leading newline in the
        // raw string, `fn main()` is line 2 and the panicking `v[10]` read is
        // on line 4. The column points within that indexing expression.
        let captured = run_program_capturing_with_filename(
            r#"
fn main() {
    let v: Vec[i64] = Vec.new();
    let _x = v[10];
    println(7);
}
"#,
            "linecol.kara",
        );
        if let Some(c) = captured {
            // Format: `panic at linecol.kara:<line>:<col> in main: <msg>`.
            let marker = "linecol.kara:";
            let idx = c.stdout.find(marker).unwrap_or_else(|| {
                panic!(
                    "no panic location in stdout={:?} stderr={:?}",
                    c.stdout, c.stderr
                )
            });
            let rest = &c.stdout[idx + marker.len()..];
            // The two fields immediately after the filename must be numeric
            // `<line>:<col>` — proves real span data, not a `0:0` placeholder.
            let line: String = rest.chars().take_while(|ch| ch.is_ascii_digit()).collect();
            assert!(
                !line.is_empty() && line != "0",
                "expected a non-zero line number after the filename, got stdout={:?}",
                c.stdout
            );
            let after_line = &rest[line.len()..];
            assert!(
                after_line.starts_with(':'),
                "expected `:` between line and column, got stdout={:?}",
                c.stdout
            );
            let col: String = after_line[1..]
                .chars()
                .take_while(|ch| ch.is_ascii_digit())
                .collect();
            assert!(
                !col.is_empty() && col != "0",
                "expected a non-zero column number, got stdout={:?}",
                c.stdout
            );
            assert_eq!(
                line, "4",
                "panicking index is on source line 4; stdout={:?}",
                c.stdout
            );
        }
    }

    #[test]
    fn test_e2e_panic_bare_form_without_filename() {
        // Regression guard for the gate: with NO filename threaded in, the
        // original `panic: <msg>` form is preserved byte-for-byte (callers
        // that don't supply a filename — bare-IR tests, ad-hoc dumps — must
        // not see the rich form).
        let captured = run_program_capturing(
            r#"
fn main() {
    let v: Vec[i64] = Vec.new();
    let _x = v[10];
    println(7);
}
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("panic: vec index out of bounds"),
                "expected bare panic form without a filename, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                !c.stdout.contains("panic at "),
                "must NOT use the rich `panic at` form when no filename is supplied, got stdout={:?}",
                c.stdout
            );
        }
    }

    // ── Level 2 crash diagnostics — Part 2: DWARF debug-info emission ──────
    // Part 2 emits actual DWARF (DICompileUnit / DISubprogram / per-instruction
    // !dbg) via DIBuilder when enabled, for gdb/lldb symbolic backtraces.
    // `compile_to_ir_with_debug_info` forces it on race-free (no env mutation).

    #[test]
    fn test_dwarf_debug_info_present_when_enabled() {
        // With debug info forced on, the emitted IR must carry the module-level
        // debug-info scaffolding and a per-function DISubprogram. Positive proof
        // that DWARF is actually emitted — not just that codegen doesn't crash.
        let mut parsed = karac::parse(
            r#"
fn helper(x: i64) -> i64 { x + 1 }
fn main() { let y = helper(5); println(y); }
"#,
        );
        assert!(parsed.errors.is_empty(), "parse: {:?}", parsed.errors);
        let resolved = karac::resolve(&parsed.program);
        let typed = karac::typecheck(&parsed.program, &resolved);
        karac::lower(&mut parsed.program, &typed);
        let ir = karac::codegen::compile_to_ir_with_debug_info(&parsed.program, None, None)
            .expect("compile_to_ir_with_debug_info");
        assert!(
            ir.contains("DICompileUnit"),
            "expected a DICompileUnit in debug IR, got:\n{}",
            ir
        );
        assert!(
            ir.contains("DISubprogram"),
            "expected at least one DISubprogram in debug IR"
        );
        assert!(
            ir.contains("Debug Info Version"),
            "expected the `Debug Info Version` module flag in debug IR"
        );
        // Per-instruction locations: at least one `!dbg` attachment in a body.
        assert!(
            ir.contains("!dbg"),
            "expected per-instruction !dbg locations in debug IR"
        );
        // The function's DWARF display name should appear in a DISubprogram.
        assert!(
            ir.contains("name: \"helper\"") || ir.contains("\"helper\""),
            "expected the `helper` function name in DWARF metadata"
        );
    }

    #[test]
    fn test_dwarf_debug_info_absent_by_default() {
        // The default path (no force, no env) must emit NO debug metadata, so
        // release AOT binaries keep the Phase 1-3 size floor. Guards the gate.
        let mut parsed = karac::parse(r#"fn main() { println(1); }"#);
        assert!(parsed.errors.is_empty(), "parse: {:?}", parsed.errors);
        let resolved = karac::resolve(&parsed.program);
        let typed = karac::typecheck(&parsed.program, &resolved);
        karac::lower(&mut parsed.program, &typed);
        let ir = karac::codegen::compile_to_ir(&parsed.program, None, None).expect("compile_to_ir");
        assert!(
            !ir.contains("DICompileUnit") && !ir.contains("DISubprogram"),
            "default codegen must emit no DWARF debug metadata, got:\n{}",
            ir
        );
    }

    #[test]
    fn test_e2e_vec_indexed_write_after_push() {
        let out = run_program(
            r#"
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(0);
    v.push(0);
    v[0] = 7;
    v[1] = 8;
    println(v[0] + v[1]);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "15");
        }
    }

    #[test]
    fn test_e2e_vec_indexed_write_through_mut_ref_param() {
        let out = run_program(
            r#"
fn set_at(v: mut ref Vec[i64], i: i64, x: i64) {
    v[i] = x;
}
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(1);
    v.push(2);
    v.push(3);
    set_at(mut v, 1_i64, 99_i64);
    println(v[0]);
    println(v[1]);
    println(v[2]);
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["1", "99", "3"]);
        }
    }

    // ── Vec/Slice/Array indexed-receiver method dispatch (Slice Vc) ──

