    #[test]
    fn test_e2e_indexed_receiver_chained_rejected() {
        // MR5: `outer[i][j].method()` is rejected up front by codegen with
        // a clear diagnostic. Pin the diagnostic so the rejection doesn't
        // silently regress to a fall-through compile.
        let src = r#"
fn main() {
    let mut outer: Vec[Vec[Vec[i64]]] = Vec.new();
    let mut a: Vec[Vec[i64]] = Vec.new();
    let inner: Vec[i64] = Vec.new();
    a.push(inner);
    outer.push(a);
    outer[0][0].push(7);
}
"#;
        let mut parsed = karac::parse(src);
        assert!(
            parsed.errors.is_empty(),
            "parse errors: {:?}",
            parsed.errors
        );
        let resolved = karac::resolve(&parsed.program);
        let typed = karac::typecheck(&parsed.program, &resolved);
        karac::lower(&mut parsed.program, &typed);
        let err = compile_to_ir(&parsed.program, None, None)
            .expect_err("expected codegen to reject chained indexed receivers");
        assert!(
            err.contains("chained indexed receivers"),
            "expected chained-rejection diagnostic; got: {}",
            err
        );
    }

    #[test]
    fn test_ir_while_let_emits_loop_not_noop() {
        // phase-6-runtime.md line 489: `while let` lowers to a real loop
        // (header re-tests the pattern, body runs on a match). Regression
        // against the prior silent no-op (fall-through to a constant `0`,
        // loop body dropped). Archive-independent — asserts on the IR.
        let src = r#"
fn pop(v: mut ref Vec[i64]) -> Option[i64] {
    if v.len() == 0 {
        return Option.None;
    }
    let last = v.len() - 1;
    let x = v[last];
    v.remove(last);
    return Option.Some(x);
}

fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(10_i64);
    while let Some(x) = pop(mut v) {
        println(f"got {x}");
    }
}
"#;
        let ir = ir_for(src);
        assert!(
            ir.contains("whilelet.cond") && ir.contains("whilelet.body"),
            "expected while-let loop blocks in IR; got:\n{}",
            ir
        );
    }

    #[test]
    fn test_ir_discarded_vec_temp_emits_free() {
        // General owned-temp tracking, slice 1
        // (docs/spikes/general-owned-temp-tracking.md): a fresh-owned
        // Vec/String produced in statement position (`make_vec();`) is a
        // discarded temporary with no binding to drop it. The owned-temp
        // chokepoint materializes it into an `__owned_tmp` slot and queues a
        // `FreeVecBuffer` that drains at the `;`. Archive-independent — proves
        // the leak is closed at the IR level (macOS ASAN has no LeakSanitizer,
        // so the leak direction can't be caught at runtime here). Regression
        // against the prior behaviour where the buffer leaked silently.
        let src = r#"
fn make_vec() -> Vec[i64] {
    let mut v: Vec[i64] = Vec.new();
    v.push(1_i64);
    return v;
}

fn main() {
    make_vec();
}
"#;
        let ir = ir_for(src);
        assert!(
            ir.contains("__owned_tmp"),
            "expected discarded Vec temp materialized into __owned_tmp slot; got:\n{}",
            ir
        );
        assert!(
            ir.contains("cleanup.free"),
            "expected a FreeVecBuffer drain (cleanup.free block) for the discarded temp; got:\n{}",
            ir
        );
    }

    #[test]
    fn test_ir_discarded_unit_call_no_owned_temp() {
        // Negative: a discarded Call/MethodCall that does NOT yield a
        // Vec/String (here a unit-returning `println`) must not spuriously
        // allocate an `__owned_tmp` slot — `materialize_owned_temp` gates on
        // the `{ptr,len,cap}` LLVM value type, so non-heap discards are
        // untouched. Guards against the chokepoint over-reaching.
        let src = r#"
fn main() {
    println("x");
}
"#;
        let ir = ir_for(src);
        assert!(
            !ir.contains("__owned_tmp"),
            "unit-returning discard must not materialize an owned temp; got:\n{}",
            ir
        );
    }

    #[test]
    fn test_ir_discarded_map_temp_emits_free() {
        // General owned-temp tracking, slice 2
        // (docs/spikes/general-owned-temp-tracking.md): a discarded fresh Map
        // handle (`make_map();`) is a plain pointer — indistinguishable from
        // any heap pointer by LLVM type, so slice 1 leaked it. The
        // lowering-pass `owned_temp_drops` hint table carries the producing
        // expression's `Map[K, V]` TypeExpr; `materialize_owned_temp` keys it
        // by span, materializes an `__owned_tmp` slot, and queues a
        // `FreeMapHandle` → `karac_map_free` (both halves primitive). Archive-
        // independent leak-closure gate (macOS ASAN has no LeakSanitizer).
        let src = r#"
fn make_map() -> Map[i64, i64] {
    let mut m: Map[i64, i64] = Map.new();
    m.insert(1_i64, 2_i64);
    return m;
}

fn main() {
    make_map();
}
"#;
        let ir = ir_for(src);
        assert!(
            ir.contains("__owned_tmp"),
            "expected discarded Map temp materialized into __owned_tmp slot; got:\n{}",
            ir
        );
        assert!(
            ir.contains("karac_map_free"),
            "expected a FreeMapHandle drain (karac_map_free call) for the discarded Map temp; got:\n{}",
            ir
        );
    }

    #[test]
    fn test_ir_discarded_nested_vec_elem_freed() {
        // General owned-temp tracking, slice 2: a discarded `Vec[String]`
        // temp's *outer* buffer was already freed by slice 1, but its inner
        // String element buffers leaked because slice 1 passed `elem_ty:
        // None`. The hint table now supplies the element `TypeExpr`, so
        // `materialize_owned_temp` derives the element LLVM type via
        // `extract_vec_elem_type` and threads it to `track_vec_var` — the
        // `FreeVecBuffer` cleanup then emits its recursive per-element free
        // loop (`cleanup.drop.cond` block). Its presence proves the nested
        // leak is closed; a primitive-element discard (slice 1) never emits it.
        let src = r#"
fn make_vv() -> Vec[String] {
    let mut v: Vec[String] = Vec.new();
    v.push("a");
    return v;
}

fn main() {
    make_vv();
}
"#;
        let ir = ir_for(src);
        assert!(
            ir.contains("__owned_tmp"),
            "expected discarded Vec[String] temp materialized into __owned_tmp slot; got:\n{}",
            ir
        );
        assert!(
            ir.contains("cleanup.drop.cond"),
            "expected the recursive per-element free loop (elem_ty flowed from \
             owned_temp_drops, closing the nested-String leak); got:\n{}",
            ir
        );
    }

    #[test]
    fn test_ir_vec_of_vec_of_string_drop_emits_recursive_elem_drop() {
        // Slice 3n: a `Vec[Vec[String]]` (two-level heap) dropped at scope exit.
        // The inline `FreeVecBuffer` vec-struct fast path is ONE level deep — it
        // frees each inner `Vec[String]`'s data buffer but not that buffer's
        // String char-buffers, leaking the innermost Strings. The fix routes the
        // `Vec[String]` ELEMENT through `vec_elem_agg_drop_for_type_expr`'s new
        // recursive-`Vec` arm, which returns the strictly-recursive
        // `karac_drop_Vec_String` — invoked per outer element in the agg-drop
        // loop (`cleanup.adrop`), dropping every level. Its presence proves the
        // two-level leak is closed; the one-level fast path never emits a
        // per-element drop CALL (it inlines the buffer free).
        let src = r#"
fn build() -> Vec[Vec[String]] {
    let mut outer: Vec[Vec[String]] = Vec.new();
    let mut a: Vec[String] = Vec.new();
    a.push("a heap element string padded out beyond thirty-six bytes");
    outer.push(a);
    return outer;
}

fn main() {
    let vv = build();
    println(vv.len());
}
"#;
        let ir = ir_for(src);
        assert!(
            ir.contains("karac_drop_Vec_String"),
            "expected the recursive per-element drop fn karac_drop_Vec_String for the \
             Vec[Vec[String]] scope-exit drop (frees each inner Vec's Strings + buffer); \
             got:\n{}",
            ir
        );
        assert!(
            ir.contains("cleanup.adrop"),
            "expected the agg-drop loop calling the recursive per-element drop over each \
             inner Vec[String]; got:\n{}",
            ir
        );
    }

