    #[test]
    fn test_ir_discarded_block_tail_temp_freed() {
        // Slice 5 (tail-expr temp drop): a fresh `Vec` produced in the tail
        // of a statement-position block (`{ make_vec() }`) is the block's
        // return value — its frame drops only block-local lets, so the tail
        // Vec escaped uncleaned and leaked. `discarded_owned_temp_tail` now
        // peels the block to its `make_vec()` tail, and the discard arm
        // routes it through `materialize_owned_temp` (keyed on the *tail*
        // expr's span). Archive-independent (macOS ASAN has no LeakSanitizer).
        let src = r#"
fn make_vec() -> Vec[i64] {
    let mut v: Vec[i64] = Vec.new();
    v.push(1_i64);
    return v;
}

fn main() {
    { make_vec() }
    println(0);
}
"#;
        let ir = ir_for(src);
        assert!(
            ir.contains("__owned_tmp"),
            "expected the block-tail Vec temp materialized into __owned_tmp; got:\n{}",
            ir
        );
        assert!(
            ir.contains("cleanup.free"),
            "expected a FreeVecBuffer drain for the discarded block-tail temp; got:\n{}",
            ir
        );
    }

    #[test]
    fn test_ir_let_wildcard_block_tail_temp_freed() {
        // Slice 5: `let _ = { make_vec() };` discards the block's tail temp
        // through the wildcard-`let` path. The early Wildcard arm routes the
        // peeled tail (`make_vec()`) through the chokepoint. The hint table is
        // keyed on the tail call's span, so a `Vec[String]` would recover its
        // element type — here a `Vec[i64]` only needs the outer-buffer free.
        let src = r#"
fn make_vec() -> Vec[i64] {
    let mut v: Vec[i64] = Vec.new();
    v.push(1_i64);
    return v;
}

fn main() {
    let _ = { make_vec() };
    println(0);
}
"#;
        let ir = ir_for(src);
        assert!(
            ir.contains("__owned_tmp"),
            "expected the wildcard-let block-tail Vec temp materialized; got:\n{}",
            ir
        );
        assert!(
            ir.contains("cleanup.free"),
            "expected a FreeVecBuffer drain for the wildcard-let discarded temp; got:\n{}",
            ir
        );
    }

    #[test]
    fn test_ir_discarded_branching_tail_temp_not_tracked() {
        // Negative / double-free guard: slice 5 peels only *single-tail* block
        // wrappers. A branching tail (`if … { make() } else { other }`) in
        // discard position is conservatively NOT routed through the chokepoint
        // — an aliasing place-expr branch would be double-freed. Construction
        // uses no other fresh-temp discard, so the absence of `__owned_tmp`
        // proves the branching tail stayed untracked (a safe leak, deferred).
        let src = r#"
fn make_vec() -> Vec[i64] {
    let mut v: Vec[i64] = Vec.new();
    v.push(1_i64);
    return v;
}

fn main() {
    let cond = true;
    { if cond { make_vec() } else { make_vec() } }
    println(0);
}
"#;
        let ir = ir_for(src);
        assert!(
            !ir.contains("__owned_tmp"),
            "a branching discard tail must stay untracked in slice 5 \
             (single-tail wrappers only); got:\n{}",
            ir
        );
    }

    // ── pattern-arm unbound heap-field drop (B) ──
    //
    // docs/spikes/pattern-arm-unbound-field-drop.md: a fresh-temp enum
    // scrutinee (`if let Full(_, n) = make()`) has no source `EnumDrop`, so an
    // arm that leaves a heap payload field unbound leaks it. The fix
    // materializes the temp into `__freshtemp_enum_scrut` + `track_enum_var`
    // (the `__karac_drop_<E>` walk frees unbound fields); the per-arm
    // suppression zeroes the caps of fields the pattern moved into bindings.
    // These IR tests are the macOS-reliable gate (no LeakSanitizer there);
    // the ASAN suite adds the bound-field double-free gate.

    const B_ENUM_PRELUDE: &str = r#"
enum Holder { Full(Vec[i64], i64), Empty }
fn make() -> Holder {
    let mut v: Vec[i64] = Vec.new();
    v.push(1_i64);
    return Holder.Full(v, 42_i64);
}
"#;

    #[test]
    fn test_ir_iflet_freshtemp_enum_unbound_field_freed() {
        // `if let Full(_, n) = make()` — the Vec field is `_` (unbound). Before
        // the fix the payload words were extracted with no `free` (IR-proven
        // leak). Now the temp is materialized and the enum drop walk frees the
        // unbound Vec.
        let src = format!(
            "{B_ENUM_PRELUDE}\nfn main() {{ if let Holder.Full(_, n) = make() {{ println(n); }} }}\n"
        );
        let ir = ir_for_with_ownership(&src);
        assert!(
            ir.contains("__freshtemp_enum_scrut"),
            "expected the fresh-temp enum scrutinee materialized; got:\n{ir}"
        );
        assert!(
            ir.contains("@__karac_drop_Holder("),
            "expected the enum drop walk to free the unbound Vec field; got:\n{ir}"
        );
    }

    #[test]
    fn test_ir_match_freshtemp_enum_unbound_field_freed() {
        // `match make() { Full(_, n) => …, Empty => … }` — same leak, match
        // surface. Confirms the fresh-temp materialization fires in
        // compile_match (the bound-variable path already worked via the source
        // binding's EnumDrop).
        let src = format!(
            "{B_ENUM_PRELUDE}\nfn main() {{ match make() {{ Holder.Full(_, n) => println(n), Holder.Empty => println(0) }} }}\n"
        );
        let ir = ir_for_with_ownership(&src);
        assert!(
            ir.contains("__freshtemp_enum_scrut") && ir.contains("@__karac_drop_Holder("),
            "expected fresh-temp match scrutinee materialized + enum-dropped; got:\n{ir}"
        );
    }

    #[test]
    fn test_ir_iflet_freshtemp_enum_bound_field_suppressed() {
        // `if let Full(v, n) = make()` — the Vec is MOVED into `v`. The
        // materialized temp gets an EnumDrop, but the suppression must zero the
        // moved field's payload words (`match.dest.suppress.wp` ← 0) so the drop
        // walk skips it — `v`'s own cleanup frees it exactly once (no
        // double-free). (B-2026-06-13-13 generalized the suppression from
        // cap-only to all payload words, so nested-struct payloads' inner caps
        // are zeroed too; the label changed from `match.dest.cap.suppress.p`.)
        let src = format!(
            "{B_ENUM_PRELUDE}\nfn main() {{ if let Holder.Full(v, n) = make() {{ println(v.len() + n); }} }}\n"
        );
        let ir = ir_for_with_ownership(&src);
        assert!(
            ir.contains("__freshtemp_enum_scrut"),
            "expected the fresh-temp enum scrutinee materialized; got:\n{ir}"
        );
        assert!(
            ir.contains("match.dest.suppress.wp"),
            "expected the moved Vec field's payload words zeroed (suppression) to \
             avoid a double-free against the enum drop walk; got:\n{ir}"
        );
    }

    #[test]
    fn test_ir_iflet_place_scrutinee_not_materialized() {
        // Negative / double-free guard: a *place* scrutinee (a let-bound enum
        // `x`) already owns its `EnumDrop`. Materializing a second one for it
        // would double-free, so `materialize_freshtemp_enum_scrutinee` gates to
        // fresh Call/MethodCall temps only — `if let Full(_, n) = x` must NOT
        // emit a `__freshtemp_enum_scrut`.
        let src = format!(
            "{B_ENUM_PRELUDE}\nfn main() {{ let x = make(); if let Holder.Full(_, n) = x {{ println(n); }} }}\n"
        );
        let ir = ir_for_with_ownership(&src);
        assert!(
            !ir.contains("__freshtemp_enum_scrut"),
            "a place (bound-variable) scrutinee must not materialize a second \
             enum temp (would double-free against its own drop); got:\n{ir}"
        );
    }

    #[test]
    fn test_ir_letelse_freshtemp_enum_unbound_field_freed() {
        // `let Full(_, n) = make() else { return };` — let-else surface. The
        // unbound Vec is freed by the materialized temp's EnumDrop (on the
        // match edge at enclosing-scope exit; on the miss edge the divergent
        // else's cleanup walk frees it wholesale).
        let src = format!(
            "{B_ENUM_PRELUDE}\nfn main() {{\n    let Holder.Full(_, n) = make() else {{ return }}\n    println(n);\n}}\n"
        );
        let ir = ir_for_with_ownership(&src);
        assert!(
            ir.contains("__freshtemp_enum_scrut") && ir.contains("@__karac_drop_Holder("),
            "expected fresh-temp let-else scrutinee materialized + enum-dropped; got:\n{ir}"
        );
    }

    #[test]
    fn test_ir_whilelet_freshtemp_enum_unbound_field_freed() {
        // `while let Full(_, n) = next(i) { … }` — per-iteration fresh-temp enum
        // scrutinee. The materialize + `track_enum_var` register in the body's
        // per-iteration frame (not an enclosing one), so the enum drop walk
        // frees each iteration's unbound Vec before the next scrutinee eval.
        let src = r#"
enum Holder { Full(Vec[i64], i64), Empty }
fn next(i: i64) -> Holder {
    if i < 3 {
        let mut v: Vec[i64] = Vec.new();
        v.push(1_i64);
        return Holder.Full(v, i);
    }
    return Holder.Empty;
}
fn main() {
    let mut i = 0;
    while let Holder.Full(_, n) = next(i) {
        println(n);
        i = i + 1;
    }
}
"#;
        let ir = ir_for_with_ownership(src);
        assert!(
            ir.contains("__freshtemp_enum_scrut") && ir.contains("@__karac_drop_Holder("),
            "expected fresh-temp while-let scrutinee materialized + enum-dropped; got:\n{ir}"
        );
    }

    #[test]
    fn test_ir_whilelet_miss_variant_freed() {
        // B follow-up #2: the final non-matching fresh-temp enum scrutinee at
        // loop exit (here `Item.Stop(vec)` — heap-bearing, does not match
        // `Go`) is freed wholesale on the dedicated `whilelet.miss` edge. Pre-
        // fix the miss branched straight to exit and that Vec leaked.
        let src = r#"
enum Item { Go(Vec[i64]), Stop(Vec[i64]) }
fn mk() -> Vec[i64] {
    let mut v: Vec[i64] = Vec.new();
    v.push(1_i64);
    return v;
}
fn step(c: i64) -> Item {
    if c < 2 {
        return Item.Go(mk());
    }
    return Item.Stop(mk());
}
fn main() {
    let mut c: i64 = 0;
    while let Go(xs) = step(c) {
        c = c + 1;
    }
    println(c);
}
"#;
        let ir = ir_for_with_ownership(src);
        assert!(
            ir.contains("whilelet.miss"),
            "expected a dedicated whilelet.miss block; got:\n{ir}"
        );
        assert!(
            ir.contains("__whilelet_miss_scrut")
                && ir.contains("@__karac_drop_Item(ptr %__whilelet_miss_scrut"),
            "expected the final non-matching scrutinee dropped wholesale on the \
             miss edge; got:\n{ir}"
        );
    }

    #[test]
    fn test_ir_whilelet_place_scrutinee_miss_not_dropped() {
        // A *place* scrutinee (a binding, owned by its own scope) must NOT be
        // wholesale-dropped on the miss edge — that would double-free against
        // the binding's own scope-exit cleanup. The miss helper is gated to
        // fresh temps, so no `__whilelet_miss_scrut` is emitted here.
        let src = r#"
enum Item { Go(Vec[i64]), Stop(Vec[i64]) }
fn mk() -> Vec[i64] {
    let mut v: Vec[i64] = Vec.new();
    v.push(1_i64);
    return v;
}
fn main() {
    let item = Item.Stop(mk());
    while let Go(_) = item {
        break;
    }
}
"#;
        let ir = ir_for_with_ownership(src);
        assert!(
            !ir.contains("__whilelet_miss_scrut"),
            "place scrutinee must not be materialized/dropped on the miss edge; got:\n{ir}"
        );
    }

    #[test]
    fn test_ir_let_else_emits_branch_not_noop() {
        // phase-6-runtime.md line 489: `let … else` lowers to a real branch
        // (match edge binds + falls through, else edge diverges). Regression
        // against the prior silent no-op (fall-through that emitted nothing).
        let src = r#"
fn maybe(empty: bool) -> Option[i64] {
    if empty {
        return Option.None;
    }
    return Option.Some(7_i64);
}

fn main() {
    let Some(x) = maybe(false) else {
        return
    }
    println(f"bound {x}");
}
"#;
        let ir = ir_for(src);
        assert!(
            ir.contains("letelse.match") && ir.contains("letelse.else"),
            "expected let-else branch blocks in IR; got:\n{}",
            ir
        );
    }

    #[test]
    fn test_e2e_while_let_drains_and_binds() {
        // The loop body runs once per match with the correct per-iteration
        // binding, and terminates when the scrutinee stops matching (`None`).
        let src = r#"
fn pop(v: mut ref Vec[i64]) -> Option[i64] {
    if v.len() == 0 {
        return Option.None;
    }
    let last = v.len() - 1;
    let x = v[last];
    v.remove(last);
    return Option.Some(x);
}

fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(10_i64);
    v.push(20_i64);
    v.push(30_i64);
    let mut sum = 0_i64;
    while let Some(x) = pop(mut v) {
        sum = sum + x;
        println(f"got {x}");
    }
    println(f"sum={sum}");
    println("done");
}
"#;
        if let Some(out) = run_program(src) {
            assert_eq!(out.trim(), "got 30\ngot 20\ngot 10\nsum=60\ndone");
        }
    }

    #[test]
    fn test_e2e_let_else_binds_then_else_diverges() {
        // Match edge: bind the payload and continue to the following code.
        // Non-match edge: run the else block, which diverges (`return`) — the
        // bound-name path is skipped, control returns to the caller.
        let src = r#"
fn maybe(empty: bool) -> Option[i64] {
    if empty {
        return Option.None;
    }
    return Option.Some(7_i64);
}

fn run(empty: bool) {
    let Some(x) = maybe(empty) else {
        println("else fired");
        return
    }
    println(f"bound {x}");
}

fn main() {
    run(false);
    run(true);
    println("done");
}
"#;
        if let Some(out) = run_program(src) {
            assert_eq!(out.trim(), "bound 7\nelse fired\ndone");
        }
    }

    #[test]
    fn test_e2e_indexed_receiver_user_struct_method() {
        // Vec[Counter] indexed receiver dispatching through `Counter.bump`.
        // Verifies var_type_names wiring for synth identifiers and that
        // the mut-ref-self method writes back through the elem pointer.
        let out = run_program(
            r#"
struct Counter { n: i64 }
impl Counter {
    fn bump(mut ref self) { self.n = self.n + 1; }
    fn read(ref self) -> i64 { self.n }
}
fn main() {
    let mut v: Vec[Counter] = Vec.new();
    v.push(Counter { n: 10 });
    v.push(Counter { n: 20 });
    v[0].bump();
    v[0].bump();
    v[1].bump();
    println(v[0].read());
    println(v[1].read());
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["12", "21"]);
        }
    }

