    #[test]
    fn test_e2e_soa_layout_named_param_base_is_aos_mono_is_soa() {
        // Per-layout monomorphization slice 5 (origin-only `soa_layouts`): a
        // by-value `Vec[E]` param whose NAME coincides with a `layout` block
        // (`es`) no longer lowers SoA by name. The physical layout is the value
        // carrier of the ARGUMENT's binding site, not the param name:
        //   - `sumall(es)`    — `es` is the SoA local (matches `layout es`), so
        //                       the call routes to a per-layout monomorph whose
        //                       `es` param is the 4-field SoA struct.
        //   - `sumall(plain)` — `plain` is an ordinary AoS `Vec[E]`, so the call
        //                       routes to the BASE symbol, whose `es` param is
        //                       AoS `{ptr,len,cap}`.
        // Before slice 5 the name-keyed `soa_value_param_layout` lowered the
        // base `sumall`'s `es` param SoA on the name match alone, so the AoS
        // `sumall(plain)` call marshalled a 3-field AoS Vec into a 4-field SoA
        // slot — an LLVM "Call parameter type does not match function signature"
        // verification failure (the footgun this slice retires). Each path reads
        // its own grouping correctly: es → (1+2)+(3+4)=10, plain → 100+200=300.
        let out = run_program(
            r#"
struct E { x: f64, y: f64 }
layout es: Vec[E] { group g1 { x } group g2 { y } }
fn sumall(es: Vec[E]) -> f64 {
    let mut s = 0.0;
    let mut i = 0;
    while i < es.len() {
        let e = es[i];
        s = s + e.x + es[i].y;
        i = i + 1;
    }
    s
}
fn main() {
    let mut es: Vec[E] = Vec.new();
    es.push(E { x: 1.0, y: 2.0 });
    es.push(E { x: 3.0, y: 4.0 });
    let mut plain: Vec[E] = Vec.new();
    plain.push(E { x: 100.0, y: 0.0 });
    plain.push(E { x: 200.0, y: 0.0 });
    println(sumall(es));
    println(sumall(plain));
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(
                out.trim(),
                "10\n300",
                "layout-named by-value param: SoA arg routes to a SoA mono, AoS arg to the AoS base symbol"
            );
        }
    }

    #[test]
    fn test_e2e_soa_field_index_store_strided() {
        // B-2026-06-20-7: field-level SoA index-store `bodies[i].field = expr`.
        // The destination must address the field's OWN group buffer at [i], by
        // the group sub-struct stride — not stride the SoA struct as a contiguous
        // AoS element. Before the fix the store fell into the nested-plain-struct
        // path which treated SoA as AoS: index 0 coincidentally hit group-0 slot
        // 0, but index >= 1 wrote PAST the group buffer (a silent heap overflow),
        // so the store was dropped. This exercises the `e.pos += e.vel` idiom
        // (a field store whose RHS reads two OTHER groups of the same element) and
        // reads back across a third group. bodies[0].x=0+1.5=1.5, bodies[1].x=
        // 10+2.5=12.5; total = (1.5+100)+(12.5+50) = 164. A dropped index-1 store
        // (the bug) would leave bodies[1].x=10 -> 161.5.
        let out = run_program(
            r#"
struct Body { x: f64, vx: f64, health: f64 }
layout bodies: Vec[Body] { group pos { x } group vel { vx } group hp { health } }
fn main() {
    let mut bodies: Vec[Body] = Vec.new();
    bodies.push(Body { x: 0.0, vx: 1.5, health: 100.0 });
    bodies.push(Body { x: 10.0, vx: 2.5, health: 50.0 });
    let mut i = 0;
    while i < bodies.len() {
        bodies[i].x = bodies[i].x + bodies[i].vx;
        i = i + 1;
    }
    let mut total = 0.0;
    let mut j = 0;
    while j < bodies.len() {
        total = total + bodies[j].x + bodies[j].health;
        j = j + 1;
    }
    println(total);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(
                out.trim(),
                "164",
                "field-level SoA index-store must persist at every index (cross-group write + read)"
            );
        }
    }

    #[test]
    fn test_e2e_soa_whole_element_index_store() {
        // Follow-on: WHOLE-element SoA index store `grid[i] = E { … }` (the
        // scatter-by-assignment a stateful kernel writes, the sibling of the
        // field-level store above). The RHS is the full AoS element; its fields
        // must scatter into each group's OWN buffer at [i], strided by the group
        // sub-struct — NOT written as one contiguous AoS element over group-0's
        // narrower stride. Before `compile_soa_index_store` the store fell into
        // `compile_vec_index_store`, which read the SoA 4-field struct's field-0
        // (the x-group buffer) as an AoS `{ptr,len,cap}` data pointer and wrote
        // 16-byte AoS elements over the 8-byte x-group stride — a silent heap
        // overflow that scrambled every group (this program printed 3, not 36).
        // grid[i] = {i+1, i*10}: (1+0)+(2+10)+(3+20) = 36.
        let out = run_program(
            r#"
struct E { x: f64, y: f64 }
layout grid: Vec[E] { group g1 { x } group g2 { y } }
fn main() with panics {
    let mut grid: Vec[E] = Vec.new();
    grid.push(E { x: 0.0, y: 0.0 });
    grid.push(E { x: 0.0, y: 0.0 });
    grid.push(E { x: 0.0, y: 0.0 });
    let mut i = 0;
    while i < grid.len() {
        grid[i] = E { x: (i + 1) as f64, y: (i * 10) as f64 };
        i = i + 1;
    }
    let mut s = 0.0;
    let mut j = 0;
    while j < grid.len() { s = s + grid[j].x + grid[j].y; j = j + 1; }
    println(s);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(
                out.trim(),
                "36",
                "whole-element SoA index-store must scatter fields into per-group buffers at [i]"
            );
        }
    }

    #[test]
    fn test_e2e_soa_whole_element_index_store_mut_ref() {
        // Follow-on: the exact shape the spike named as the open item — a kernel
        // that scatters WHOLE elements by `mut ref Vec[E]` index assignment
        // across a function boundary. The callee's slot holds a POINTER to the
        // caller's SoA struct; `compile_soa_index_store` derefs once (via
        // `ref_params`) before GEPing each group, so the writes land in the
        // caller's buffers. Three fields across two groups (one multi-field hot
        // group) proves the per-group decomposition crosses the boundary intact.
        // ps[i] = {i+1, i+2, i+3}: (1+2+3)+(2+3+4) = 15.
        let out = run_program(
            r#"
struct P { x: f64, y: f64, m: f64 }
layout ps: Vec[P] { group pos { x, y } group mass { m } }
fn scatter(ps: mut ref Vec[P]) {
    let mut i = 0;
    while i < ps.len() {
        ps[i] = P { x: (i + 1) as f64, y: (i + 2) as f64, m: (i + 3) as f64 };
        i = i + 1;
    }
}
fn main() with panics {
    let mut ps: Vec[P] = Vec.new();
    ps.push(P { x: 0.0, y: 0.0, m: 0.0 });
    ps.push(P { x: 0.0, y: 0.0, m: 0.0 });
    scatter(mut ps);
    let mut s = 0.0;
    let mut j = 0;
    while j < ps.len() { s = s + ps[j].x + ps[j].y + ps[j].m; j = j + 1; }
    println(s);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(
                out.trim(),
                "15",
                "whole-element SoA scatter through `mut ref Vec[E]` must write the caller's groups"
            );
        }
    }

    #[test]
    fn test_e2e_soa_whole_element_index_store_cold_group() {
        // Follow-on: whole-element SoA index store into a layout WITH a cold
        // group — the scatter must also reach the trailing cold allocation (the
        // separate-malloc branch), not just the hot groups. `vy` lives in cold,
        // `x`/`y` in one hot group, `vx` in another; `entities[j] = {j,j+1,j+2,
        // j+3}` then reads back from every buffer. entities[4] -> 4,5,6,7;
        // entities[2].vy -> 5.
        let src = r#"
struct Entity { x: i64, y: i64, vx: i64, vy: i64 }
layout entities: Vec[Entity] {
    group pos { x, y }
    group vel { vx }
    cold { vy }
}
fn main() with panics {
    let mut entities: Vec[Entity] = Vec.new();
    let mut i: i64 = 0;
    while i < 5 { entities.push(Entity { x: 0, y: 0, vx: 0, vy: 0 }); i = i + 1; }
    let mut j: i64 = 0;
    while j < 5 {
        entities[j] = Entity { x: j, y: j + 1, vx: j + 2, vy: j + 3 };
        j = j + 1;
    }
    let e = entities[4];
    println(e.x); println(e.y); println(e.vx); println(e.vy);
    println(entities[2].vy);
}
"#;
        if let Some(out) = run_program(src) {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(
                lines,
                vec!["4", "5", "6", "7", "5"],
                "whole-element SoA store must scatter into the cold buffer too"
            );
        }
    }

    // ── SoA cross-function, slice 6 (Slipstream full-SoA proof) ────

    #[test]
    fn test_e2e_soa_counted_loop_fill_returned() {
        // Slice 6: a SoA `Vec[E]` filled by a COUNTED loop and returned. The
        // `presize` lowering pass rewrites `let mut grid = Vec.new()` into
        // `Vec.with_capacity(n)` when a `while i < n { grid.push(..) }` fills it
        // (the `init_grid`/`fan_collide` shape). The SoA let path only recognized
        // `Vec.new`, so the capacity-rewritten binding fell through to the AoS
        // `{ptr,len,cap}` path while its layout was the 4-field SoA struct — an
        // LLVM return-type / use-site mismatch. `is_vec_with_capacity_call` now
        // routes it to the SoA constructor. build(3): x=0,1,2 y=0,2,4 → 9.
        let out = run_program(
            r#"
struct E { x: f64, y: f64 }
layout grid: Vec[E] { group g1 { x } group g2 { y } }
fn build(n: i64) -> Vec[E] {
    let mut grid: Vec[E] = Vec.new();
    let mut i = 0;
    while i < n { grid.push(E { x: i as f64, y: (i * 2) as f64 }); i = i + 1; }
    grid
}
fn main() with panics {
    let g: Vec[E] = build(3);
    let mut s = 0.0;
    let mut i = 0;
    while i < g.len() { s = s + g[i].x + g[i].y; i = i + 1; }
    println(s);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(
                out.trim(),
                "9",
                "SoA Vec filled by a counted loop (presize -> with_capacity) must lower SoA"
            );
        }
    }

    #[test]
    fn test_e2e_soa_returned_local_name_matches_layout() {
        // Slice 6: a builder whose RETURNED local is named after a `layout` block
        // (`grid`). The base (AoS-return) symbol name-matched the local SoA in its
        // body while its signature returned the AoS `{ptr,len,cap}` — a body/sig
        // mismatch. The fix suppresses `seed_binding_site_layout`'s origin
        // name-match for a returned local (its layout is the return mono's, not
        // its name); the SoA-returning specialization is the `$ret_soa_grid` mono.
        // make(): grid[0].x + grid[1].y = 1 + 4 = 5.
        let out = run_program(
            r#"
struct E { x: f64, y: f64 }
layout grid: Vec[E] { group g1 { x } group g2 { y } }
fn make() -> Vec[E] {
    let mut grid: Vec[E] = Vec.new();
    grid.push(E { x: 1.0, y: 2.0 });
    grid.push(E { x: 3.0, y: 4.0 });
    grid
}
fn main() with panics {
    let g: Vec[E] = make();
    println(g[0].x + g[1].y);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(
                out.trim(),
                "5",
                "a returned local named like a layout block must stay base/sig-consistent"
            );
        }
    }

    #[test]
    fn test_e2e_soa_reassign_carried_buffer() {
        // Slice 6: the carried-grid double-buffer move `grid = bump(grid)` — a
        // reassignment (not a `let`) of an existing SoA binding to a
        // layout-returning call, the heart of a stateful sim's per-frame loop.
        // The let arm had `compile_soa_let_from_call`; the assignment arm did not,
        // so the call returned the AoS struct (no backward mono) and the 3-field
        // value was stored into the 4-field SoA slot → garbage group pointers →
        // SIGSEGV on the next index. `compile_soa_assign_from_call` parks the
        // return layout, frees the OLD groups (caller-retains by-value param), and
        // stores the new SoA header. Run twice (the loop shape): x0 1->3, x1 3->5
        // → 8.
        let out = run_program(
            r#"
struct E { x: f64, y: f64 }
layout grid: Vec[E] { group g1 { x } group g2 { y } }
fn bump(g: Vec[E]) -> Vec[E] {
    let mut out: Vec[E] = Vec.new();
    let mut i = 0;
    while i < g.len() { let e = g[i]; out.push(E { x: e.x + 1.0, y: e.y }); i = i + 1; }
    out
}
fn main() with panics {
    let mut grid: Vec[E] = Vec.new();
    grid.push(E { x: 1.0, y: 2.0 });
    grid.push(E { x: 3.0, y: 4.0 });
    grid = bump(grid);
    grid = bump(grid);
    println(grid[0].x + grid[1].x);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(
                out.trim(),
                "8",
                "SoA reassignment from a layout-returning call (carried-buffer double-buffer)"
            );
        }
    }

    #[test]
    fn test_e2e_soa_tail_call_soa_return() {
        // Slice 6: a SoA-returning function whose body ENDS IN a layout-returning
        // call (`substep`'s `fan_stream(coll, …)` shape). The tail-identifier
        // return is seeded by `soa_return_local_names`; the tail-CALL had no
        // path, so the callee returned AoS while the signature was SoA. The
        // tail-call propagation in `compile_tail_final_expr` flows the function's
        // return layout to the tail call. step()->bump(): r[0].x = 1 + 1 = 2.
        let out = run_program(
            r#"
struct E { x: f64, y: f64 }
layout grid: Vec[E] { group g1 { x } group g2 { y } }
fn bump(g: Vec[E]) -> Vec[E] {
    let mut out: Vec[E] = Vec.new();
    let mut i = 0;
    while i < g.len() { let e = g[i]; out.push(E { x: e.x + 1.0, y: e.y }); i = i + 1; }
    out
}
fn step(g: Vec[E]) -> Vec[E] with panics { bump(g) }
fn main() with panics {
    let mut grid: Vec[E] = Vec.new();
    grid.push(E { x: 1.0, y: 2.0 });
    let r: Vec[E] = step(grid);
    println(r[0].x);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(
                out.trim(),
                "2",
                "a SoA-returning fn whose tail is a layout-returning call must propagate the layout"
            );
        }
    }

    // ── SoA branch-leaf / multi-return (follow-on) ─────────────────

    #[test]
    fn test_e2e_soa_early_return_then_tail() {
        // Follow-on (branch-leaf / multi-`return` SoA returns): a guard-clause
        // helper — an EARLY `return a;` plus a tail `b`, the two flowing to a
        // SoA return. `soa_return_local_names` previously caught only the single
        // tail `b`, so the early `return a` lowered AoS against the SoA-patched
        // return signature → LLVM "return type does not match operand type"
        // verify failure. The recursive collector now seeds BOTH; the early
        // return's branch-safe move-out (`neutralize_moved_soa_groups_slot`)
        // keeps the fall-through free intact. pick(true) -> a -> 1 + 2 = 3.
        let out = run_program(
            r#"
struct E { x: f64, y: f64 }
layout grid: Vec[E] { group g1 { x } group g2 { y } }
fn pick(flag: bool) -> Vec[E] {
    let mut a: Vec[E] = Vec.new();
    a.push(E { x: 1.0, y: 2.0 });
    if flag {
        return a;
    }
    let mut b: Vec[E] = Vec.new();
    b.push(E { x: 3.0, y: 4.0 });
    b
}
fn main() with panics {
    let grid: Vec[E] = pick(true);
    println(grid[0].x + grid[0].y);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(
                out.trim(),
                "3",
                "an early `return` SoA local must lower SoA like the tail (multi-return)"
            );
        }
    }

    #[test]
    fn test_e2e_soa_if_else_both_return() {
        // Follow-on: BOTH arms of an if/else are explicit `return`s of distinct
        // SoA locals — neither is the block's tail expression, so both rely on
        // the recursive return collector. pick(true) -> a (1+2=3);
        // pick(false) -> b (3+4=7).
        let out = run_program(
            r#"
struct E { x: f64, y: f64 }
layout grid: Vec[E] { group g1 { x } group g2 { y } }
fn pick(flag: bool) -> Vec[E] {
    if flag {
        let mut a: Vec[E] = Vec.new();
        a.push(E { x: 1.0, y: 2.0 });
        return a;
    } else {
        let mut b: Vec[E] = Vec.new();
        b.push(E { x: 3.0, y: 4.0 });
        return b;
    }
}
fn main() with panics {
    let g1: Vec[E] = pick(true);
    let g2: Vec[E] = pick(false);
    println(g1[0].x + g1[0].y);
    println(g2[0].x + g2[0].y);
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(
                lines,
                vec!["3", "7"],
                "both explicit-`return` arms of an if/else must lower SoA"
            );
        }
    }

    #[test]
    fn test_e2e_soa_branch_leaf_bare_tails() {
        // Follow-on: branch-leaf BARE tails (`if flag { a } else { b }`, no
        // `return` keyword) — the function value is the `If`, whose then/else
        // tail leaves are the returned locals. The recursive collector reaches
        // them through the branch blocks; before, only a directly-bare body
        // `final_expr` qualified, so neither leaf seeded SoA. Same expectations
        // as the explicit-return form: pick(true) -> 3, pick(false) -> 7.
        let out = run_program(
            r#"
struct E { x: f64, y: f64 }
layout grid: Vec[E] { group g1 { x } group g2 { y } }
fn pick(flag: bool) -> Vec[E] {
    if flag {
        let mut a: Vec[E] = Vec.new();
        a.push(E { x: 1.0, y: 2.0 });
        a
    } else {
        let mut b: Vec[E] = Vec.new();
        b.push(E { x: 3.0, y: 4.0 });
        b
    }
}
fn main() with panics {
    let g1: Vec[E] = pick(true);
    let g2: Vec[E] = pick(false);
    println(g1[0].x + g1[0].y);
    println(g2[0].x + g2[0].y);
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(
                lines,
                vec!["3", "7"],
                "branch-leaf bare-tail SoA returns must lower SoA at every leaf"
            );
        }
    }

    // ── SoA heap-field (String / Vec) elements ────────────────────
    // String and Vec[POD] element fields are now supported in SoA
    // layouts. The element's heap fields live in their own group
    // buffer (scattered like every SoA field); push moves them in,
    // index/field stores drop-then-overwrite, and scope cleanup +
    // carried-grid reassignment free each live element's buffers via
    // the synthesized `__karac_soa_drop_<layout>`. These tests cover
    // functional correctness; the leak/UAF guards live in
    // `tests/memory_sanitizer.rs` (`asan_soa_string_field_*`).

    #[test]
    fn test_e2e_soa_string_field_push_read() {
        // A SoA element with a heap String field in its own group.
        // Push three elements with `f"..."` (heap, cap > 0) names plus a
        // numeric `id` in a separate group, then read both back — the
        // String header must scatter into the names group and the id into
        // the ids group, each readable independently.
        let out = run_program(
            r#"
struct Cell { id: i64, name: String }
layout cells: Vec[Cell] { group ids { id } group names { name } }
fn main() with panics {
    let mut cells: Vec[Cell] = Vec.new();
    let mut i = 0;
    while i < 3 {
        cells.push(Cell { id: i, name: f"soa-element-heap-owning-string-payload-{i}" });
        i = i + 1;
    }
    println(cells[1].name);
    println(cells[2].id);
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(
                lines,
                vec!["soa-element-heap-owning-string-payload-1", "2"],
                "SoA String field must scatter/read independently of the numeric group"
            );
        }
    }

    #[test]
    fn test_e2e_soa_string_field_whole_element_store() {
        // Whole-element overwrite `cells[i] = Cell { … }` over a String
        // field: the old element's String buffer is dropped, the new
        // element's String moved in. Read back the rewritten name.
        let out = run_program(
            r#"
struct Cell { id: i64, name: String }
layout cells: Vec[Cell] { group ids { id } group names { name } }
fn main() with panics {
    let mut cells: Vec[Cell] = Vec.new();
    cells.push(Cell { id: 0, name: f"initial-placeholder-heap-string-value-{0}" });
    cells.push(Cell { id: 1, name: f"initial-placeholder-heap-string-value-{1}" });
    let mut i = 0;
    while i < cells.len() {
        cells[i] = Cell { id: i + 10, name: f"rewritten-soa-heap-string-element-{i}" };
        i = i + 1;
    }
    println(cells[0].name);
    println(cells[1].id);
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(
                lines,
                vec!["rewritten-soa-heap-string-element-0", "11"],
                "whole-element SoA store must overwrite the String field (drop old, move new)"
            );
        }
    }

    #[test]
    fn test_e2e_soa_string_field_field_store() {
        // Field-level store `cells[i].name = f"…"` over a heap String:
        // the displaced buffer is freed and the new one stored in place,
        // leaving the other group (id) untouched.
        let out = run_program(
            r#"
struct Cell { id: i64, name: String }
layout cells: Vec[Cell] { group ids { id } group names { name } }
fn main() with panics {
    let mut cells: Vec[Cell] = Vec.new();
    cells.push(Cell { id: 7, name: f"original-soa-heap-string-payload-{0}" });
    cells[0].name = f"replacement-soa-heap-string-payload-{0}";
    println(cells[0].name);
    println(cells[0].id);
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(
                lines,
                vec!["replacement-soa-heap-string-payload-0", "7"],
                "SoA field store must replace only the named String field"
            );
        }
    }

    #[test]
    fn test_e2e_soa_vec_pod_field_compiles_and_runs() {
        // A `Vec[i64]` (Vec over a POD element) field in a SoA layout now
        // compiles (was rejected at layout validation) and runs cleanly — the
        // pushed Vec headers are stored into the `bulk` group and freed by the
        // synthesized per-element drop at scope exit. Asserts on a PRIMITIVE
        // read (`rows[i].tag`); the Vec field's *content* read-back is a
        // separate read-path concern (per-field method/index on a SoA heap
        // field needs the field's address — see the leak coverage in
        // `tests/memory_sanitizer.rs::asan_soa_vec_pod_field_no_leak`).
        let out = run_program(
            r#"
struct Row { tag: i64, data: Vec[i64] }
layout rows: Vec[Row] { group tags { tag } group bulk { data } }
fn make(n: i64) -> Vec[i64] {
    let mut v: Vec[i64] = Vec.new();
    let mut i = 0;
    while i < n { v.push(i * 2); i = i + 1; }
    v
}
fn main() with panics {
    let mut rows: Vec[Row] = Vec.new();
    rows.push(Row { tag: 1, data: make(3) });
    rows.push(Row { tag: 2, data: make(5) });
    let mut s = 0;
    let mut i = 0;
    while i < rows.len() { s = s + rows[i].tag; i = i + 1; }
    println(s);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(
                out.trim(),
                "3",
                "SoA Vec[POD] field must compile, store, and drop cleanly"
            );
        }
    }

    // ── String operators ──────────────────────────────────────────

    #[test]
    fn test_e2e_string_equality() {
        let out = run_program(
            r#"
fn main() {
    let a = "hello";
    let b = "hello";
    let c = "world";
    if a == b { println(1); } else { println(0); }
    if a == c { println(1); } else { println(0); }
    if a != c { println(1); } else { println(0); }
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["1", "0", "1"]);
        }
    }

