    #[test]
    fn test_e2e_fstring_match_arm_value() {
        // phase-12 self-hosting blocker #3: an f-string that is a match
        // arm's TAIL (value) expression, interpolating the arm's payload
        // binding, compiled to empty under AOT. The f-string accumulator is
        // an entry-block alloca registered for scope cleanup; the per-arm
        // `drain_top_frame_with_emit` freed its buffer between the value load
        // and the merge, so the match result (and any caller binding) saw an
        // empty/dangling String. Fix: when the arm tail is an f-string, zero
        // the acc's `cap` so its cleanup no-ops and the value escapes via the
        // match phi (mirrors the function-tail f-string-return handling).
        // Covers fn-return, let-bound, i64 payload, nested-into-outer, and a
        // discarded result (must not double-free). The brace-WRAPPED arm body
        // (`=> { f"…" }` / `=> { let p = f"…"; p }`) is the separate
        // block-expr-value heap-return shape, fixed and covered by
        // `test_e2e_block_expr_value_heap_return` (B-2026-06-11-2).
        let out = run_program(
            r#"
enum E { A(String), B(i64) }
fn describe(e: E) -> String {
    match e {
        E.A(name) => f"A[{name}]",
        E.B(k) => f"B[{k}]",
    }
}
fn main() {
    println(describe(E.A("x" + "y")));
    println(describe(E.B(99)));
    let e = E.A("hi");
    let s = match e {
        E.A(name) => f"<{name}>",
        E.B(_) => "none",
    };
    println(s);
    let r = describe(E.A("a" + "b"));
    println(f"outer:{r}");
    let d = E.A("z");
    match d {
        E.A(n) => f"[{n}]",
        E.B(_) => "x",
    };
    println("done");
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out, "A[xy]\nB[99]\n<hi>\nouter:A[ab]\ndone\n");
        }
    }

    #[test]
    fn test_e2e_block_expr_value_heap_return() {
        // B-2026-06-11-2: a block expression USED AS A VALUE whose tail is a
        // scope-registered heap value (an f-string accumulator or a block-local
        // `let`-bound String) lost the value under AOT — it printed empty. The
        // block's `compile_block_with_frame` loaded the tail, then drained its
        // own frame, freeing the tail's buffer between the load and the value
        // escaping (a use-after-free). Fix: suppress the tail value's cleanup
        // before the block-frame drain (mirrors `compile_function`'s tail
        // handling) so the consumer's own binding is the sole owner. Covers
        // every consumer the bug surfaced across: plain let-RHS (f-string and
        // identifier tail), `if`-arm value, a block-`let` inside a loop, a
        // brace-WRAPPED match arm (f-string and identifier tail), a nested
        // block, a function-return block, and a struct-field initializer block.
        let out = run_program(
            r#"
enum E { A(String), B }
fn mk() -> String { { f"ret{1}" } }
struct S { name: String }
fn main() {
    let a = { f"a{1}" };
    println(a);
    let b = { let p = "x" + "y"; p };
    println(b);
    let c = if true { f"yes{2}" } else { f"no{0}" };
    println(c);
    let mut i = 0i64;
    while i < 2i64 { let v = { f"v{i}" }; println(v); i = i + 1i64; }
    let e1 = E.A("m");
    let d = match e1 { E.A(n) => { f"<{n}>" }, E.B => "z" };
    println(d);
    let e2 = E.A("k");
    let g = match e2 { E.A(n) => { let p = f"[{n}]"; p }, E.B => "z" };
    println(g);
    let h = { { f"nest{3}" } };
    println(h);
    println(mk());
    let s = S { name: { f"fld{4}" } };
    println(s.name);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out, "a1\nxy\nyes2\nv0\nv1\n<m>\n[k]\nnest3\nret1\nfld4\n");
        }
    }

    #[test]
    fn test_e2e_by_value_aggregate_drops() {
        // B-2026-06-11-4: by-value aggregates leaked their heap fields across
        // several shapes the named-struct drop path didn't cover. This asserts
        // the VALUE is correct (the heap field survives to its use) across all
        // of them; the no-leak / single-free side is `tests/memory_sanitizer.rs
        // ::asan_by_value_aggregate_drops_single_free`. Shapes: a let-bound
        // tuple passed by value, a tuple-to-tuple move, a tuple returned from a
        // fn, a tuple forwarded through two params, a tuple literal arg, a
        // struct literal arg, and a nested-struct field.
        let out = run_program(
            r#"
struct S { k: i64, name: String }
struct Inner { name: String }
struct Outer { id: i64, inner: Inner }
fn show_tup(p: (i64, String)) { println(p.1); }
fn fwd(p: (i64, String)) { show_tup(p); }
fn show_s(s: S) { println(s.name); }
fn show_o(o: Outer) { println(o.inner.name); }
fn mk(n: i64) -> (i64, String) { (n, f"r-{n}") }
fn main() {
    let t = (1i64, f"let-{1}");
    show_tup(t);
    let u = (2i64, f"mv-{2}");
    let w = u;
    println(w.1);
    let r = mk(3i64);
    println(r.1);
    fwd((4i64, f"fwd-{4}"));
    show_tup((5i64, f"lit-{5}"));
    show_s(S { k: 6i64, name: f"slit-{6}" });
    let o = Outer { id: 7i64, inner: Inner { name: f"nest-{7}" } };
    show_o(o);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out, "let-1\nmv-2\nr-3\nfwd-4\nlit-5\nslit-6\nnest-7\n");
        }
    }

    #[test]
    fn test_e2e_tuple_projection() {
        // B-2026-06-11-7: a chained tuple index `t.1.1` failed to PARSE (the
        // lexer ate `1.1` as a float). B-2026-06-11-6: a struct field read
        // THROUGH a tuple element `t.1.name` compiled to the `i64 0` placeholder
        // under AOT (interp was correct) because `type_name_of_expr` couldn't
        // resolve the tuple element's struct type. Both fixed: the lexer treats
        // a `.`-preceded number as a tuple index, and a tuple binding's element
        // type names are recorded so the field access resolves. Covers nested
        // tuple index, struct-through-tuple (multi-field), and an annotated tuple.
        let out = run_program(
            r#"
struct Inner { name: String, age: i64 }
fn main() {
    let nt = (1i64, (2i64, 3i64));
    println(nt.1.0);
    println(nt.1.1);
    let t = (9i64, Inner { name: f"in-{2}", age: 7i64 });
    println(t.1.name);
    println(t.1.age);
    let a: (i64, Inner) = (5i64, Inner { name: f"ann-{4}", age: 8i64 });
    println(a.1.name);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out, "2\n3\nin-2\n7\nann-4\n");
        }
    }

