    fn test_e2e_for_in_string_bytes_multibyte_count() {
        // `é` is two UTF-8 bytes — `.bytes()` yields both (byte count, not
        // char count). Pins that the loop iterates raw bytes.
        let out = run_program(
            r#"
fn main() {
    let s = "é";
    let mut n: i64 = 0_i64;
    for _b in s.bytes() {
        n = n + 1_i64;
    }
    println(n);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "2");
        }
    }

