    #[test]
    fn test_e2e_vec_string_sort() {
        // `Vec[String].sort()` codegen: bare `sort()` over String elements now
        // lowers to the `karac_string_cmp` byte-lexicographic comparator (the
        // default-order String thunk), where it previously errored "integer
        // element types only". Ascending order, A/B with the interpreter.
        let out = run_program(
            r#"
fn main() {
    let mut v: Vec[String] = Vec.new();
    v.push("banana");
    v.push("apple");
    v.push("cherry");
    v.sort();
    for s in v {
        println(s);
    }
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["apple", "banana", "cherry"]);
        }
    }

    #[test]
    fn test_e2e_map_string_keys_sorted_report() {
        // `Map[String,i64].keys()` + `Vec.sort()` — the canonical "ordered
        // report from a hash map" idiom. Exercises BOTH fixes together: keys()
        // deep-clones each String key into the result Vec (a shallow copy
        // double-freed against the map at scope exit — it crashed before), and
        // `.sort()` orders the String Vec. Counts read back with get_or.
        let out = run_program(
            r#"
fn main() {
    let mut m: Map[String, i64] = Map.new();
    m.insert("pear".to_string(), 3_i64);
    m.insert("fig".to_string(), 1_i64);
    m.insert("kiwi".to_string(), 2_i64);
    let mut keys: Vec[String] = m.keys();
    keys.sort();
    for k in keys {
        println(f"{k} {m.get_or(k.clone(), 0_i64)}");
    }
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["fig 1", "kiwi 2", "pear 3"]);
        }
    }

    #[test]
    fn test_e2e_map_string_values_entries_owned() {
        // `Map[String,String].values()` / `entries()` deep-clone each heap half
        // into the result Vec (owned-Vec contract). Pre-fix the shallow copy
        // aliased the map's buffers and double-freed at scope exit.
        let out = run_program(
            r#"
fn main() {
    let mut m: Map[String, String] = Map.new();
    m.insert("k1".to_string(), "alpha".to_string());
    let vs: Vec[String] = m.values();
    println(vs.len());
    for v in vs { println(v); }
    for pair in m.entries() {
        let (a, b) = pair;
        println(f"{a}={b}");
    }
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["1", "alpha", "k1=alpha"]);
        }
    }

    #[test]
    fn test_e2e_map_get_remove_with_vec_value_payload() {
        // Bisected from the LeetCode 3629 codegen-vs-interpreter divergence.
        // Pins `Map.get` and `Map.remove` returning `Option[Vec[i64]]`:
        // the `Some(v) => v.len()` arm must reconstruct the full Vec
        // (3 LLVM words: ptr, len, cap) from the Option's payload fields.
        // Before the per-payload-word fix, `coerce_to_i64` truncated the
        // Vec to a single word and the destructure read undef for fields
        // 2 and 3 — producing garbage `len()` reads and reordered output.
        // After the fix, both paths round-trip the full payload.
        let out = run_program(
            r#"
fn main() {
    let mut bucket: Map[i64, Vec[i64]] = Map.new();
    bucket.entry(2_i64).or_insert(Vec.new()).push(10_i64);
    bucket.entry(2_i64).or_insert(Vec.new()).push(20_i64);
    bucket.entry(2_i64).or_insert(Vec.new()).push(30_i64);
    bucket.entry(3_i64).or_insert(Vec.new()).push(99_i64);

    match bucket.get(2_i64) {
        Some(v) => { println(v.len()); },
        None    => { println(-1_i64); },
    }
    match bucket.get(3_i64) {
        Some(v) => { println(v.len()); },
        None    => { println(-1_i64); },
    }

    match bucket.remove(2_i64) {
        Some(indices) => {
            for j in indices.into_iter() {
                println(j);
            }
        },
        None => { println(-1_i64); },
    }

    println(bucket.len());

    match bucket.remove(2_i64) {
        Some(_) => { println(99_i64); },
        None    => { println(0_i64); },
    }
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["3", "1", "10", "20", "30", "1", "0"]);
        }
    }

    // ── Clone trait surface (canonical: phase-8-stdlib-floor.md
    //    "Clone trait surface for collections") ───────────────────────────

    #[test]
    fn test_e2e_vec_clone_preserves_contents() {
        // Cloned Vec contains the same elements as the source.
        let out = run_program(
            r#"
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(10_i64);
    v.push(20_i64);
    v.push(30_i64);
    let w: Vec[i64] = v.clone();
    println(w[0]);
    println(w[1]);
    println(w[2]);
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["10", "20", "30"]);
        }
    }

    #[test]
    fn test_e2e_vec_clone_independent_buffers() {
        // Mutating the source Vec after cloning leaves the clone unchanged
        // — independent buffers from a fresh malloc.
        let out = run_program(
            r#"
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(1_i64);
    v.push(2_i64);
    let w: Vec[i64] = v.clone();
    v.push(99_i64);
    println(v.len());
    println(w.len());
    println(w[0]);
    println(w[1]);
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["3", "2", "1", "2"]);
        }
    }

    #[test]
    fn test_e2e_vec_clone_empty_fast_path() {
        // `v.clone()` on an empty Vec hits the empty-fast path: dst gets
        // {null, 0, 0} without any allocation. Verifies the cloned Vec is
        // still observably empty and supports push afterwards.
        let out = run_program(
            r#"
fn main() {
    let v: Vec[i64] = Vec.new();
    let w: Vec[i64] = v.clone();
    println(w.len());
    w.push(7_i64);
    println(w.len());
    println(w[0]);
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["0", "1", "7"]);
        }
    }

    #[test]
    fn test_e2e_vec_clone_borrowed_receiver_is_deep() {
        // Regression for B-2026-06-18-9: `path.clone()` where `path` is a
        // BORROWED receiver (`ref` / `mut ref` parameter) mis-built — the clone
        // fn was handed the alloca's raw pointer (a `**Vec` for a ref param), so
        // it copied the {data,len,cap} from the pointer's own bits, producing an
        // alias that shared the source buffer. A later mutation of the source
        // then drained the "snapshot". The interpreter always deep-copied, so it
        // was a run/build divergence. `get_data_ptr` now unwraps the ref level.
        //
        // Two receiver modes, both through a function-parameter borrow, both
        // followed by draining the source AFTER the snapshot:
        //   - `mut ref`: snapshot via a recursive backtracking shape (the kata
        //     #39 form — push, recurse, snapshot at the leaf, pop on unwind).
        //   - `ref`: snapshot a borrowed Vec, return it, then drain the source.
        let out = run_program(
            r#"
fn snap_mut(path: mut ref Vec[i64], out: mut ref Vec[Vec[i64]]) {
    out.push(path.clone());
}
fn snap_ref(path: ref Vec[i64]) -> Vec[i64] {
    path.clone()
}
fn rec(depth: i64, path: mut ref Vec[i64], out: mut ref Vec[Vec[i64]]) {
    if depth == 0i64 {
        snap_mut(path, out);
        return;
    }
    path.push(depth);
    rec(depth - 1i64, path, out);
    path.pop();
}
fn main() {
    // mut ref through recursion: snapshot [3,2,1] taken at the leaf must
    // survive the pops on the way back up.
    let mut out: Vec[Vec[i64]] = Vec.new();
    let mut path: Vec[i64] = Vec.new();
    rec(3i64, mut path, mut out);
    let row = out[0];
    println(row.len());
    println(row[0]);
    println(row[1]);
    println(row[2]);

    // ref borrow: snapshot must be independent of a later drain.
    let mut src: Vec[i64] = Vec.new();
    src.push(7_i64);
    src.push(8_i64);
    let kept = snap_ref(src);
    src.pop();
    src.pop();
    println(kept.len());
    println(kept[0]);
    println(kept[1]);
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["3", "3", "2", "1", "2", "7", "8"]);
        }
    }

