    // ── defer / errdefer codegen ─────────────────────────────────
    //
    // Slice 1 (Phase 7 § *defer / errdefer codegen*) pins user `defer`
    // on normal scope exit only: the deferred block compiles via
    // `compile_block` from the `UserDefer(Block)` cleanup variant when
    // `emit_scope_cleanup` drains the function's top frame at return.
    // LIFO order is mandatory per design.md § *Drop ordering within a
    // branch* — "last declared, first drained". Error-exit, panic, and
    // `?`-propagation paths are slice 2's scope; block-scoped dispatch
    // and runtime-reachability of defers inside not-taken branches are
    // tracked as a follow-on entry in phase-7-codegen.md.

    #[test]
    fn test_e2e_defer_fires_on_normal_scope_exit() {
        let out = run_program(
            r#"
fn main() {
    defer { println("deferred"); }
    println("inline");
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["inline", "deferred"]);
        }
    }

    #[test]
    fn test_e2e_defer_lifo_order_within_function() {
        let out = run_program(
            r#"
fn main() {
    defer { println("a"); }
    defer { println("b"); }
    println("body");
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["body", "b", "a"]);
        }
    }

    #[test]
    fn test_e2e_defer_fires_on_explicit_early_return() {
        // `return` from the function body calls `emit_scope_cleanup`
        // before `build_return`, which walks every live cleanup frame
        // LIFO — including registered user defers. Pins that the early-
        // return path drains the same cleanup stack as the normal-exit
        // path. (Block-scope dispatch and runtime-reachability — defer
        // inside a not-taken branch must NOT fire — are tracked
        // separately in phase-7-codegen.md as a follow-on; this slice
        // covers function-scoped, compile-time-registered defer.)
        let out = run_program(
            r#"
fn body() {
    defer { println("d"); }
    println("a");
    return;
    println("unreached");
}

fn main() { body(); }
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["a", "d"]);
        }
    }

    #[test]
    fn test_e2e_defer_with_three_actions_lifo() {
        let out = run_program(
            r#"
fn main() {
    defer { println("1"); }
    defer { println("2"); }
    defer { println("3"); }
    println("0");
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["0", "3", "2", "1"]);
        }
    }

    // --- Phase 7 § *defer codegen* slice 1.5: block-scope + runtime-reachability ---
    //
    // Slice 1 ships function-scoped, compile-time-registered defer:
    // every `defer` lands on the function's top cleanup frame and
    // fires at function exit, regardless of which enclosing block
    // declared it or whether that block's runtime branch was taken.
    // Slice 1.5 narrows the drain scope by pushing a fresh
    // `scope_cleanup_actions` frame inside the "naked block" path
    // (if-arms, bare `{ ... }` / `Seq` / `unsafe` expression-blocks,
    // nested defer bodies) and draining it at block exit via
    // `compile_block_with_frame`. Because the drain IR lives at the
    // end of the *emitted* block body, a not-taken conditional arm
    // bypasses the drain instruction entirely — runtime-reachability
    // falls out of block-scoping for free. These four tests pin the
    // four observable shapes that distinguish slice 1.5 from slice 1.

    #[test]
    fn test_e2e_defer_in_if_true_fires_at_end_of_arm() {
        // The defer is declared inside the if's then-block. Slice 1.5
        // requires it to fire when control falls off the end of that
        // block (before the merge BB), not at function exit. Expected
        // stream: `before-if` → `in-if` → `after-defer` → defer body
        // (`a`) → `after-if`.
        let out = run_program(
            r#"
fn main() {
    println("before-if");
    if true {
        println("in-if");
        defer { println("a"); }
        println("after-defer");
    }
    println("after-if");
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(
                lines,
                vec!["before-if", "in-if", "after-defer", "a", "after-if"]
            );
        }
    }

    #[test]
    fn test_e2e_defer_in_if_false_does_not_fire() {
        // Runtime-reachability: the defer's drain IR is emitted
        // inside the then-arm's BB. Because the conditional jump
        // skips that BB at runtime (`if false`), the drain
        // instruction is never executed, so the defer body never
        // runs. This is the v1 correctness gap vs the interpreter
        // that slice 1.5 closes (interpreter's
        // `test_defer_registers_when_reached_not_at_block_start`).
        let out = run_program(
            r#"
fn main() {
    println("before");
    if false {
        defer { println("not-printed"); }
    }
    println("after");
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["before", "after"]);
        }
    }

    #[test]
    fn test_e2e_defer_in_while_body_fires_per_iteration() {
        // While bodies already push a per-iteration cleanup frame
        // (`compile_while` in `src/codegen/control_flow.rs:499`)
        // so defer landed on it correctly in slice 1; this test
        // pins that semantic in a lock-in form alongside the new
        // if-arm tests above so a regression to function-scoped
        // defer (which would print all three `d`s after `after`)
        // is caught here.
        let out = run_program(
            r#"
fn main() {
    let mut i = 0;
    while i < 3 {
        defer { println("d"); }
        i = i + 1;
    }
    println("after");
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["d", "d", "d", "after"]);
        }
    }

    // --- Phase 7 § *defer / errdefer codegen* slice 2: errdefer on error paths ---
    //
    // Slice 2 wires `UserErrDefer { binding: Option<String>, body: Block }`
    // onto the same `scope_cleanup_actions` stack `UserDefer` lives on, then
    // splits the drain into two phases routed by exit path:
    //   - `emit_scope_cleanup` (normal exit) filters out `UserErrDefer` so an
    //     `errdefer { ... }` declared in a normally-exiting function never
    //     fires.
    //   - `emit_scope_cleanup_for_error_path` (error exit) drains errdefers
    //     LIFO in phase 1, then drops + defers LIFO in phase 2, innermost
    //     frame first. Mirrors the interpreter's per-scope `run_cleanup`
    //     shape (`src/interpreter/eval_stmt.rs:364-408`).
    //
    // Error-exit sites today: the `?` operator's Err-propagation branch
    // (`compile_question`'s `fail_bb`), early `return Err(...)` / `return
    // None` (the `ExprKind::Return` arm in `compile_expr`), and tail-position
    // `Err(...)` / `None` (`compile_function`'s tail emitter). Detection is
    // purely syntactic via `Codegen::is_error_exit_value`.
    //
    // Out of scope for slice 2 (deferred):
    //   - Binding form `errdefer(e) { ... }` — pushed in slice 4; the
    //     compile_stmt push gates on `binding.is_none()` so for now the
    //     binding form falls through to the catch-all `_ => Ok(())` arm
    //     and stays a no-op at codegen, mirroring slice 1's deferral of
    //     block-scoped defer to slice 1.5.
    //   - Panic landing pads — the panic-unwind story is not in this
    //     compiler today (panic=abort-style), so there are no landing pads
    //     to wire. Phase 7 § *defer/errdefer codegen* slice 2 design called
    //     this out for coordination if the panic story landed first.

    #[test]
    fn test_e2e_errdefer_fires_on_explicit_return_err() {
        // Param-less errdefer fires when control exits via
        // `return Err(...)`. Mirrors interpreter
        // `test_errdefer_fires_on_err_return`.
        let out = run_program(
            r#"
fn body() -> Result[i64, i64] {
    defer { println("d"); }
    errdefer { println("e"); }
    return Err(7_i64);
}
fn main() {
    match body() {
        Ok(_) => println("ok"),
        Err(_) => println("caller-err"),
    }
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            // Phase 1 (errdefer) then phase 2 (defer), then caller's
            // match arm. errdefer prints "e" before defer's "d".
            assert_eq!(lines, vec!["e", "d", "caller-err"]);
        }
    }

    #[test]
    fn test_e2e_errdefer_skipped_on_normal_return() {
        // errdefer must NOT fire on a normal `return Ok(...)`; defer
        // always fires. Mirrors interpreter
        // `test_errdefer_skipped_on_normal_return`.
        let out = run_program(
            r#"
fn body() -> Result[i64, i64] {
    defer { println("d"); }
    errdefer { println("e"); }
    return Ok(1_i64);
}
fn main() {
    match body() {
        Ok(_) => println("caller-ok"),
        Err(_) => println("caller-err"),
    }
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["d", "caller-ok"]);
        }
    }

    #[test]
    fn test_e2e_errdefer_fires_on_question_propagation() {
        // The `?` operator's Err-propagation branch is the canonical
        // error-exit path. An `errdefer { ... }` registered upstream
        // of the `?` site fires in the `fail_bb` before the early
        // `ret` — `emit_scope_cleanup_for_error_path` drains in phase
        // order. Compares against the existing
        // `test_e2e_question_triggers_scope_cleanup` test, which only
        // pins that compiler-internal cleanup runs at the `?` site.
        let out = run_program(
            r#"
fn boom() -> Result[i64, i64] { Err(7_i64) }
fn caller() -> Result[i64, i64] {
    errdefer { println("err-cleanup"); }
    let _ = boom()?;
    Ok(0_i64)
}
fn main() {
    match caller() {
        Ok(_) => println("ok"),
        Err(_) => println("caller-err"),
    }
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["err-cleanup", "caller-err"]);
        }
    }

    #[test]
    fn test_e2e_errdefer_phase1_before_defer_lifo() {
        // Phase ordering pin: on an error path the LIFO drain runs
        // (errdefer e2, errdefer e1) in phase 1, then (defer d2, defer
        // d1) in phase 2 — full output `e2 e1 d2 d1`. Mirrors the
        // interpreter's `test_errdefer_runs_before_defer_on_error_path`
        // shape.
        let out = run_program(
            r#"
fn body() -> Result[i64, i64] {
    defer { println("d1"); }
    errdefer { println("e1"); }
    defer { println("d2"); }
    errdefer { println("e2"); }
    return Err(0_i64);
}
fn main() {
    match body() {
        Ok(_) => println("ok"),
        Err(_) => println("caller-err"),
    }
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["e2", "e1", "d2", "d1", "caller-err"]);
        }
    }

    #[test]
    fn test_e2e_errdefer_fires_on_tail_err_expression() {
        // Function-tail error-exit: when the function's final
        // expression is syntactically `Err(...)` (no leading `return`),
        // `compile_function`'s tail emitter routes through
        // `emit_scope_cleanup_for_error_path` and the errdefer fires.
        // Distinguishes the tail-expression path from the explicit
        // `return` path covered above — both flow through the same
        // `is_error_exit_value` detector but different emitters.
        let out = run_program(
            r#"
fn body() -> Result[i64, i64] {
    errdefer { println("tail-err-cleanup"); }
    Err(42_i64)
}
fn main() {
    match body() {
        Ok(_) => println("ok"),
        Err(_) => println("caller-err"),
    }
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["tail-err-cleanup", "caller-err"]);
        }
    }

    // --- Phase 7 § *defer / errdefer codegen* slice 3: LIFO interleave ---
    //
    // Slice 3 audits and pins that user `defer { ... }` and the compiler-
    // internal cleanup actions (`FreeVecBuffer`, `RcDec`, `FreeMapHandle`,
    // `EnumDrop`, `StructDrop`, `RcDecOption`) share a single per-scope
    // stack (`scope_cleanup_actions.last_mut()`) and drain in reverse
    // push order (LIFO) per `emit_scope_cleanup` (`src/codegen/runtime.rs`).
    // The structural invariant was established by slice 1 (`UserDefer`
    // pushes onto the same frame `track_vec_var` / `track_rc_var` /
    // `track_map_handle` push onto) — slice 3's contribution is the
    // verification + the regression-pin tests below.
    //
    // Design.md § *Drop ordering within a branch* mandates program-order
    // LIFO interleave: `let v = Vec.new(); defer foo();` drains `foo()`
    // first, then `drop(v)`. Both observable behaviours are pinned:
    //   - E2E (`test_e2e_defer_lifo_with_let_vec_interleave`,
    //     `test_e2e_defer_lifo_with_two_let_vecs_interleave`) — defer
    //     bodies read the let-bound Vec's `.len()` at scope exit and the
    //     output proves the Vec was still alive when the defer fired
    //     (had the order been "all drops then defers", the read would
    //     touch freed memory).
    //   - IR (`test_ir_defer_drop_interleave_emission_order`) — pins the
    //     emission order of `mark_b()` / `@free` / `mark_a()` / `@free`
    //     within `compile_function`'s tail-cleanup block to distinguish
    //     the unified-stack-LIFO behaviour from the "all defers then all
    //     drops" two-phase alternative (which would emit both `mark_*`
    //     calls before any `@free`).

    #[test]
    fn test_e2e_defer_lifo_with_let_vec_interleave() {
        // Single let + single defer: push order is `[FreeVec(v),
        // UserDefer(println)]`; LIFO drain fires the defer first (sees
        // live `v.len() == 3`), then the `FreeVec(v)` cleanup releases
        // the buffer. Under the alternative two-phase ordering
        // "all drops then all defers", the defer would read a freed
        // data pointer and either print garbage or crash; observing
        // `"len=3"` pins the unified-stack interleave.
        let out = run_program(
            r#"
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(10_i64);
    v.push(20_i64);
    v.push(30_i64);
    defer { println(f"len={v.len()}"); }
    println("body");
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["body", "len=3"]);
        }
    }

    #[test]
    fn test_e2e_defer_lifo_with_two_let_vecs_interleave() {
        // Mirrors design.md's canonical example:
        //     let v = Vec.new(); defer A; let w = Vec.new(); defer B;
        // → push order `[FreeVec(v), Defer A, FreeVec(w), Defer B]`,
        //   LIFO drain `[Defer B, FreeVec(w), Defer A, FreeVec(v)]`.
        //
        // Each defer's body prints its respective Vec's `.len()`.
        // The interleaved LIFO drain order guarantees both reads land
        // BEFORE the matching `FreeVec` for that Vec: defer B reads w
        // before FreeVec(w); defer A reads v before FreeVec(v). The
        // stdout order is `wlen=2` then `vlen=1` because B drains
        // before A (LIFO between the two defers, both alive on the
        // same unified stack). Distinguishes from "all drops then all
        // defers" by the live read; the LIFO-vs-FIFO defer order pin
        // is additional.
        let out = run_program(
            r#"
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(1_i64);
    defer { println(f"vlen={v.len()}"); }
    let mut w: Vec[i64] = Vec.new();
    w.push(10_i64);
    w.push(20_i64);
    defer { println(f"wlen={w.len()}"); }
    println("body");
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["body", "wlen=2", "vlen=1"]);
        }
    }

    #[test]
    fn test_ir_defer_drop_interleave_emission_order() {
        // Slice 3's structural pin. The two prior E2E tests rule out
        // "all drops then all defers" (defers read live Vec buffers),
        // but they do NOT distinguish the unified-stack LIFO interleave
        // from the alternative two-phase ordering "all defers then all
        // drops" — both orderings let a defer see its in-scope let-
        // binding alive. This IR test closes the gap by pinning the
        // emission order of defer bodies vs. `@free` calls in
        // `compile_function`'s tail-cleanup block.
        //
        // Source:
        //     let v = Vec.new(); v.push(...); defer { mark_a(); }
        //     let w = Vec.new(); w.push(...); defer { mark_b(); }
        //
        // Push order at the function's top frame:
        //     [FreeVec(v), UserDefer(mark_a), FreeVec(w), UserDefer(mark_b)]
        //
        // Drain order (LIFO) emits IR in this sequence inside main's
        // exit-cleanup block:
        //     1. UserDefer(mark_b) → `call .* @mark_b`
        //     2. FreeVec(w)        → `call .* @free` on w's data ptr
        //     3. UserDefer(mark_a) → `call .* @mark_a`
        //     4. FreeVec(v)        → `call .* @free` on v's data ptr
        //
        // Counterfactual ordering "all defers then all drops" would
        // emit `[@mark_b, @mark_a, @free, @free]`. Observing `@mark_a`
        // appearing AFTER an `@free` (and before the second `@free`)
        // distinguishes the actual unified-LIFO behaviour from that
        // alternative.
        let full_ir = ir_for(
            r#"
fn mark_a() { println("a"); }
fn mark_b() { println("b"); }
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(1_i64);
    defer { mark_a(); }
    let mut w: Vec[i64] = Vec.new();
    w.push(2_i64);
    defer { mark_b(); }
}
"#,
        );
        // Scope to `@main`'s body so positions are not confused by
        // `@free` calls inside `Vec.push`'s realloc path (which run
        // BEFORE the cleanup block in IR text order, but live in a
        // different function).
        let main_start = full_ir
            .find("define i32 @main")
            .unwrap_or_else(|| panic!("expected `define i32 @main` in IR; got:\n{full_ir}"));
        // `@main` ends at the first `\n}\n` after its opening — every
        // other top-level fn starts on a new line after that.
        let main_body_end_rel = full_ir[main_start..]
            .find("\n}\n")
            .unwrap_or_else(|| panic!("expected `@main` body terminator in IR; got:\n{full_ir}"));
        let ir = &full_ir[main_start..main_start + main_body_end_rel];

        let pos_b = ir
            .find("call void @mark_b")
            .unwrap_or_else(|| panic!("expected `call void @mark_b` in main; got:\n{ir}"));
        let pos_a = ir
            .find("call void @mark_a")
            .unwrap_or_else(|| panic!("expected `call void @mark_a` in main; got:\n{ir}"));
        // The cleanup-time `@free` calls take their data pointer from
        // `%cleanup.data*` slots (per `emit_cleanup_action`'s
        // `FreeVecBuffer` arm in `src/codegen/runtime.rs`). Earlier
        // `@free` calls in main's body come from `Vec.push`'s realloc
        // path (`call void @free(ptr %data4)`) and are NOT what we want
        // to compare against — scope to the `%cleanup.data` form.
        let cleanup_free_pat = "call void @free(ptr %cleanup.data";
        let pos_free1 = ir.find(cleanup_free_pat).unwrap_or_else(|| {
            panic!("expected first cleanup-time `@free` (matching `{cleanup_free_pat}`) in main; got:\n{ir}")
        });
        let pos_free2 = {
            let start = pos_free1 + 1;
            let rest = &ir[start..];
            rest.find(cleanup_free_pat)
                .map(|p| start + p)
                .unwrap_or_else(|| {
                    panic!("expected a second cleanup-time `@free` in main; got:\n{ir}")
                })
        };
        // Drain order: mark_b → free(w) → mark_a → free(v). The
        // critical assertion is that mark_a sits BETWEEN the two
        // free calls — that's what rules out "all defers then all
        // drops" (which would put both `mark_*` before either free).
        assert!(
            pos_b < pos_free1,
            "defer B (`mark_b`) should drain before the first cleanup `@free`; got mark_b at {pos_b}, free at {pos_free1}\nmain IR:\n{ir}",
        );
        assert!(
            pos_free1 < pos_a,
            "first cleanup `@free` (FreeVec(w)) should drain before defer A (`mark_a`); got free at {pos_free1}, mark_a at {pos_a}\nmain IR:\n{ir}",
        );
        assert!(
            pos_a < pos_free2,
            "defer A (`mark_a`) should drain before the second cleanup `@free` (FreeVec(v)); got mark_a at {pos_a}, free at {pos_free2}\nmain IR:\n{ir}",
        );
    }

    // --- Phase 7 § *defer / errdefer codegen* slice 4: errdefer(e) binding form ---
    //
    // Slice 4 lifts the `binding.is_none()` gate in `compile_stmt`'s
    // ErrDefer arm so `errdefer(e) { ... }` also lands on the unified
    // `scope_cleanup_actions` frame. The binding-form dispatch in
    // `emit_cleanup_action_at`'s UserErrDefer branch reads
    // `pending_errdefer_payload` (staged by each error-exit site
    // immediately before `emit_scope_cleanup_for_error_path`),
    // allocates an entry-block alloca of the payload's LLVM type,
    // stores the staged value, and registers the binding in
    // `self.variables` for the duration of the body's
    // `compile_block_with_frame` call. After the body emits, the prior
    // `variables[name]` (if any) is restored; otherwise the slot is
    // removed.
    //
    // Three staging sites stage `pending_errdefer_payload`:
    //   1. `compile_question`'s `fail_bb` — stages `w0` (the i64-wide
    //      payload word extracted from the result struct's field 1).
    //   2. `ExprKind::Return(Err(arg))` in `compile_expr` — re-compiles
    //      `arg` to get the source-level value (rather than peeling
    //      fields off the constructed Err struct).
    //   3. Function-tail `Err(arg)` in `compile_function` — same shape
    //      as the explicit-return site.
    //
    // Out of scope for slice 4 (deferred):
    //   - Wider E payloads (`Result[T, String]`, `Result[T, struct]`):
    //     today the `?` site extracts only `w0` (one i64), so the
    //     binding form sees a coerced i64 word rather than the
    //     reconstructed source-level value when E is multi-word. The
    //     explicit-return and tail-Err paths re-compile the inner Err
    //     arg directly, so they work for any payload type; the `?`
    //     path is the residual gap.
    //   - Double-evaluation of side-effecting payload expressions in
    //     the explicit-return and tail-Err sites: `return Err(expensive())`
    //     calls `expensive()` once for the return-struct construction
    //     and again to stage the binding-form payload. Acceptable for
    //     v1's narrow common case (typed `i64` / identifier payloads)
    //     but pinned as a known limitation.

    #[test]
    fn test_e2e_errdefer_with_binding_on_explicit_return_err() {
        // Mirrors interpreter `test_errdefer_with_binding_sees_err_payload`
        // (`tests/interpreter.rs:1288`). The `errdefer(e) { println(e); }`
        // body binds `e` to the about-to-be-returned Err payload from
        // `return Err(7_i64)`. Without slice 4, the binding form was
        // gated out at `compile_stmt`; with slice 4 wired, the binding
        // is registered into `self.variables` during the body's
        // emission and the print resolves to the staged payload.
        let out = run_program(
            r#"
fn body() -> Result[i64, i64] {
    errdefer(e) { println(e); }
    return Err(7_i64);
}
fn main() {
    match body() {
        Ok(_) => println(0_i64),
        Err(_) => println(1_i64),
    }
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            // errdefer(e) prints the bound 7, then the caller's
            // Err arm prints 1.
            assert_eq!(lines, vec!["7", "1"]);
        }
    }

    #[test]
    fn test_e2e_errdefer_with_binding_on_question_propagation() {
        // Pin the `?` site's payload staging: when `boom()?`
        // propagates an Err, the `errdefer(e) { ... }` in the caller's
        // scope binds `e` to the i64 payload word (`w0`) extracted
        // from the propagated result struct. Distinguishes the `?`-
        // failure path from the explicit-return path covered above —
        // they share the same `emit_scope_cleanup_for_error_path`
        // drain but stage the payload from different sources
        // (`compile_question`'s `w0` vs `compile_expr`'s recompiled
        // Err arg).
        let out = run_program(
            r#"
fn boom() -> Result[i64, i64] { Err(99_i64) }
fn caller() -> Result[i64, i64] {
    errdefer(e) { println(e); }
    let _ = boom()?;
    Ok(0_i64)
}
fn main() {
    match caller() {
        Ok(_) => println(0_i64),
        Err(_) => println(2_i64),
    }
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            // errdefer(e) prints the bound 99 (the propagated payload),
            // then the caller's Err arm prints 2.
            assert_eq!(lines, vec!["99", "2"]);
        }
    }

    #[test]
    fn test_e2e_errdefer_with_binding_no_double_eval_on_impure_err_arg() {
        // Slice 4 follow-up (b) — double-eval fix (2026-05-26).
        // Slice 4 staged the Err binding-form payload by unconditionally
        // re-compiling `payload_expr`, which evaluated side-effecting Err
        // args twice (`return Err(some_io());` → `some_io()` ran for the
        // return-struct construction AND again to stage the payload).
        //
        // This test pins single-evaluation via `Self::is_pure_recompilable`:
        // `make_err()` is an impure call (writes "called" to stdout),
        // so it routes through the extract-from-v path — the constructed
        // Err struct's field 1 (`w0`) is the i64-coerced payload. With
        // the fix, "called" appears exactly once in output; pre-fix it
        // would have appeared twice.
        //
        // The binding-form errdefer reads the staged i64 payload (`7`
        // here) and prints it.
        let out = run_program(
            r#"
fn make_err() -> i64 {
    println("called");
    7_i64
}
fn body() -> Result[i64, i64] {
    errdefer(e) { println(e); }
    return Err(make_err());
}
fn main() {
    match body() {
        Ok(_) => println("ok"),
        Err(_) => println("caller-err"),
    }
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            // Expected sequence:
            //   "called" — make_err() runs exactly ONCE for the Err
            //              return struct's construction (single eval).
            //   "7"      — errdefer(e) prints the staged i64 payload
            //              (extracted from the constructed struct's
            //              field 1).
            //   "caller-err" — the caller's Err arm.
            assert_eq!(lines, vec!["called", "7", "caller-err"]);
            // Stronger assertion against regression: count "called"
            // occurrences. Pre-fix it would have been 2 (double-eval).
            let called_count = out.matches("called").count();
            assert_eq!(
                called_count, 1,
                "impure Err arg should evaluate exactly once; got {called_count} `called` lines:\n{out}",
            );
        }
    }

    #[test]
    fn test_e2e_errdefer_with_binding_sees_wider_e_at_question_propagation() {
        // Slice 4 follow-up (a) — wider-E payload reconstruction at the
        // `?` site (2026-05-26). Pre-(a), `compile_question`'s `fail_bb`
        // staged bare `w0` (the i64-coerced first payload word) for the
        // binding-form errdefer's payload — so a `Result[T, String]`
        // caller's `errdefer(e) { println(e); }` at a `boom()?` site
        // saw `e` as the i64 reinterpretation of String's `data` ptr
        // (garbage from the binding's perspective; would crash on
        // println if the load happened to dereference a non-string-like
        // value).
        //
        // The fix records the current function's source-level Err arm
        // LLVM type at `compile_function` entry (in
        // `current_fn_err_payload_ty`, lowered via
        // `llvm_type_for_type_expr` from the `Result[T, E]`
        // annotation). `compile_question`'s `fail_bb` extracts every
        // available payload word from the result struct (w0/w1/w2 at
        // fields 1/2/3) and calls `rebuild_value_from_payload_words`
        // to reconstruct the source-typed value. For `Result[T, String]`
        // this gives the `{ptr, i64 len, i64 cap}` struct directly —
        // the binding-form errdefer sees the live String value and
        // `println(e)` prints the message.
        //
        // This test pins the canonical wider-E shape (String — 3
        // payload words). Adjacent shapes (Vec, user struct) ride on
        // the same `rebuild_value_from_payload_words` dispatch path
        // and are out of scope for this single test.
        let out = run_program(
            r#"
fn boom() -> Result[i64, String] { Err("kaboom") }
fn caller() -> Result[i64, String] {
    errdefer(e) { println(e); }
    let _ = boom()?;
    Ok(0_i64)
}
fn main() {
    match caller() {
        Ok(_) => println("ok"),
        Err(_) => println("caller-err"),
    }
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            // errdefer(e) prints the bound String payload "kaboom"
            // (rebuilt from the result struct's 3 payload words via
            // `rebuild_value_from_payload_words`), then the caller's
            // Err arm prints "caller-err".
            assert_eq!(lines, vec!["kaboom", "caller-err"]);
        }
    }

    // ── Slice 9: Module-level let / let mut codegen (design.md §1278-1330) ─
    //
    // Real LLVM globals — immutable `let X: T = INIT` lowers to
    // `@X = internal constant T INIT`; `let mut X: T = INIT` lowers
    // to `@X = internal global T INIT`. `#[thread_local]` adds the
    // thread-local storage class. Reads route through LLVM `load`,
    // writes through LLVM `store`. Tests below exercise each shape
    // end-to-end so a regression in any layer surfaces.

    #[test]
    fn test_e2e_modbind_immutable_let_read() {
        let output = run_program(
            "let MAX: i64 = 100;\n\
             fn main() { println(MAX); }",
        )
        .expect("compile + run failed");
        assert_eq!(output, "100\n");
    }

    #[test]
    fn test_e2e_modbind_let_mut_read_and_write() {
        // Bump in one function, read in main — global state survives
        // across function calls, which is the v1-blocking property
        // captured by §1322's synthetic-resource conflict analysis.
        let output = run_program(
            "let mut COUNTER: i64 = 0;\n\
             fn bump() { COUNTER = COUNTER + 1; }\n\
             fn main() {\n\
                 bump();\n\
                 bump();\n\
                 bump();\n\
                 println(COUNTER);\n\
             }",
        )
        .expect("compile + run failed");
        assert_eq!(output, "3\n");
    }

    #[test]
    fn test_e2e_modbind_compound_assign() {
        // `+=` / `-=` / `*=` lower to load + binop + store on the
        // global pointer. Catches any drift in the CompoundAssign
        // arm's identifier-LHS fast path.
        let output = run_program(
            "let mut N: i64 = 5;\n\
             fn main() {\n\
                 N += 10;\n\
                 N -= 3;\n\
                 N *= 2;\n\
                 println(N);\n\
             }",
        )
        .expect("compile + run failed");
        assert_eq!(output, "24\n");
    }

    #[test]
    fn test_e2e_modbind_string_slice_literal() {
        // `let G: StringSlice = "hello";` materialises a (ptr, len,
        // cap=0) aggregate global. `cap=0` is the static-buffer
        // marker — runtime scope-exit cleanup never frees this
        // pointer.
        let output = run_program(
            "let GREETING: StringSlice = \"hello\";\n\
             fn main() { println(GREETING); }",
        )
        .expect("compile + run failed");
        assert_eq!(output, "hello\n");
    }

    #[test]
    fn test_e2e_modbind_thread_local_read_write() {
        // `#[thread_local]` lowers to an LLVM thread-local global.
        // Single-task case: behaves identically to a non-thread-local
        // `let mut` (each task sees its own copy starting at the
        // initializer). The per-task disjoint-instance semantic
        // matters for parallel code; main-thread sanity check here.
        let output = run_program(
            "#[thread_local]\n\
             let mut TLS_COUNTER: i64 = 0;\n\
             fn main() {\n\
                 TLS_COUNTER = 42;\n\
                 println(TLS_COUNTER);\n\
             }",
        )
        .expect("compile + run failed");
        assert_eq!(output, "42\n");
    }

    #[test]
    fn test_e2e_modbind_bool_let_mut() {
        let output = run_program(
            "let mut FLAG: bool = false;\n\
             fn flip() { FLAG = true; }\n\
             fn main() {\n\
                 flip();\n\
                 println(FLAG);\n\
             }",
        )
        .expect("compile + run failed");
        assert_eq!(output, "true\n");
    }

    #[test]
    fn test_e2e_modbind_float_immutable_let() {
        let output = run_program(
            "let PI: f64 = 3.14;\n\
             fn main() { println(PI); }",
        )
        .expect("compile + run failed");
        assert_eq!(output, "3.14\n");
    }

    #[test]
    fn test_e2e_modbind_negated_int_literal() {
        // `let X = -42;` — the AST shape is `Unary { Neg, Integer }`,
        // not `Integer(-42)`. The slice-9 surface lowers it
        // recursively so the negative-init case works.
        let output = run_program(
            "let TEMP: i64 = -42;\n\
             fn main() { println(TEMP); }",
        )
        .expect("compile + run failed");
        assert_eq!(output, "-42\n");
    }

    #[test]
    fn test_e2e_modbind_two_distinct_bindings_independent() {
        // Two distinct `let mut` bindings get their own globals; a
        // write to one doesn't leak into the other. Mirrors the
        // slice-6 effect-checker test which proves synthetic
        // resources are per-binding; this is the codegen analogue.
        let output = run_program(
            "let mut A: i64 = 0;\n\
             let mut B: i64 = 0;\n\
             fn main() {\n\
                 A = 7;\n\
                 B = 11;\n\
                 println(A);\n\
                 println(B);\n\
             }",
        )
        .expect("compile + run failed");
        assert_eq!(output, "7\n11\n");
    }

    #[test]
    fn test_e2e_modbind_read_from_callee_observes_writes_from_caller() {
        // Writer in main, reader in private fn — confirms the
        // global-state visibility property end-to-end. If the read
        // path resolved to a stale local snapshot instead of the
        // global, the second `read()` call would print `0`.
        let output = run_program(
            "let mut STATE: i64 = 0;\n\
             fn read() -> i64 { STATE }\n\
             fn main() {\n\
                 println(read());\n\
                 STATE = 100;\n\
                 println(read());\n\
             }",
        )
        .expect("compile + run failed");
        assert_eq!(output, "0\n100\n");
    }

    #[test]
    fn test_e2e_modbind_local_shadow_takes_precedence() {
        // A function-local `let mut COUNTER` shadows the
        // module-level binding for the duration of that scope — the
        // identifier read resolves to the local slot first per the
        // compile_expr Identifier arm's lookup order (`variables`
        // before `module_bindings`). Without this guarantee, a
        // function that happened to name a local after a module
        // binding would silently read the global instead.
        let output = run_program(
            "let mut COUNTER: i64 = 100;\n\
             fn local_shadows() -> i64 {\n\
                 let COUNTER: i64 = 7;\n\
                 COUNTER\n\
             }\n\
             fn main() {\n\
                 println(local_shadows());\n\
                 println(COUNTER);\n\
             }",
        )
        .expect("compile + run failed");
        assert_eq!(output, "7\n100\n");
    }

    #[test]
    fn test_e2e_modbind_computed_cross_referencing_initializer() {
        // B-2026-07-11-16: a COMPUTED / cross-referencing module-binding
        // initializer (`let DOUBLED = COUNT * 2`, referencing another binding) is
        // not a foldable const shape, so it is deferred to `__karac_static_init`
        // (compiled via `compile_expr`, stored before `main`). Declaration order
        // is preserved, so `TRIPLED = DOUBLED + COUNT` sees DOUBLED's computed
        // value. Matches the interpreter output exactly (run==build parity).
        let output = run_program(
            "let COUNT: i64 = 42;\n\
             let DOUBLED: i64 = COUNT * 2;\n\
             let TRIPLED: i64 = DOUBLED + COUNT;\n\
             let SUM: i64 = 2 + 3 * 4;\n\
             fn main() {\n\
                 println(COUNT);\n\
                 println(DOUBLED);\n\
                 println(TRIPLED);\n\
                 println(SUM);\n\
             }",
        )
        .expect("compile + run failed");
        assert_eq!(output, "42\n84\n126\n14\n");
    }

    #[test]
    fn test_e2e_modbind_computed_unannotated_initializer() {
        // B-2026-07-11-16 residual: a COMPUTED binding with NO `: TYPE`
        // annotation (`let DOUBLED = COUNT * 2;`). There is no declared type to
        // size the placeholder global, so codegen sizes it from the
        // typechecker's inferred type (`program.module_binding_types`, threaded
        // through lowering). Both an i64 chain and an i32 binding are exercised
        // to confirm the inferred width is honored (not defaulted to i64).
        // Matches the interpreter output exactly (run==build parity).
        let output = run_program(
            "let COUNT: i64 = 42;\n\
             let DOUBLED = COUNT * 2;\n\
             let TRIPLED = DOUBLED + COUNT;\n\
             let SMALL: i32 = 7i32;\n\
             let SMALL2 = SMALL + 3i32;\n\
             fn main() {\n\
                 println(DOUBLED);\n\
                 println(TRIPLED);\n\
                 println(SMALL2);\n\
             }",
        )
        .expect("compile + run failed");
        assert_eq!(output, "84\n126\n10\n");
    }

    #[test]
    fn test_e2e_modbind_struct_field_read_annotated() {
        // Uppercase-receiver field access — `CFG.max` / nested
        // `OUTER.inner.field` on a value binding. The parser consumes the
        // uppercase-led dotted chain greedily into a `Path`, so the read
        // lands in `resolve_path_type`, which now walks the binding's struct
        // fields. Codegen's `compile_path_expr` always lowered this shape
        // correctly, but `karac build` exited on a typecheck error
        // (`expected 'i64', found 'Config'`) before the typechecker walk
        // landed. Assert the typecheck gate is CLEAN — the slice-10
        // `run_program` harness ignores typecheck errors, so the runtime
        // output alone would pass vacuously. phase-8-stdlib-floor.md
        // "Uppercase-receiver field access" entry.
        let src = "struct Inner { field: i64 }\n\
                   struct Config { max: i64, count: i64 }\n\
                   struct Outer { inner: Inner }\n\
                   let CFG: Config = Config { max: 64, count: 7 };\n\
                   fn main() {\n\
                       let m: i64 = CFG.max;\n\
                       let c: i64 = CFG.count;\n\
                       let OUTER: Outer = Outer { inner: Inner { field: 9 } };\n\
                       let n: i64 = OUTER.inner.field;\n\
                       println(f\"{m} {c} {n}\");\n\
                   }";
        // The real CLI gate: typecheck must produce no errors.
        let parsed = karac::parse(src);
        assert!(
            parsed.errors.is_empty(),
            "parse errors: {:?}",
            parsed.errors
        );
        let resolved = karac::resolve(&parsed.program);
        let typed = karac::typecheck(&parsed.program, &resolved);
        assert!(
            typed.errors.is_empty(),
            "uppercase-receiver field read must typecheck clean, got: {:?}",
            typed.errors.iter().map(|e| &e.message).collect::<Vec<_>>(),
        );
        // And the binary produces the right values.
        let output = run_program(src).expect("compile + run failed");
        assert_eq!(output, "64 7 9\n");
    }

    // ── Map.new() / Set.new() as module-binding initialisers
    //    (phase-8-stdlib-floor.md "Map.new() / Set.new() as module-binding
    //    initialisers"). Unlike Vec.new(), the empty value is NOT a
    //    zero-shaped constant — `karac_map_new` installs hash seeds + a
    //    vtable — so codegen emits a placeholder `null` ptr global and fills
    //    it from a `__karac_static_init` prologue that runs before main's
    //    body. Each test asserts the typecheck gate is CLEAN (run_program
    //    ignores typecheck errors, so runtime output alone passes vacuously)
    //    AND the binary produces the right values. ──

    #[test]
    fn test_e2e_modbind_map_new_insert_and_get() {
        // Module-scope `Map.new()`: insert in one fn, read in another —
        // the handle lives in a global filled by the static-init prologue,
        // so the write is observable across calls.
        let src = "let mut REGISTRY: Map[String, i64] = Map.new();\n\
                   fn put() { REGISTRY.insert(\"answer\", 42); }\n\
                   fn main() {\n\
                       put();\n\
                       println(REGISTRY.get(\"answer\").unwrap_or(0));\n\
                       println(REGISTRY.get(\"missing\").unwrap_or(-1));\n\
                   }";
        let parsed = karac::parse(src);
        assert!(
            parsed.errors.is_empty(),
            "parse errors: {:?}",
            parsed.errors
        );
        let resolved = karac::resolve(&parsed.program);
        let typed = karac::typecheck(&parsed.program, &resolved);
        assert!(
            typed.errors.is_empty(),
            "module-scope Map.new() must typecheck clean, got: {:?}",
            typed.errors.iter().map(|e| &e.message).collect::<Vec<_>>(),
        );
        let output = run_program(src).expect("compile + run failed");
        assert_eq!(output, "42\n-1\n");
    }

    #[test]
    fn test_e2e_modbind_map_new_int_keys() {
        // Int-keyed module-scope Map — a different hash/eq emission path
        // (i64 key vs the String key above). Two inserts + an overwrite to
        // prove the single global handle persists across writes.
        let src = "let mut SCORES: Map[i64, i64] = Map.new();\n\
                   fn main() {\n\
                       SCORES.insert(1, 10);\n\
                       SCORES.insert(2, 20);\n\
                       SCORES.insert(1, 11);\n\
                       println(SCORES.get(1).unwrap_or(0));\n\
                       println(SCORES.get(2).unwrap_or(0));\n\
                   }";
        let parsed = karac::parse(src);
        assert!(
            parsed.errors.is_empty(),
            "parse errors: {:?}",
            parsed.errors
        );
        let resolved = karac::resolve(&parsed.program);
        let typed = karac::typecheck(&parsed.program, &resolved);
        assert!(
            typed.errors.is_empty(),
            "int-keyed module-scope Map.new() must typecheck clean, got: {:?}",
            typed.errors.iter().map(|e| &e.message).collect::<Vec<_>>(),
        );
        let output = run_program(src).expect("compile + run failed");
        assert_eq!(output, "11\n20\n");
    }

    #[test]
    fn test_e2e_modbind_set_new_insert_and_contains() {
        // Module-scope `Set.new()`: insert in one fn, query membership in
        // main. Set reuses `karac_map_new` with val_size = 0.
        let src = "let mut SEEN: Set[i64] = Set.new();\n\
                   fn mark() { SEEN.insert(7); }\n\
                   fn main() {\n\
                       mark();\n\
                       SEEN.insert(9);\n\
                       println(SEEN.contains(7));\n\
                       println(SEEN.contains(9));\n\
                       println(SEEN.contains(3));\n\
                   }";
        let parsed = karac::parse(src);
        assert!(
            parsed.errors.is_empty(),
            "parse errors: {:?}",
            parsed.errors
        );
        let resolved = karac::resolve(&parsed.program);
        let typed = karac::typecheck(&parsed.program, &resolved);
        assert!(
            typed.errors.is_empty(),
            "module-scope Set.new() must typecheck clean, got: {:?}",
            typed.errors.iter().map(|e| &e.message).collect::<Vec<_>>(),
        );
        let output = run_program(src).expect("compile + run failed");
        assert_eq!(output, "true\ntrue\nfalse\n");
    }

    #[test]
    fn test_e2e_modbind_two_distinct_maps_independent() {
        // Two distinct module-scope Map bindings each get their own global
        // handle filled by the prologue; a write to one doesn't leak into
        // the other (the static-init emits one karac_map_new per binding).
        let src = "let mut A: Map[i64, i64] = Map.new();\n\
                   let mut B: Map[i64, i64] = Map.new();\n\
                   fn main() {\n\
                       A.insert(1, 100);\n\
                       B.insert(1, 200);\n\
                       println(A.get(1).unwrap_or(0));\n\
                       println(B.get(1).unwrap_or(0));\n\
                   }";
        let parsed = karac::parse(src);
        assert!(
            parsed.errors.is_empty(),
            "parse errors: {:?}",
            parsed.errors
        );
        let resolved = karac::resolve(&parsed.program);
        let typed = karac::typecheck(&parsed.program, &resolved);
        assert!(
            typed.errors.is_empty(),
            "two module-scope Maps must typecheck clean, got: {:?}",
            typed.errors.iter().map(|e| &e.message).collect::<Vec<_>>(),
        );
        let output = run_program(src).expect("compile + run failed");
        assert_eq!(output, "100\n200\n");
    }

    // ── Type-changing shadows (phase-5-diagnostics "codegen
    //    type-changing-shadow"). A `let` that re-binds an in-scope name with
    //    a different type/class used to be rejected by a `bind_pattern` guard
    //    because the per-variable sidecar metadata (string/collection class
    //    tags) survived the rebind and mis-dispatched a later use. The
    //    `shadow.rs` take/restore dance now purges the old tags. Each test
    //    soft-skips when the runtime archive is unavailable (run_program ->
    //    None), matching the rest of the E2E suite. ──

    #[test]
    fn test_e2e_shadow_string_to_int_via_old_binding() {
        // `let s = s.len()` — collection→scalar shadow whose RHS references
        // the OLD binding. The dance must keep `s` dispatching as a String
        // while the RHS compiles, then drop the String tag so `println(s)`
        // formats an i64 (not a String, which would trap).
        if let Some(out) = run_program(
            "fn main() {\n\
             let s = \"hello\";\n\
             let s = s.len();\n\
             println(s);\n\
             }",
        ) {
            assert_eq!(out, "5\n");
        }
    }

    #[test]
    fn test_e2e_shadow_int_to_string() {
        // int→String shadow. The new String tag must be installed; the old
        // (absent) scalar metadata leaves nothing to purge.
        if let Some(out) = run_program(
            "fn main() {\n\
             let s = 5i64;\n\
             let s = \"world\";\n\
             println(s);\n\
             }",
        ) {
            assert_eq!(out, "world\n");
        }
    }

    #[test]
    fn test_e2e_shadow_string_to_vec_chars_references_old() {
        // String→Vec[char] shadow whose RHS (`s.chars()`) dispatches on the
        // OLD String binding. Same-layout cross-class ({ptr,i64,i64}); the
        // dance is what lets `chars()` see a String while `s.len()` after the
        // rebind sees the new Vec[char].
        if let Some(out) = run_program(
            "fn main() {\n\
             let s = \"abc\";\n\
             let s = s.chars();\n\
             println(s.len());\n\
             }",
        ) {
            assert_eq!(out, "3\n");
        }
    }

    #[test]
    fn test_e2e_shadow_collection_to_scalar() {
        // Vec→scalar shadow with RHS referencing the old Vec. The old
        // `vec_elem_types` tag must be purged so `println(v)` formats an i64.
        if let Some(out) = run_program(
            "fn main() {\n\
             let mut v: Vec[i64] = Vec.new();\n\
             v.push(10i64);\n\
             v.push(20i64);\n\
             v.push(30i64);\n\
             let v = v.len();\n\
             println(v);\n\
             }",
        ) {
            assert_eq!(out, "3\n");
        }
    }

    #[test]
    fn test_e2e_shadow_vec_to_string() {
        // Vec→String shadow (same layout, opposite direction). The old
        // collection tags must be gone so `s` dispatches as a String.
        if let Some(out) = run_program(
            "fn main() {\n\
             let mut s: Vec[i64] = Vec.new();\n\
             s.push(1i64);\n\
             let s = \"done\";\n\
             println(s);\n\
             println(s.len());\n\
             }",
        ) {
            assert_eq!(out, "done\n4\n");
        }
    }

    #[test]
    fn test_e2e_shadow_struct_a_to_struct_b() {
        // struct-A→struct-B shadow. `var_type_names` / field metadata for the
        // old struct must be replaced so `p.<field>` resolves against B.
        if let Some(out) = run_program(
            "struct A { x: i64 }\n\
             struct B { y: i64 }\n\
             fn main() {\n\
             let p = A { x: 1i64 };\n\
             let p = B { y: 2i64 };\n\
             println(p.y);\n\
             }",
        ) {
            assert_eq!(out, "2\n");
        }
    }

    #[test]
    fn test_e2e_shadow_in_for_loop_over_collection_var() {
        // A for-loop binding that shadows an in-scope String with a scalar
        // element. The purge lives in `bind_pattern` (the for-loop's choke
        // point), so the loop var `s` dispatches as i64 inside the body even
        // though an outer `s` was a String — `sum + s` and `println(s)` both
        // treat `s` as i64. (This program did not compile before the fix: the
        // old `bind_pattern` guard rejected the scalar-over-String rebind.
        // Codegen's function-flat `variables` map does not restore the outer
        // `s` after the loop, an orthogonal pre-existing scoping limitation,
        // so the test asserts only the in-loop dispatch.)
        if let Some(out) = run_program(
            "fn main() {\n\
             let s = \"outer\";\n\
             let mut sum = 0i64;\n\
             for s in [1i64, 2i64, 3i64] {\n\
                 println(s);\n\
                 sum = sum + s;\n\
             }\n\
             println(sum);\n\
             }",
        ) {
            assert_eq!(out, "1\n2\n3\n6\n");
        }
    }

    #[test]
    fn test_e2e_shadow_same_class_still_works() {
        // Regression guard: a same-class shadow (String→String) must keep
        // working — the dance is a no-op-equivalent when the class is
        // unchanged (old tags purged, identical new tags reinstalled).
        if let Some(out) = run_program(
            "fn main() {\n\
             let s = \"first\";\n\
             let s = \"second\";\n\
             println(s);\n\
             println(s.len());\n\
             }",
        ) {
            assert_eq!(out, "second\n6\n");
        }
    }

    #[test]
    fn test_ir_modbind_emits_internal_global() {
        // The lowered IR contains the global with `internal` linkage
        // and the right constant/non-constant flag for the
        // `let` / `let mut` distinction.
        let ir = ir_for(
            "let MAX: i64 = 100;\n\
             let mut COUNTER: i64 = 0;\n\
             fn main() { println(MAX); println(COUNTER); }",
        );
        assert!(
            ir.contains("@MAX = internal constant i64 100"),
            "expected `@MAX = internal constant i64 100` in IR, got:\n{}",
            ir
        );
        assert!(
            ir.contains("@COUNTER = internal global i64 0"),
            "expected `@COUNTER = internal global i64 0` in IR, got:\n{}",
            ir
        );
    }

    #[test]
    fn test_ir_modbind_thread_local_carries_storage_class() {
        // `#[thread_local]` must produce the `thread_local` keyword
        // on the LLVM global so the linker emits the per-task TLS
        // segment. The general-dynamic model is portable across
        // ELF/Mach-O; LLVM IR prints it as `thread_local` (no
        // qualifier) by default.
        let ir = ir_for(
            "#[thread_local]\n\
             let mut TLS_COUNTER: i64 = 0;\n\
             fn main() { TLS_COUNTER = 1; println(TLS_COUNTER); }",
        );
        assert!(
            ir.contains("thread_local") && ir.contains("@TLS_COUNTER"),
            "expected thread_local TLS_COUNTER global in IR, got:\n{}",
            ir
        );
    }

    #[test]
    fn test_ir_modbind_vec_new_emits_empty_aggregate() {
        // `Vec.new()` at module scope lowers to the canonical empty-Vec
        // `{ptr null, i64 0, i64 0}` aggregate matching the runtime
        // invariant in `assoc_call.rs`'s shared `Vec/VecDeque && method
        // == "new"` arm. LLVM prints an all-zero aggregate as
        // `zeroinitializer` rather than the expanded field list, which
        // is what we assert against. Mutable form → `internal global`;
        // immutable form → `internal constant`.
        let ir = ir_for(
            "let mut TODOS: Vec[i64] = Vec.new();\n\
             let EMPTY: Vec[i64] = Vec.new();\n\
             fn main() {}",
        );
        assert!(
            ir.contains("@TODOS = internal global { ptr, i64, i64 } zeroinitializer"),
            "expected @TODOS Vec global as zeroinitializer, got:\n{}",
            ir
        );
        assert!(
            ir.contains("@EMPTY = internal constant { ptr, i64, i64 } zeroinitializer"),
            "expected @EMPTY Vec constant as zeroinitializer, got:\n{}",
            ir
        );
    }

    #[test]
    fn test_ir_modbind_vecdeque_new_emits_empty_aggregate() {
        // `VecDeque.new()` shares Vec's `{ptr, len, cap}` layout per
        // `assoc_call.rs`; same const-init lowering applies.
        let ir = ir_for(
            "let mut QUEUE: VecDeque[i64] = VecDeque.new();\n\
             fn main() {}",
        );
        assert!(
            ir.contains("@QUEUE = internal global { ptr, i64, i64 } zeroinitializer"),
            "expected @QUEUE VecDeque global as zeroinitializer, got:\n{}",
            ir
        );
    }

    #[test]
    fn test_e2e_modbind_vec_push_then_len() {
        // End-to-end pin for the uppercase-receiver method-dispatch fix —
        // the backend kata's canonical shape. The parser produces
        // `Call(Path([TODOS, push]))` because `TODOS` starts uppercase;
        // the typechecker rewrite at `infer_call` re-routes through
        // `infer_method_call`, lowering rewrites the AST to
        // `MethodCall(Identifier(TODOS), push, ...)`, and codegen's
        // method-call dispatch for module-binding receivers uses
        // `get_data_ptr`'s module-binding fall-back to thread the
        // global's pointer through `compile_vec_method`. Without any
        // one of those three steps, the call falls through to a
        // codegen error or compiles to a stub that no-ops.
        let output = run_program(
            "let mut TODOS: Vec[i64] = Vec.new();\n\
             fn main() {\n\
                 TODOS.push(10);\n\
                 TODOS.push(20);\n\
                 TODOS.push(30);\n\
                 println(TODOS.len());\n\
             }",
        )
        .expect("compile + run failed");
        assert_eq!(output, "3\n");
    }

    #[test]
    fn test_e2e_vec_remove_local() {
        // `Vec.remove(idx)` on a local: returns the removed element,
        // shifts the tail down by one, decrements len. v1 contract is
        // unchecked (UB on OOB) — the test pins an in-bounds case.
        let output = run_program(
            "fn main() {\n\
                 let mut xs: Vec[i64] = Vec.new();\n\
                 xs.push(10);\n\
                 xs.push(20);\n\
                 xs.push(30);\n\
                 let removed: i64 = xs.remove(1);\n\
                 println(removed);\n\
                 println(xs.len());\n\
                 println(xs[0]);\n\
                 println(xs[1]);\n\
             }",
        )
        .expect("compile + run failed");
        assert_eq!(output, "20\n2\n10\n30\n");
    }

