    // ── Refinement types (phase-9 step 4) ───────────────────────

    #[test]
    fn test_e2e_refinement_arithmetic_returns_base() {
        // `d + d` where `d: Doubled` strips to the base `i64` for the add,
        // and the result is the base type — so it prints as a plain i64.
        let out = run_program(
            r#"
type Doubled = i64 where self % 2 == 0;
fn main() {
    let d = 4 as Doubled;
    println(d + d);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "8");
        }
    }

    #[test]
    fn test_ir_refinement_param_uses_base_layout() {
        // A refinement over `i64` lowers its parameter to an `i64`, not a
        // pointer / struct — the base-layout resolution at work.
        let ir = ir_for(
            "type Even = i64 where self % 2 == 0;
             fn takes(e: Even) -> i64 { e + e }",
        );
        assert!(
            ir.contains("i64 @takes(i64") || ir.contains("define i64 @takes(i64"),
            "refinement param should lower to its i64 base:\n{ir}"
        );
    }

    #[test]
    fn test_ir_refinement_over_string_matches_base_layout() {
        // The bug the layout arm fixes: a refinement over a *non-`i64`*
        // base (`type Name = String`) must lower to the base's layout, not
        // the `i64` fall-through default. Prove it by comparing the `@takes`
        // parameter type against the equivalent plain-`String` signature —
        // they must be identical.
        fn takes_param_type(ir: &str) -> String {
            let i = ir.find("@takes(").expect("no @takes in IR");
            let rest = &ir[i + "@takes(".len()..];
            let end = rest.find([' ', ')']).unwrap_or(rest.len());
            rest[..end].to_string()
        }
        let refined = ir_for(
            "type Name = String where self.len() > 0;
             fn takes(n: Name) -> i64 { 0 }",
        );
        let plain = ir_for("fn takes(n: String) -> i64 { 0 }");
        assert_eq!(
            takes_param_type(&refined),
            takes_param_type(&plain),
            "refinement over String must lower to the String base layout\nrefined IR:\n{refined}"
        );
        // Sanity: it is NOT the i64 fall-through default.
        assert_ne!(
            takes_param_type(&refined),
            "i64",
            "refinement over String must not hit the i64 fall-through:\n{refined}"
        );
    }

    #[test]
    fn test_e2e_refinement_string_base_method_deref() {
        // Codegen value-dispatch (phase-9 step 5a) strips the refinement to
        // its base, so `n.len()` (base-deref, step 2) reads 5 from the
        // String value bound through an `as Name` cast.
        let out = run_program(
            r#"
type Name = String where self.len() > 0;
fn main() {
    let n = "hello" as Name;
    println(n.len());
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "5");
        }
    }

    #[test]
    fn test_e2e_refinement_string_value_prints_as_base() {
        // `println(n)` on a refinement-over-String binding dispatches the
        // String display path (value-dispatch, step 5a) — not the i64
        // fall-through that would print a pointer-sized integer.
        let out = run_program(
            r#"
type Name = String where self.len() > 0;
fn main() {
    let n = "hello" as Name;
    println(n);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "hello");
        }
    }

    #[test]
    fn test_e2e_refinement_i64_value_dispatch_unaffected() {
        // Refinements over i64 already work end-to-end (base layout
        // coincides with codegen's i64 default); the value-dispatch
        // normalization must not regress them.
        let out = run_program(
            r#"
type Even = i64 where self % 2 == 0;
fn main() {
    let e = 4 as Even;
    let f = e + 2;
    println(f);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "6");
        }
    }

    // ── Refinement runtime predicate emission (phase-9 step 5c) ──

    #[test]
    fn test_e2e_refinement_as_cast_predicate_holds() {
        // `4 as Even` passes `self % 2 == 0`, so the value flows through and
        // execution continues normally (no fault).
        let out = run_program(
            r#"
type Even = i64 where self % 2 == 0;
fn main() {
    let e = 4 as Even;
    println(e);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "4");
        }
    }

    #[test]
    fn test_e2e_refinement_as_cast_violation_aborts() {
        // `3 as Even` fails the predicate: codegen emits a contract-violation
        // abort, and code after the cast does not run.
        let captured = run_program_capturing(
            r#"
type Even = i64 where self % 2 == 0;
fn main() {
    let e = 3 as Even;
    println(e);
    println(42);
}
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract violated") && c.stdout.contains("Even"),
                "expected a contract-violation abort naming Even, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                !c.stdout.contains("42"),
                "code after a violated refinement cast must not run"
            );
        }
    }

    #[test]
    fn test_e2e_refinement_as_cast_string_method_predicate_aborts() {
        // A method-form predicate (`self.len() > 0`) over a String base is
        // compiled and enforced: an empty string fails and aborts.
        let captured = run_program_capturing(
            r#"
type NonEmpty = String where self.len() > 0;
fn main() {
    let s = "" as NonEmpty;
    println(s);
}
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract violated") && c.stdout.contains("NonEmpty"),
                "expected NonEmpty contract abort, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
        }
    }

    #[test]
    fn test_e2e_refinement_try_from_ok_branch() {
        // `Even.try_from(4)` builds `Ok(4)` at runtime; the match prints it.
        let out = run_program(
            r#"
type Even = i64 where self % 2 == 0;
fn main() {
    match Even.try_from(4) {
        Ok(v) => println(v),
        Err(_) => println(-1),
    }
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "4");
        }
    }

    #[test]
    fn test_e2e_refinement_try_from_err_branch() {
        // `Even.try_from(3)` builds `Err(...)`; the match takes the Err arm
        // (no abort — try_from is the recoverable construction form).
        let out = run_program(
            r#"
type Even = i64 where self % 2 == 0;
fn main() {
    match Even.try_from(3) {
        Ok(v) => println(v),
        Err(_) => println(-1),
    }
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "-1");
        }
    }

    // ── Distinct types — constructor + .raw() (zero-cost) ──────────

    #[test]
    fn test_e2e_distinct_constructor_and_raw() {
        // `UserId(42)` wraps a base value (zero-cost) and `.raw()` unwraps
        // it — at codegen the wrapper is invisible (i64 base layout).
        let out = run_program(
            r#"
distinct type UserId = i64;
fn main() {
    let u = UserId(42);
    let r: i64 = u.raw();
    println(r);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "42");
        }
    }

    #[test]
    fn test_e2e_distinct_float_base_layout() {
        // A non-`i64` base lowers to the correct layout: a distinct type
        // over `f64` round-trips `3.5` losslessly (would print garbage if it
        // hit the `i64` fall-through default).
        let out = run_program(
            r#"
distinct type Meters = f64;
fn main() {
    let m = Meters(3.5);
    println(m.raw());
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "3.5");
        }
    }

    #[test]
    fn test_e2e_distinct_roundtrips_through_function() {
        // A distinct value passes through a function call typed in the
        // distinct type and unwraps back to its base on the far side.
        let out = run_program(
            r#"
distinct type UserId = i64;
fn identity(id: UserId) -> UserId { id }
fn main() {
    let u = identity(UserId(7));
    println(u.raw());
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "7");
        }
    }

    // ── Combined `distinct type T = Base where pred` ───────────────

    #[test]
    fn test_e2e_distinct_where_constructor_holds() {
        // `Even(8)` passes the predicate — the constructor compiles to the
        // base value with the runtime assertion satisfied.
        let out = run_program(
            r#"
distinct type Even = i64 where self % 2 == 0;
fn mk(n: i64) -> Even { Even(n) }
fn main() { println(mk(8).raw()); }
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "8");
        }
    }

    #[test]
    fn test_e2e_distinct_where_constructor_aborts() {
        // `Even(7)` violates the predicate at runtime: the constructor emits
        // a contract-violation abort, and code after it does not run.
        let captured = run_program_capturing(
            r#"
distinct type Even = i64 where self % 2 == 0;
fn mk(n: i64) -> Even { Even(n) }
fn main() {
    let e = mk(7);
    println(e.raw());
    println(42);
}
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract violated"),
                "expected a contract-violation abort, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                !c.stdout.contains("42"),
                "code after a violated distinct constructor must not run"
            );
        }
    }

    #[test]
    fn test_e2e_distinct_where_try_from_branches() {
        // `Even.try_from` builds `Ok`/`Err` with no abort (recoverable form).
        let ok = run_program(
            r#"
distinct type Even = i64 where self % 2 == 0;
fn main() {
    match Even.try_from(8) { Ok(e) => println(e.raw()), Err(_) => println(-1) }
}
"#,
        );
        if let Some(out) = ok {
            assert_eq!(out.trim(), "8");
        }
        let err = run_program(
            r#"
distinct type Even = i64 where self % 2 == 0;
fn main() {
    match Even.try_from(7) { Ok(e) => println(e.raw()), Err(_) => println(-1) }
}
"#,
        );
        if let Some(out) = err {
            assert_eq!(out.trim(), "-1");
        }
    }

    // ── ExitCode entry-point return type (Phase-8 Slice B) ─────────

    #[test]
    fn test_e2e_main_exitcode_success() {
        // `main() -> ExitCode { ... ExitCode.SUCCESS }` exits 0.
        let cap = run_program_capturing(
            r#"
fn main() -> ExitCode {
    println("ran");
    ExitCode.SUCCESS
}
"#,
        );
        if let Some(cap) = cap {
            assert_eq!(cap.status.code(), Some(0), "stderr={:?}", cap.stderr);
            assert_eq!(cap.stdout.trim(), "ran");
        }
    }

    #[test]
    fn test_e2e_main_exitcode_failure() {
        // `ExitCode.FAILURE` exits 1 (the literal `1`, not EXIT_FAILURE).
        let cap = run_program_capturing(
            r#"
fn main() -> ExitCode {
    ExitCode.FAILURE
}
"#,
        );
        if let Some(cap) = cap {
            assert_eq!(cap.status.code(), Some(1), "stderr={:?}", cap.stderr);
        }
    }

    #[test]
    fn test_e2e_main_exitcode_from_arbitrary() {
        // `ExitCode.from(code)` returns an arbitrary process exit code.
        let cap = run_program_capturing(
            r#"
fn main() -> ExitCode {
    ExitCode.from(42)
}
"#,
        );
        if let Some(cap) = cap {
            assert_eq!(cap.status.code(), Some(42), "stderr={:?}", cap.stderr);
        }
    }

    #[test]
    fn test_e2e_main_exitcode_direct_constructor_narrows_to_i32() {
        // `ExitCode(7)` — the bare distinct constructor over an `i32` base.
        // The default-`i64` literal must narrow to the `i32` base width so
        // it round-trips through the C-entry `i32 main()` signature.
        let cap = run_program_capturing(
            r#"
fn main() -> ExitCode {
    ExitCode(7)
}
"#,
        );
        if let Some(cap) = cap {
            assert_eq!(cap.status.code(), Some(7), "stderr={:?}", cap.stderr);
        }
    }

    #[test]
    fn test_e2e_main_exitcode_canonical_match_ok_unit() {
        // The canonical design.md § Entry Point shape: match a fallible
        // result, `Ok(())` → SUCCESS, `Err(e)` → a custom code. Exercises
        // the `Ok(())` unit-payload pattern (exhaustiveness + match codegen)
        // together with the `ExitCode` arms — both must agree on `i32` width
        // so the match phi merges.
        let cap = run_program_capturing(
            r#"
fn run(ok: bool) -> Result[(), String] {
    if ok { Ok(()) } else { Err("boom") }
}
fn main() -> ExitCode {
    match run(false) {
        Ok(()) => ExitCode.SUCCESS,
        Err(e) => {
            eprintln("Error: {e}");
            ExitCode.from(3)
        }
    }
}
"#,
        );
        if let Some(cap) = cap {
            assert_eq!(cap.status.code(), Some(3), "stderr={:?}", cap.stderr);
        }
    }

    #[test]
    fn test_e2e_match_ok_unit_payload_is_exhaustive_and_selects_correct_arm() {
        // Regression: matching `Result[(), E]` with `Ok(())` / `Err(_)` is
        // exhaustive (the `()` empty-tuple pattern covers the unit payload)
        // and selects the right arm at runtime. Before the
        // `enumerate_ctors(Unit)` + variant-payload generic-substitution fix
        // this was wrongly flagged non-exhaustive and miscompiled (the Err
        // value fell through to a placeholder). Observed via stdout, not an
        // exit code, to keep the assertion ExitCode-independent.
        let out = run_program(
            r#"
fn classify(r: Result[(), String]) -> i64 {
    match r {
        Ok(()) => 10,
        Err(e) => 20,
    }
}
fn main() {
    println(classify(Err("x")));
    println(classify(Ok(())));
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "20\n10");
        }
    }

    // ── Contracts — requires preconditions (codegen / AOT) ─────────

    #[test]
    fn test_e2e_contract_requires_holds() {
        let out = run_program(
            r#"
fn checked(x: i64) -> i64 requires x > 0 { x * 2 }
fn main() { println(checked(5)); }
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "10");
        }
    }

    #[test]
    fn test_e2e_contract_requires_violation_aborts() {
        // A failed `requires` aborts with `contract violated`, and code after
        // the call does not run.
        let captured = run_program_capturing(
            r#"
fn checked(x: i64) -> i64 requires x > 0 { x * 2 }
fn main() {
    println(checked(-3));
    println(42);
}
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract violated"),
                "expected a contract-violation abort, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                !c.stdout.contains("42"),
                "code after a violated requires must not run"
            );
        }
    }

    #[test]
    fn test_e2e_contract_method_requires_aborts() {
        // `requires` is emitted on the method-dispatch path too.
        let captured = run_program_capturing(
            r#"
struct C { n: i64 }
impl C { fn step(self, by: i64) -> i64 requires by > 0 { self.n + by } }
fn main() {
    let c = C { n: 5 };
    println(c.step(-1));
    println(42);
}
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract violated"),
                "expected a method-requires abort, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                !c.stdout.contains("42"),
                "code after the abort must not run"
            );
        }
    }

    // ── Contracts — ensures + old() postconditions (codegen / AOT) ──

    #[test]
    fn test_e2e_contract_ensures_holds() {
        let out = run_program(
            r#"
fn double(x: i64) -> i64 ensures(result) result > x { x * 2 }
fn main() { println(double(5)); }
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "10");
        }
    }

    #[test]
    fn test_e2e_contract_ensures_violation_aborts() {
        let captured = run_program_capturing(
            r#"
fn bad(x: i64) -> i64 ensures(result) result > 100 { x }
fn main() { println(bad(5)); println(42); }
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract violated"),
                "expected an ensures abort, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                !c.stdout.contains("42"),
                "code after the abort must not run"
            );
        }
    }

    #[test]
    fn test_e2e_contract_ensures_old_holds() {
        // The canonical `old()` postcondition runs in an AOT binary: the
        // pre-state balance is captured at entry and read back at exit.
        let out = run_program(
            r#"
struct Account { balance: i64 }
impl Account {
    pub fn withdraw(mut ref self, amount: i64) -> i64
        ensures(result) self.balance == old(self.balance) - amount
    { self.balance = self.balance - amount; amount }
}
fn main() { let mut a = Account { balance: 100 }; println(a.withdraw(30)); }
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "30");
        }
    }

    #[test]
    fn test_e2e_contract_ensures_old_violation_aborts() {
        let captured = run_program_capturing(
            r#"
struct Account { balance: i64 }
impl Account {
    pub fn withdraw(mut ref self, amount: i64) -> i64
        ensures(result) self.balance == old(self.balance) - amount
    { self.balance = self.balance - 999; amount }
}
fn main() { let mut a = Account { balance: 100 }; println(a.withdraw(30)); println(42); }
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract violated"),
                "expected an old() ensures abort, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                !c.stdout.contains("42"),
                "code after the abort must not run"
            );
        }
    }

    #[test]
    fn test_e2e_contract_ensures_on_explicit_return() {
        // The check fires on an explicit `return`, not just the tail.
        let captured = run_program_capturing(
            r#"
fn f(x: i64) -> i64 ensures(result) result > 100 { if x > 0 { return x; } 999 }
fn main() { println(f(5)); println(42); }
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract violated"),
                "expected an ensures abort on the explicit-return path, got stdout={:?}",
                c.stdout
            );
            assert!(
                !c.stdout.contains("42"),
                "code after the abort must not run"
            );
        }
    }

    // ── Contracts — struct/impl invariants at method exits (codegen) ──
    //
    // design.md § Contracts rule 3: `impl invariant` fires at every method
    // exit (pub and private); plain `invariant` only at `pub` method exits.
    // These exercise the pub/private × plain/impl matrix in an AOT binary,
    // mirroring the interpreter coverage in tests/interpreter.rs.

    #[test]
    fn test_e2e_contract_invariant_holds() {
        // A pub method that keeps `self.n >= 0` true must not fault; the
        // value prints normally.
        let out = run_program(
            r#"
struct Counter { n: i64, invariant self.n >= 0 }
impl Counter { pub fn inc(mut ref self) -> i64 { self.n = self.n + 1; self.n } }
fn main() { let mut c = Counter { n: 0 }; println(c.inc()); }
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "1");
        }
    }

    #[test]
    fn test_e2e_contract_invariant_violation_aborts() {
        // `dec` drives `self.n` to -1, violating `self.n >= 0` at the pub
        // method exit — the binary aborts with `contract violated`.
        let captured = run_program_capturing(
            r#"
struct Counter { n: i64, invariant self.n >= 0 }
impl Counter { pub fn dec(mut ref self) { self.n = self.n - 1; } }
fn main() { let mut c = Counter { n: 0 }; c.dec(); println(42); }
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract violated"),
                "expected an invariant abort, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                !c.stdout.contains("42"),
                "code after the abort must not run"
            );
        }
    }

    #[test]
    fn test_e2e_contract_impl_invariant_fires_on_nonpub_exit() {
        // `impl invariant` fires at *every* method exit, including non-pub
        // methods. `dec` is non-pub and breaks `self.n >= 0` at its exit;
        // the binary aborts. This is what distinguishes `impl invariant`
        // from a plain `invariant` (next test). Calls the non-pub method
        // directly from `main` (same module, identifier receiver) — the
        // `self.method()` self-dispatch path is a separate codegen gap.
        let captured = run_program_capturing(
            r#"
struct Counter { n: i64, impl invariant self.n >= 0 }
impl Counter { fn dec(mut ref self) { self.n = self.n - 1; } }
fn main() { let mut c = Counter { n: 0 }; c.dec(); println(42); }
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract violated"),
                "expected impl-invariant abort at the non-pub exit, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                !c.stdout.contains("42"),
                "code after the abort must not run"
            );
        }
    }

    #[test]
    fn test_e2e_contract_plain_invariant_not_at_nonpub_exit() {
        // A plain `invariant` is checked only at `pub` method exits. `dec`
        // is non-pub and drives `self.n` to -1, violating `self.n >= 0` —
        // but because the method isn't `pub`, no check fires and the
        // program completes normally (prints 7). Same plain-invariant
        // struct as the abort test above; the *only* difference is the
        // `pub` keyword, isolating the pub-gating logic.
        let out = run_program(
            r#"
struct Counter { n: i64, invariant self.n >= 0 }
impl Counter { fn dec(mut ref self) { self.n = self.n - 1; } }
fn main() { let mut c = Counter { n: 0 }; c.dec(); println(7); }
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "7");
        }
    }

    // ── Contracts — constructor invariants (pub assoc fn returning Self) ─
    //
    // design.md § Contracts: "Constructors (pub associated functions that
    // return `Self`) also check the invariant at their return point." In
    // codegen the constructor has no `self` parameter, so the RETURN value is
    // bound as `self` before the invariant check (mirroring how `ensures`
    // binds `result`). Before this slice, `method_invariants_for` resolved the
    // invariants by the `Type.method` name but `emit_invariant_checks` aborted
    // codegen with `Undefined variable 'self'` — so these tests are
    // load-bearing (the harness panics on codegen failure). Owned structs
    // only; shared (RC) constructors are a tracked follow-on.

    #[test]
    fn test_e2e_constructor_invariant_holds() {
        // A constructor that produces a valid instance prints normally.
        let out = run_program(
            r#"
struct Counter { n: i64, invariant self.n >= 0 }
impl Counter { pub fn make() -> Counter { Counter { n: 7 } } }
fn main() { let c = Counter.make(); println(c.n); }
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "7");
        }
    }

    #[test]
    fn test_e2e_constructor_invariant_violation_aborts() {
        // The constructor builds `n = -5`, violating `self.n >= 0` at its
        // return point — the AOT binary aborts with `contract violated` even
        // though no method ran.
        let captured = run_program_capturing(
            r#"
struct Counter { n: i64, invariant self.n >= 0 }
impl Counter { pub fn bad() -> Counter { Counter { n: 0 - 5 } } }
fn main() { let c = Counter.bad(); println(c.n); println(42); }
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract violated"),
                "constructor invariant must abort, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                !c.stdout.contains("42"),
                "code after the abort must not run"
            );
        }
    }

    #[test]
    fn test_e2e_constructor_impl_invariant_aborts() {
        // `impl invariant` fires at the constructor return too. (The constructor
        // returns the explicit type name `-> Counter`; a `-> Self` return with a
        // named struct literal is rejected by the typechecker before codegen, so
        // `-> Type` is the buildable constructor form — `returns_self_or_type`
        // also accepts a literal `Self` defensively.)
        let captured = run_program_capturing(
            r#"
struct Counter { n: i64, impl invariant self.n >= 0 }
impl Counter { pub fn bad() -> Counter { Counter { n: 0 - 1 } } }
fn main() { let c = Counter.bad(); println(c.n); }
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract violated"),
                "an `impl invariant` must fire at the constructor return, got stdout={:?}",
                c.stdout
            );
        }
    }

    #[test]
    fn test_e2e_constructor_non_self_return_not_checked() {
        // A static associated function returning some other type (`-> i64`) is
        // not a constructor — its return value is NOT bound as `self` and NOT
        // invariant-checked, even though the type has an invariant. (Also a
        // regression guard: before this slice this aborted codegen with
        // `Undefined variable 'self'`.)
        let out = run_program(
            r#"
struct Counter { n: i64, invariant self.n >= 0 }
impl Counter { pub fn answer() -> i64 { 0 - 9 } }
fn main() { println(Counter.answer()); }
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "-9");
        }
    }

    #[test]
    fn test_e2e_shared_constructor_invariant_holds() {
        // Shared (RC) struct constructor invariants are now enforced in codegen
        // too: a valid instance runs and prints. The shared-receiver `self.field`
        // resolves through the heap-GEP path because `shared_type_for_expr`
        // accepts the constructor's `SelfValue` binding (gated to constructor
        // emission via `constructor_invariant_self_type`).
        let out = run_program(
            r#"
shared struct Scell { n: i64, invariant self.n >= 0 }
impl Scell { pub fn make() -> Scell { Scell { n: 3 } } }
fn main() { let c = Scell.make(); println(c.n); }
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "3");
        }
    }

    #[test]
    fn test_e2e_shared_constructor_invariant_violation_aborts() {
        // A shared-struct constructor that builds `n = -1` violates
        // `self.n >= 0` at its return point and aborts — the shared heap-GEP
        // field read sees the real `-1` (the +1 refcount offset is handled by
        // the shared path). Before this slice shared constructors were skipped
        // (unenforced); now they enforce like owned ones.
        let captured = run_program_capturing(
            r#"
shared struct Scell { n: i64, invariant self.n >= 0 }
impl Scell { pub fn bad() -> Scell { Scell { n: 0 - 1 } } }
fn main() { let c = Scell.bad(); println(c.n); println(42); }
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract violated"),
                "a shared-struct constructor invariant must abort, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                !c.stdout.contains("42"),
                "code after the abort must not run"
            );
        }
    }

    // ── `self.method()` self-dispatch (codegen method dispatch) ───────
    //
    // Inside an impl body, `self` parses as `ExprKind::SelfValue`, not
    // `Identifier("self")`. Before this slice the user-method dispatch in
    // `compile_method_call` only matched identifier receivers, so a method
    // calling another method on `self` fell through to the "no handler for
    // method 'X' on non-identifier receiver" codegen error. The fix adds a
    // `SelfValue` arm to `inferred_receiver_type` (resolving the type via the
    // synthesized `self` param registered in `var_type_names`) and to the
    // receiver-storage path (addressing `self`'s alloca for the ptr-self ABI).

    #[test]
    fn test_e2e_self_dispatch_ref_self_returns_value() {
        // A `pub ref self` method calls a private `ref self` helper via
        // `self.doubled()` and uses its return value. Exercises the
        // SelfValue receiver through the ptr-self (ref) calling convention.
        let out = run_program(
            r#"
struct Counter { n: i64 }
impl Counter {
    fn doubled(ref self) -> i64 { self.n * 2 }
    pub fn report(ref self) -> i64 { self.doubled() + 1 }
}
fn main() { let c = Counter { n: 10 }; println(c.report()); }
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "21");
        }
    }

    #[test]
    fn test_e2e_self_dispatch_mut_ref_self_mutation_persists() {
        // A `pub mut ref self` method calls a private `mut ref self` helper
        // via `self.bump()` twice. The mutation must address the *same*
        // storage `self` points at, so it accumulates and persists back to
        // the caller's `c`.
        let out = run_program(
            r#"
struct Counter { n: i64 }
impl Counter {
    fn bump(mut ref self) { self.n = self.n + 5; }
    pub fn run(mut ref self) -> i64 { self.bump(); self.bump(); self.n }
}
fn main() { let mut c = Counter { n: 0 }; println(c.run()); }
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "10");
        }
    }

    #[test]
    fn test_e2e_self_dispatch_helper_invariant_fires() {
        // Ties self-dispatch back to contracts: a `pub` method calls a
        // private `mut ref self` helper via `self.dec()` that breaks the
        // `impl invariant`. Reaching the helper at all proves dispatch
        // works; the helper's own exit-invariant check then aborts.
        let captured = run_program_capturing(
            r#"
struct Counter { n: i64, impl invariant self.n >= 0 }
impl Counter {
    fn dec(mut ref self) { self.n = self.n - 1; }
    pub fn drive(mut ref self) { self.dec(); }
}
fn main() { let mut c = Counter { n: 0 }; c.drive(); println(42); }
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract violated"),
                "expected the helper's impl-invariant abort via self-dispatch, \
                 got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                !c.stdout.contains("42"),
                "code after the abort must not run"
            );
        }
    }

    // ── Contracts — release-mode stripping (design.md § Contracts) ────
    //
    // "Checked at runtime in debug builds, stripped in release." With
    // stripping on, no contract assert (`requires` / `ensures` / `old` /
    // `invariant`) is emitted — the `contract violated` fault string, the
    // marker of an emitted assert, disappears from the IR while the function
    // body itself remains intact. `ir_for_contracts_stripped` forces the
    // decision race-free (no global env mutation).

    // A program exercising all four contract kinds in one module.
    const ALL_CONTRACTS_SRC: &str = r#"
struct Account { balance: i64, invariant self.balance >= 0 }
impl Account {
    pub fn withdraw(mut ref self, amount: i64) -> i64
        requires amount > 0
        ensures(result) self.balance == old(self.balance) - amount
    { self.balance = self.balance - amount; amount }
}
fn checked(x: i64) -> i64 requires x > 0 ensures(result) result > x { x * 2 }
fn main() {
    let mut a = Account { balance: 100 };
    println(a.withdraw(30));
    println(checked(5));
}
"#;

    #[test]
    fn test_ir_contracts_present_in_debug_default() {
        // Baseline: with the default (debug) settings, contract asserts ARE
        // emitted — the `contract violated` fault string appears in the IR.
        let ir = ir_for(ALL_CONTRACTS_SRC);
        assert!(
            ir.contains("contract violated"),
            "debug build must emit contract asserts; IR had no `contract violated` marker"
        );
    }

    #[test]
    fn test_ir_strip_contracts_removes_all_asserts() {
        // Release: every contract assert across all four kinds is gone.
        let ir = ir_for_contracts_stripped(ALL_CONTRACTS_SRC);
        assert!(
            !ir.contains("contract violated"),
            "release build must strip all contract asserts; IR still had a `contract violated` marker:\n{ir}"
        );
    }

    #[test]
    fn test_ir_strip_contracts_keeps_function_bodies() {
        // Stripping removes only contracts, not the checked code: the bodies
        // still compile (the module still defines `checked` and `main`, and
        // the `x * 2` multiply survives).
        let ir = ir_for_contracts_stripped(ALL_CONTRACTS_SRC);
        assert!(
            ir.contains("define") && ir.contains("@checked") && ir.contains("@main"),
            "stripped module must still define the functions; IR:\n{ir}"
        );
        assert!(
            ir.contains("mul"),
            "stripped `checked` must still emit its `x * 2` body; IR:\n{ir}"
        );
    }

    #[test]
    fn test_ir_strip_contracts_requires_only() {
        // A `requires`-only function: the precondition assert is present by
        // default and gone when stripped.
        let src = r#"
fn checked(x: i64) -> i64 requires x > 0 { x * 2 }
fn main() { println(checked(5)); }
"#;
        assert!(ir_for(src).contains("contract violated"));
        assert!(!ir_for_contracts_stripped(src).contains("contract violated"));
    }

    #[test]
    fn test_ir_strip_contracts_invariant_only() {
        // An `invariant`-only struct method: the invariant assert is present
        // by default and gone when stripped.
        let src = r#"
struct Counter { n: i64, invariant self.n >= 0 }
impl Counter { pub fn inc(mut ref self) -> i64 { self.n = self.n + 1; self.n } }
fn main() { let mut c = Counter { n: 0 }; println(c.inc()); }
"#;
        assert!(ir_for(src).contains("contract violated"));
        assert!(!ir_for_contracts_stripped(src).contains("contract violated"));
    }

    // ── Contracts — `contract predicate panicked` fault category (AOT) ──
    //
    // design.md § Contracts rule 2: a predicate that *returns false* is
    // `contract violated`; a predicate whose *evaluation* faults (index OOB,
    // div-by-zero, unwrap) is the distinct `contract predicate panicked`.
    // These mirror the interpreter coverage in tests/interpreter.rs for the
    // AOT path: panics emitted while compiling the predicate carry the
    // distinct prefix.

    #[test]
    fn test_e2e_contract_predicate_panicked_is_distinct() {
        // `requires v[i] >= 0` with `i` out of range: the `v[i]` bounds check
        // fires during predicate evaluation — the distinct
        // `contract predicate panicked` fault, NOT `contract violated`.
        let captured = run_program_capturing(
            r#"
fn at(v: ref Vec[i64], i: i64) -> i64 requires v[i] >= 0 { 0 }
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(1); v.push(2); v.push(3);
    println(at(v, 99));
    println(42);
}
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract predicate panicked"),
                "expected a `contract predicate panicked` fault, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                !c.stdout.contains("contract violated"),
                "a panicking predicate must NOT report `contract violated`, got stdout={:?}",
                c.stdout
            );
            assert!(
                !c.stdout.contains("42"),
                "code after the abort must not run"
            );
        }
    }

    #[test]
    fn test_e2e_contract_violated_distinct_from_panicked() {
        // A predicate that simply returns false is `contract violated`, NOT
        // `contract predicate panicked` — the flag is cleared before the
        // explicit false-branch.
        let captured = run_program_capturing(
            r#"
fn pos(x: i64) -> i64 requires x > 0 { x }
fn main() { println(pos(-5)); println(42); }
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract violated"),
                "expected `contract violated` for a false predicate, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                !c.stdout.contains("predicate panicked"),
                "a false predicate must NOT report panicked, got stdout={:?}",
                c.stdout
            );
        }
    }

    #[test]
    fn test_e2e_contract_predicate_panicked_in_ensures() {
        // The distinct category fires for an `ensures` predicate too:
        // `v[result]` with `result` out of range panics during evaluation.
        let captured = run_program_capturing(
            r#"
fn f(v: ref Vec[i64]) -> i64 ensures(result) v[result] >= 0 { 99 }
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(1); v.push(2); v.push(3);
    println(f(v));
    println(42);
}
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract predicate panicked"),
                "expected `contract predicate panicked` in an ensures, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                !c.stdout.contains("42"),
                "code after the abort must not run"
            );
        }
    }

    #[test]
    fn test_e2e_contract_predicate_panicked_cross_call() {
        // The cross-call case: the `requires` predicate calls a helper, and the
        // panic (`v[i]` OOB) fires inside the HELPER's body — a separate
        // function compiled with no lexical predicate context. The prior
        // compile-time flag could not categorize this (the helper's panic site
        // compiles with the flag clear); the runtime depth counter set around
        // the predicate's evaluation does, so it still reports
        // `contract predicate panicked`, NOT a plain `panic:` and NOT
        // `contract violated`. This is the divergence-from-interpreter the
        // step-7 inline slice left open, now closed.
        let captured = run_program_capturing(
            r#"
fn deref_at(v: ref Vec[i64], i: i64) -> bool { v[i] >= 0 }
fn at(v: ref Vec[i64], i: i64) -> i64 requires deref_at(v, i) { 0 }
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(1); v.push(2); v.push(3);
    println(at(v, 99));
    println(42);
}
"#,
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("contract predicate panicked"),
                "a panic inside a fn the predicate CALLS must report `contract predicate panicked`, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
            assert!(
                !c.stdout.contains("contract violated"),
                "a cross-call predicate panic must NOT report `contract violated`, got stdout={:?}",
                c.stdout
            );
            assert!(
                !c.stdout.contains("42"),
                "code after the abort must not run"
            );
        }
    }

    // ── Contracts — contract-free panic-prefix fold ──────────────────
    //
    // A program with no contract can never have a non-zero predicate depth,
    // so `emit_panic` folds the fault-category prefix to the static `""`
    // instead of calling `karac_runtime_panic_prefix()`. No call → no
    // relocation → the runtime archive member carrying the thread-local
    // depth counter is never pulled in, and its writable 16 KiB __DATA page
    // dead-strips from every contract-free binary; the panic landing pad
    // stays a static-string leaf (the unconditional call regressed a
    // bounds-check-hot loop 1.34× — kata-5, 2026-06-05). Contracted
    // programs keep the runtime read — the feature is correct, only its
    // unconditional cost was the defect.

    #[test]
    fn test_ir_contract_free_panic_folds_static_prefix() {
        // A bounds-checked index is a panic site, but the program declares no
        // contract: the prefix must fold static — no runtime-prefix call.
        let ir = ir_for(
            r#"
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(1);
    println(v[0]);
}
"#,
        );
        assert!(
            !ir.contains("call ptr @karac_runtime_panic_prefix"),
            "contract-free program must not CALL karac_runtime_panic_prefix"
        );
        assert!(
            ir.contains("panic_prefix_static"),
            "expected the folded static empty-string prefix at the panic site"
        );
    }

    #[test]
    fn test_ir_panic_bodies_outlined_cold() {
        // Panic bodies (printf + exit) are outlined into per-site zero-arg
        // `internal` `cold`+`noinline`+`noreturn` functions; the landing pad
        // in the enclosing function is a single zero-operand call. This keeps
        // panic sites near-free for the LLVM inline cost model — growing the
        // panic-site printf to 7 operands (fault prefix + location, both
        // 2026-05-31) pushed bounds-check-bearing functions past the O2
        // inline threshold and regressed kata-5's hot loop 1.34× (the
        // un-inlined helper re-ran two loop-invariant guards per iteration).
        let ir = ir_for(
            r#"
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(1);
    println(v[0]);
}
"#,
        );
        assert!(
            ir.contains("define internal void @__karac_panic_site_0()"),
            "panic body must be outlined into an internal per-site function"
        );
        assert!(
            ir.contains("call void @__karac_panic_site_0()"),
            "the landing pad must be a zero-operand call to the outlined body"
        );
        // The printf must live in the outlined body, not the landing pad:
        // the attribute group attached to the site fn carries cold+noinline.
        let attrs_line = ir
            .lines()
            .find(|l| l.starts_with("attributes") && l.contains("cold") && l.contains("noinline"))
            .unwrap_or("");
        assert!(
            attrs_line.contains("noreturn"),
            "outlined panic body must be cold+noinline+noreturn, got: {attrs_line:?}"
        );
    }

    #[test]
    fn test_ir_contracted_program_keeps_runtime_prefix() {
        // Any `requires` anywhere in the program keeps the runtime read at
        // EVERY panic site — a panic in a function the predicate transitively
        // calls must still categorize as `contract predicate panicked`.
        let ir = ir_for(
            r#"
fn pos(x: i64) -> i64 requires x > 0 { x }
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(1);
    println(v[0] + pos(1));
}
"#,
        );
        assert!(
            ir.contains("call ptr @karac_runtime_panic_prefix"),
            "a program with a contract must keep the runtime prefix read"
        );
    }

    #[test]
    fn test_ir_contracts_stripped_panic_folds_static_prefix() {
        // Stripped contracts (release) emit no predicate brackets, so the
        // prefix folds static even when the source declares contracts.
        let ir = ir_for_contracts_stripped(
            r#"
fn pos(x: i64) -> i64 requires x > 0 { x }
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(1);
    println(v[0] + pos(1));
}
"#,
        );
        assert!(
            !ir.contains("call ptr @karac_runtime_panic_prefix"),
            "contracts-stripped program must not call karac_runtime_panic_prefix"
        );
    }

    #[test]
    fn test_ir_invariant_keeps_runtime_prefix() {
        // The scan must see struct `invariant`s too, not just fn contracts.
        let ir = ir_for(
            r#"
struct Counter { n: i64, invariant self.n >= 0 }
impl Counter { pub fn inc(mut ref self) -> i64 { self.n = self.n + 1; self.n } }
fn main() { let mut c = Counter { n: 0 }; println(c.inc()); }
"#,
        );
        assert!(
            ir.contains("call ptr @karac_runtime_panic_prefix"),
            "a program with a struct invariant must keep the runtime prefix read"
        );
    }

    #[test]
    fn test_ir_repl_cell_keeps_runtime_prefix() {
        // REPL cell modules always keep the runtime read: a cell can call a
        // contracted function JIT'd from an EARLIER cell, which this
        // module's item scan can't see (size/perf are irrelevant under JIT).
        let mut parsed = karac::parse(
            r#"
fn main() {
    let mut v: Vec[i64] = Vec.new();
    v.push(1);
    println(v[0]);
}
"#,
        );
        assert!(parsed.errors.is_empty(), "parse: {:?}", parsed.errors);
        let resolved = karac::resolve(&parsed.program);
        let typed = karac::typecheck(&parsed.program, &resolved);
        karac::lower(&mut parsed.program, &typed);
        let ir = karac::codegen::compile_to_ir_for_repl_cell(
            &parsed.program,
            &std::collections::HashSet::new(),
            "__karac_repl_cell_main",
        )
        .expect("repl-cell codegen failed");
        assert!(
            ir.contains("call ptr @karac_runtime_panic_prefix"),
            "a REPL cell module must keep the runtime prefix read (cross-cell contracts)"
        );
    }

    // ── std.tracing — emission surface (StdoutExporter) E2E ──────────
    //
    // Proves the baked `std.tracing` surface compiles + links + runs as a
    // real binary, not just IR-shape: the struct layouts, the builder
    // methods (`LogEvent.info` / `Span.root` / `.child` / `.with_field` /
    // `.in_span`), and the `StdoutExporter` trait-impl bodies all lower
    // through codegen and round-trip the expected structured lines. This
    // is the codegen counterpart to the interpreter coverage in
    // `tests/interpreter.rs` (`test_tracing_stdout_exporter_*`). Before
    // the tracing-codegen slice the whole surface was interpreter-only —
    // a compiled `LogEvent { ... }.message` read `0`.

    #[test]
    fn e2e_tracing_stdout_exporter_emits_events() {
        let out = run_program(
            r#"fn main() {
                let tracer = StdoutExporter {};
                tracer.export_event(LogEvent.info("plain"));
                tracer.export_event(
                    LogEvent.info("started")
                        .with_field("user_id", "42")
                        .with_field("ip", "127.0.0.1")
                        .in_span(5));
            }"#,
        );
        // Two sequential exports + an owned-event temporary dropped after
        // each: this is the shape the f-string-in-a-loop double-free
        // (`test_e2e_fstring_in_loop_no_double_free`) used to crash on. The
        // exporter bodies now use the natural multi-interpolation f-string
        // form again (the underlying codegen bug is fixed), so a green run
        // here also guards against that regression returning.
        assert_eq!(
            out.as_deref(),
            Some("[info] plain\n[info] started user_id=42 ip=127.0.0.1 span_id=5\n"),
        );
    }

    #[test]
    fn e2e_tracing_stdout_exporter_emits_spans() {
        let out = run_program(
            r#"fn main() {
                let tracer = StdoutExporter {};
                tracer.export_span(Span.root("request", 7));
                tracer.export_span(
                    Span.root("outer", 1)
                        .child("inner", 2)
                        .with_field("route", "/health"));
            }"#,
        );
        assert_eq!(
            out.as_deref(),
            Some("[span] request span_id=7\n[span] inner span_id=2 parent_id=1 route=/health\n"),
        );
    }

    #[test]
    fn e2e_tracing_log_ambient_emission() {
        // `Log.<level>(...)` — the ambient emission namespace — compiles
        // and runs in a real binary. `Log.info` etc. are assoc-fn bodies
        // over `StdoutExporter`/`LogEvent`, so they lower through the same
        // tracing-codegen pass; this pins that `karac build` (not just
        // `karac run`) honors the convenience layer.
        let out = run_program(
            r#"fn main() {
                Log.info("server started");
                Log.warn("disk 85%");
                Log.error("connection refused");
            }"#,
        );
        assert_eq!(
            out.as_deref(),
            Some("[info] server started\n[warn] disk 85%\n[error] connection refused\n"),
        );
    }

    #[test]
    fn e2e_tracing_with_span_stamps_active_span() {
        // phase-8 line 153: `with_span(s, ||body)` installs `s` as the
        // ambient active span in a compiled binary — a `Log.*` inside the
        // body is auto-stamped with the span id (via the per-thread
        // `karac_tracing_*` register), and the active span is restored on
        // exit. Proves the codegen `with_span` lowering + the
        // `tracing_active_span()`-fed auto-stamp round-trip through a real
        // executable, and that a nested span restores the outer one.
        let out = run_program(
            r#"fn main() {
                let outer = Span.root("o", 1);
                let inner = Span.root("i", 2);
                with_span(outer, || {
                    Log.info("a");
                    with_span(inner, || { Log.info("b") });
                    Log.info("c");
                });
                Log.info("d");
            }"#,
        );
        assert_eq!(
            out.as_deref(),
            Some("[info] a span_id=1\n[info] b span_id=2\n[info] c span_id=1\n[info] d\n"),
        );
    }

    #[test]
    fn e2e_tracing_par_branch_inherits_active_span() {
        // phase-8 line 153: a child task (par branch) inherits the
        // parent's active span. The branch runs on a worker thread (fresh
        // TLS), but the env-struct snapshot taken at par-block entry seeds
        // the worker's active-span register, so a `Log.*` inside the
        // branch is stamped with the enclosing `with_span`'s id. Single
        // branch → deterministic output. After `with_span` exits, the
        // active span is restored (the trailing `Log.info` has no suffix).
        let out = run_program(
            r#"fn main() {
                let s = Span.root("req", 5);
                with_span(s, || {
                    par {
                        Log.info("in-branch");
                    }
                });
                Log.info("after");
            }"#,
        );
        assert_eq!(
            out.as_deref(),
            Some("[info] in-branch span_id=5\n[info] after\n"),
        );
    }

    #[test]
    fn e2e_tracing_noop_exporter_is_silent() {
        // The default exporter compiles + runs and emits nothing — the
        // `NoOpExporter` impl bodies lower through the same path.
        let out = run_program(
            r#"fn main() {
                let drop_all = NoOpExporter {};
                drop_all.export_event(LogEvent.warn("ignored"));
                drop_all.export_span(Span.root("ignored", 9));
                println("done");
            }"#,
        );
        assert_eq!(out.as_deref(), Some("done\n"));
    }

    // ── std.tracing — configurable ambient exporter (line 156) E2E ───
    //
    // The codegen half of phase-8 line 156: a *compiled* `Log.*` honors
    // `Log.set_min_level` / `set_exporter` / `reset` via the process-global
    // runtime config (`runtime/src/tracing.rs`) + the `tracing_*` builtin
    // lowerings. These mirror the interpreter coverage in
    // `tests/interpreter.rs` (`test_tracing_log_{min_level_filters,
    // set_exporter_noop_silences,reset_restores_default,
    // custom_exporter_receives_events}`), pinning identical behavior under
    // `karac build` as under `karac run`.

    #[test]
    fn e2e_tracing_log_min_level_filters_below_threshold() {
        // `Log.set_min_level("warn")` drops trace/debug/info; warn + error
        // emit. Proves the compiled level gate consults the runtime global.
        let out = run_program(
            r#"fn main() {
                Log.set_min_level("warn");
                Log.trace("t");
                Log.debug("d");
                Log.info("i");
                Log.warn("w");
                Log.error("e");
            }"#,
        );
        assert_eq!(out.as_deref(), Some("[warn] w\n[error] e\n"));
    }

    #[test]
    fn e2e_tracing_log_set_exporter_noop_silences() {
        // Registering `NoOpExporter` routes compiled `Log.*` to its empty
        // `export_event` (indirect dispatch through the runtime fn-ptr)
        // instead of stdout — so the program emits nothing.
        let out = run_program(
            r#"fn main() {
                Log.set_exporter(NoOpExporter {});
                Log.info("i");
                Log.error("e");
                println("done");
            }"#,
        );
        assert_eq!(out.as_deref(), Some("done\n"));
    }

    #[test]
    fn e2e_tracing_log_reset_restores_default() {
        // `Log.reset()` clears the min level (and any sink), so a level
        // dropped before the reset emits to stdout again afterward.
        let out = run_program(
            r#"fn main() {
                Log.set_min_level("error");
                Log.info("dropped");
                Log.reset();
                Log.info("kept");
            }"#,
        );
        assert_eq!(out.as_deref(), Some("[info] kept\n"));
    }

    #[test]
    fn e2e_tracing_log_custom_exporter_receives_events() {
        // A user `Exporter` registered as the ambient sink receives
        // compiled `Log.*` events via the indirect-dispatch path, rendering
        // its own format. Also exercises the min-level filter applying
        // before the custom sink (the dropped `debug` never reaches it) and
        // `Log.set_exporter`'s call-site type inference for a user struct.
        let out = run_program(
            r#"struct Tagging { }
            impl Exporter for Tagging {
                fn export_span(ref self, span: Span) { }
                fn export_event(ref self, event: LogEvent) {
                    println(f"CUSTOM<{event.level}>: {event.message}");
                }
            }
            fn main() {
                Log.set_exporter(Tagging {});
                Log.set_min_level("info");
                Log.debug("dropped");
                Log.info("hi");
                Log.error("bye");
            }"#,
        );
        assert_eq!(
            out.as_deref(),
            Some("CUSTOM<info>: hi\nCUSTOM<error>: bye\n"),
        );
    }

    #[test]
    fn e2e_tracing_user_exporter_impl_reads_event_and_span_fields() {
        // A user `impl Exporter` whose methods take `LogEvent` / `Span` by
        // value compiles and reads their fields correctly. Regression for a
        // pre-existing gap surfaced by the line-156 work: the baked tracing
        // value structs weren't in `struct_types` when user functions were
        // declared, so `fn export_event(ref self, event: LogEvent)` got an
        // `i64` param (the `llvm_type_for_name` fall-through) and the call
        // `t.export_event(LogEvent.info(...))` failed module verification.
        // `seed_builtin_struct_types` now seeds `SpanField`/`Span`/`LogEvent`
        // so the by-value param layout matches. Direct (non-registered) calls.
        let out = run_program(
            r#"struct Collector { }
            impl Exporter for Collector {
                fn export_event(ref self, event: LogEvent) {
                    println(f"E {event.level}/{event.message}/{event.span_id}");
                }
                fn export_span(ref self, span: Span) {
                    println(f"S {span.name}/{span.span_id}/{span.parent_id}");
                }
            }
            fn main() {
                let c = Collector {};
                c.export_event(LogEvent.warn("disk").in_span(3));
                c.export_span(Span.root("req", 7).child("inner", 9));
            }"#,
        );
        assert_eq!(out.as_deref(), Some("E warn/disk/3\nS inner/9/7\n"),);
    }

    #[test]
    fn e2e_tracing_unused_in_program_emits_no_tracing_bodies() {
        // The usage gate: a program that never touches std.tracing must
        // not carry any tracing impl-method body. Pins that the unused-
        // declaration deletion in `compile_tracing_stdlib_method_bodies`
        // keeps tracing-free binaries lean (and is what lets the IR-shape
        // tests above stay valid).
        let ir = ir_for(
            r#"
fn main() {
    let buf: Array[i64, 8] = [42; 8];
    let _ = buf[0];
}
"#,
        );
        assert!(
            !ir.contains("@LogEvent.")
                && !ir.contains("@Span.")
                && !ir.contains("@StdoutExporter.")
                && !ir.contains("@NoOpExporter."),
            "a tracing-free program must emit no tracing impl methods; got IR:\n{}",
            ir
        );
    }

    // ── Phase 6 `par struct` slice C: always-Arc codegen ─────────
    // A `par struct` / `par enum` reuses the entire shared-struct codegen
    // (same `{ i64 refcount, … }` heap layout, malloc, field access, method
    // dispatch, drop). The ONLY difference is that the refcount header is
    // mutated atomically (`atomicrmw`, via emit_arc_inc / emit_arc_dec)
    // because `par` values cross task boundaries. design.md § Part 5b.

    #[test]
    fn test_ir_par_struct_rc_inc_is_atomic() {
        // The clone pattern `let b = a` increments the refcount. For a `par
        // struct` that inc must be an `atomicrmw add`, NOT the plain
        // `add i64 %rc` a `shared struct` emits.
        let ir = ir_for(
            r#"
par struct Obj { data: i64 }
fn copy_par() {
    let a = Obj { data: 10 };
    let b = a;
    let _x = a.data + b.data;
}
"#,
        );
        assert!(
            ir.contains("atomicrmw add"),
            "par struct copy must emit an atomic refcount increment (atomicrmw add); got IR:\n{ir}"
        );
        assert!(
            !ir.contains("add i64 %rc"),
            "par struct refcount inc must NOT use the non-atomic `add i64 %rc` shared path; got IR:\n{ir}"
        );
    }

    #[test]
    fn test_ir_par_struct_rc_dec_is_atomic_and_frees() {
        // Scope exit decrements the refcount and conditionally frees. For a
        // `par struct` the decrement must be an `atomicrmw sub`.
        let ir = ir_for(
            r#"
par struct Token { id: i64 }
fn use_token() {
    let t = Token { id: 1 };
    let _x = t.id;
}
"#,
        );
        assert!(
            ir.contains("atomicrmw sub"),
            "par struct scope exit must emit an atomic refcount decrement (atomicrmw sub); got IR:\n{ir}"
        );
        assert!(
            ir.contains("@free"),
            "par struct scope exit must conditionally free the heap allocation; got IR:\n{ir}"
        );
    }

    #[test]
    fn test_ir_shared_struct_rc_stays_non_atomic_regression() {
        // Regression: the par atomic routing must NOT leak into `shared
        // struct` — a shared struct keeps the plain non-atomic refcount.
        let ir = ir_for(
            r#"
shared struct Obj { data: i64 }
fn copy_shared() {
    let a = Obj { data: 10 };
    let b = a;
    let _x = a.data + b.data;
}
"#,
        );
        assert!(
            ir.contains("add i64 %rc"),
            "shared struct must keep the non-atomic `add i64 %rc` refcount inc; got IR:\n{ir}"
        );
        assert!(
            !ir.contains("atomicrmw"),
            "shared struct must emit NO atomic refcount ops; got IR:\n{ir}"
        );
    }

    #[test]
    fn test_e2e_par_struct_basic() {
        let out = run_program(
            r#"
par struct Counter { val: i64 }
fn main() {
    let c = Counter { val: 42 };
    println(c.val);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "42");
        }
    }

    #[test]
    fn test_e2e_par_struct_with_atomic_field_constructs() {
        // `Atomic.new` in general (struct-field-init) position lets a
        // concurrent `par struct` with an `Atomic` field be constructed —
        // `Atomic[T]` is a transparent wrapper, so the field lowers to its
        // inner value. (Atomic-method dispatch on a shared/par field receiver
        // is a separate pre-existing gap; here we read a sibling plain field
        // to prove construction + the Arc lifecycle work with an Atomic field
        // present.)
        let out = run_program(
            r#"
par struct Counter { count: Atomic[i64], label: i64 }
fn label_of(c: Counter) -> i64 { c.label }
fn main() {
    let c = Counter { count: Atomic.new(0), label: 7 };
    println(label_of(c));
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "7");
        }
    }

    #[test]
    fn test_e2e_par_struct_atomic_field_set_get() {
        // The canonical concurrent shape: a `par struct` with an `Atomic`
        // field, mutated + read via atomic store/load on a `ref self` method.
        // Exercises atomic method dispatch on a par-struct FIELD receiver
        // (resolve_atomic_storage's shared/par branch — GEP idx+1 into the
        // heap layout). Round-trips 10 -> 42.
        let out = run_program(
            r#"
par struct Counter { count: Atomic[i64] }
impl Counter {
    fn get(ref self) -> i64 { self.count.load(MemoryOrdering.SeqCst) }
    fn set(ref self, v: i64) { self.count.store(v, MemoryOrdering.SeqCst) }
}
fn main() {
    let c = Counter { count: Atomic.new(10) };
    println(c.get());
    c.set(42);
    println(c.get());
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["10", "42"]);
        }
    }

    #[test]
    fn test_ir_atomic_fetch_add_emits_atomicrmw() {
        let ir = ir_for(
            r#"
par struct Counter { count: Atomic[i64] }
impl Counter { fn inc(ref self) -> i64 { self.count.fetch_add(1, MemoryOrdering.SeqCst) } }
fn main() { let c = Counter { count: Atomic.new(0) }; let _ = c.inc(); }
"#,
        );
        assert!(
            ir.contains("atomicrmw add"),
            "fetch_add must lower to `atomicrmw add`; got IR:\n{ir}"
        );
    }

    #[test]
    fn test_e2e_atomic_fetch_add_sub_returns_old_and_accumulates() {
        // fetch_add / fetch_sub return the PREVIOUS value and mutate in place.
        let out = run_program(
            r#"
par struct Counter { count: Atomic[i64] }
impl Counter {
    fn inc(ref self) -> i64 { self.count.fetch_add(1, MemoryOrdering.SeqCst) }
    fn dec(ref self) -> i64 { self.count.fetch_sub(1, MemoryOrdering.SeqCst) }
    fn get(ref self) -> i64 { self.count.load(MemoryOrdering.SeqCst) }
}
fn main() {
    let c = Counter { count: Atomic.new(0) };
    println(c.inc());   // 0 (old)
    println(c.inc());   // 1
    println(c.get());   // 2
    println(c.dec());   // 2 (old)
    println(c.get());   // 1
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["0", "1", "2", "2", "1"]);
        }
    }

    #[test]
    fn test_ir_atomic_swap_and_bitwise_emit_correct_atomicrmw() {
        // swap / fetch_and / fetch_or / fetch_xor each lower to the matching
        // single `atomicrmw` opcode (xchg / and / or / xor).
        let ir = ir_for(
            r#"
par struct B { v: Atomic[i64] }
impl B {
    fn a(ref self) -> i64 { self.v.fetch_and(6, MemoryOrdering.SeqCst) }
    fn o(ref self) -> i64 { self.v.fetch_or(1, MemoryOrdering.SeqCst) }
    fn x(ref self) -> i64 { self.v.fetch_xor(2, MemoryOrdering.SeqCst) }
    fn s(ref self) -> i64 { self.v.swap(9, MemoryOrdering.SeqCst) }
}
fn main() {
    let b = B { v: Atomic.new(7) };
    let _ = b.a(); let _ = b.o(); let _ = b.x(); let _ = b.s();
}
"#,
        );
        for op in [
            "atomicrmw and",
            "atomicrmw or",
            "atomicrmw xor",
            "atomicrmw xchg",
        ] {
            assert!(ir.contains(op), "expected `{op}` in IR; got:\n{ir}");
        }
    }

    #[test]
    fn test_e2e_atomic_bitwise_and_swap_semantics() {
        // fetch_or / fetch_and / fetch_xor / swap all return the OLD value and
        // apply the bitwise / exchange op in place.
        let out = run_program(
            r#"
par struct Flags { bits: Atomic[i64] }
impl Flags {
    fn set_or(ref self, m: i64) -> i64 { self.bits.fetch_or(m, MemoryOrdering.SeqCst) }
    fn clear_and(ref self, m: i64) -> i64 { self.bits.fetch_and(m, MemoryOrdering.SeqCst) }
    fn toggle(ref self, m: i64) -> i64 { self.bits.fetch_xor(m, MemoryOrdering.SeqCst) }
    fn exchange(ref self, v: i64) -> i64 { self.bits.swap(v, MemoryOrdering.SeqCst) }
    fn get(ref self) -> i64 { self.bits.load(MemoryOrdering.SeqCst) }
}
fn main() {
    let f = Flags { bits: Atomic.new(0) };
    println(f.set_or(5));    // old 0  -> 5
    println(f.set_or(2));    // old 5  -> 7
    println(f.clear_and(6)); // old 7  -> 6   (7 & 6)
    println(f.toggle(2));    // old 6  -> 4   (6 ^ 2)
    println(f.exchange(99)); // old 4  -> 99
    println(f.get());        // 99
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["0", "5", "7", "6", "4", "99"]);
        }
    }

    #[test]
    fn test_e2e_atomic_bool_swap() {
        // `swap` is the one RMW that also works on `Atomic[bool]` (i8 slot —
        // incoming i1 widened, returned old i8 truncated). A take-once latch.
        let out = run_program(
            r#"
par struct Latch { flag: Atomic[bool] }
impl Latch {
    fn take(ref self) -> bool { self.flag.swap(true, MemoryOrdering.SeqCst) }
    fn get(ref self) -> bool { self.flag.load(MemoryOrdering.SeqCst) }
}
fn main() {
    let l = Latch { flag: Atomic.new(false) };
    if l.take() { println(1); } else { println(0); }   // old false -> 0
    if l.get() { println(1); } else { println(0); }    // now true  -> 1
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["0", "1"]);
        }
    }

    #[test]
    fn test_ir_atomic_compare_exchange_emits_cmpxchg() {
        let ir = ir_for(
            r#"
par struct C { v: Atomic[i64] }
impl C {
    fn cas(ref self) -> Result[i64, i64] {
        self.v.compare_exchange(0, 5, MemoryOrdering.SeqCst, MemoryOrdering.SeqCst)
    }
}
fn main() { let c = C { v: Atomic.new(0) }; let _ = c.cas(); }
"#,
        );
        assert!(
            ir.contains("cmpxchg"),
            "compare_exchange must lower to LLVM `cmpxchg`; got IR:\n{ir}"
        );
    }

    #[test]
    fn test_e2e_atomic_compare_exchange_success_and_failure() {
        // CAS returns Ok(prev) and swaps when the expected value matches;
        // Err(actual) and leaves the slot unchanged when it does not.
        let out = run_program(
            r#"
par struct Cell { v: Atomic[i64] }
impl Cell {
    fn cas(ref self, old: i64, new: i64) -> Result[i64, i64] {
        self.v.compare_exchange(old, new, MemoryOrdering.SeqCst, MemoryOrdering.SeqCst)
    }
    fn get(ref self) -> i64 { self.v.load(MemoryOrdering.SeqCst) }
}
fn report(r: Result[i64, i64]) {
    match r {
        Ok(prev) => { println(100 + prev); }
        Err(actual) => { println(200 + actual); }
    }
}
fn main() {
    let c = Cell { v: Atomic.new(5) };
    report(c.cas(5, 9));   // 5 == 5 -> Ok(5)  -> 105
    println(c.get());      // 9 (swapped)
    report(c.cas(5, 1));   // 5 != 9 -> Err(9) -> 209
    println(c.get());      // 9 (unchanged — failed CAS does not store)
}
"#,
        );
        if let Some(out) = out {
            let lines: Vec<&str> = out.trim().lines().collect();
            assert_eq!(lines, vec!["105", "9", "209", "9"]);
        }
    }

    #[test]
    fn test_e2e_concurrent_cas_loop_increment_no_lost_updates() {
        // The canonical lock-free pattern: a load + compare_exchange retry
        // loop, run concurrently from two `par {}` branches 50_000× each.
        // CAS guarantees exactly 100_000 — a failed exchange retries with the
        // freshly-observed value, so no update is ever lost.
        let out = run_program(
            r#"
par struct Counter { v: Atomic[i64] }
impl Counter {
    fn get(ref self) -> i64 { self.v.load(MemoryOrdering.SeqCst) }
    fn inc(ref self) {
        let mut done = false;
        while not done {
            let cur = self.v.load(MemoryOrdering.SeqCst);
            match self.v.compare_exchange(cur, cur + 1, MemoryOrdering.SeqCst, MemoryOrdering.SeqCst) {
                Ok(_) => { done = true; }
                Err(_) => { }
            }
        }
    }
}
fn bump(c: Counter, n: i64) {
    let mut i = 0;
    while i < n { c.inc(); i = i + 1; }
}
fn main() {
    let c = Counter { v: Atomic.new(0) };
    par {
        bump(c, 50000);
        bump(c, 50000);
    }
    println(c.get());
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "100000");
        }
    }

    // ── Mutex + lock blocks (slice 1: spinlock, standalone) ──────

    #[test]
    fn test_ir_lock_block_emits_futex_cmpxchg_and_conditional_wake() {
        let ir = ir_for(
            r#"
fn main() {
    let m = Mutex.new(0);
    lock m x { x = x + 1; }
}
"#,
        );
        // Acquire fast path: cmpxchg(0 -> 1) — uncontended locking stays inline.
        assert!(
            ir.contains("cmpxchg"),
            "lock acquire must emit a `cmpxchg` fast path; got IR:\n{ir}"
        );
        // Contended path calls the runtime to block instead of spinning.
        assert!(
            ir.contains("@karac_runtime_mutex_lock"),
            "lock contended path must call `karac_runtime_mutex_lock`; got IR:\n{ir}"
        );
        // Release: atomic xchg(-> 0) reading the prior state, then a *conditional*
        // wake call (only when the prior state was 2 = contended).
        assert!(
            ir.contains("atomicrmw xchg"),
            "lock release must emit `atomicrmw xchg` to read the prior state; got IR:\n{ir}"
        );
        assert!(
            ir.contains("@karac_runtime_mutex_unlock_wake"),
            "lock release must conditionally call `karac_runtime_mutex_unlock_wake`; got IR:\n{ir}"
        );
    }

    #[test]
    fn test_e2e_lock_block_single_threaded_alias_and_no_alias() {
        // Both forms: `lock m x { ... }` (alias) and `lock m { ... m ... }`
        // (the mutex name shadows to the inner value). 10 -> +5 -> *2 -> 30.
        let out = run_program(
            r#"
fn main() {
    let m = Mutex.new(10);
    lock m x { x = x + 5; }
    lock m y { y = y * 2; }
    lock m { println(m); }
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "30");
        }
    }

    #[test]
    fn test_e2e_concurrent_mutex_counter_no_lost_updates() {
        // A standalone local `Mutex[i64]` shared across two `par {}` branches
        // (par captures the local by reference to the same aggregate). The
        // spinlock serializes the read-modify-write, so 2×50_000 increments
        // yield exactly 100_000 — a non-locked `+1` would lose updates.
        let out = run_program(
            r#"
fn main() {
    let m = Mutex.new(0);
    par {
        {
            let mut i = 0;
            while i < 50000 { lock m x { x = x + 1; } i = i + 1; }
        }
        {
            let mut j = 0;
            while j < 50000 { lock m y { y = y + 1; } j = j + 1; }
        }
    }
    lock m v { println(v); }
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "100000");
        }
    }

