    #[test]
    fn test_e2e_tensor_broadcast() {
        // Row / column / rank-mismatch broadcasting, two-singleton expand, a
        // fresh-temp argument (`a + b`), and float division. Operand reuse
        // afterward confirms borrow-not-move. Output verified vs `karac run`.
        let out = run_program(
            "fn main() {\n\
                 let m: Tensor[i64, [2, 3]] = Tensor.from([[1, 2, 3], [4, 5, 6]]);\n\
                 let row: Tensor[i64, [1, 3]] = Tensor.from([[10, 20, 30]]);\n\
                 let r = m.broadcast_add(row);\n\
                 println(r[0, 0]); println(r[1, 2]);\n\
                 let col: Tensor[i64, [2, 1]] = Tensor.from([[100], [200]]);\n\
                 let c = m.broadcast_mul(col);\n\
                 println(c[0, 1]); println(c[1, 0]);\n\
                 let v: Tensor[i64, [3]] = Tensor.from([1, 2, 3]);\n\
                 let d = m.broadcast_sub(v);\n\
                 println(d[0, 0]); println(d[1, 1]);\n\
                 // two singletons broadcast UP to [2, 3].\n\
                 let g = row.broadcast_add(col);\n\
                 println(g[1, 0]);\n\
                 // fresh-temp argument (the `b + b` intermediate is freed).\n\
                 let b: Tensor[i64, [1, 3]] = Tensor.from([[1, 1, 1]]);\n\
                 let h = m.broadcast_add(b + b);\n\
                 println(h[0, 0]);\n\
                 // float division.\n\
                 let fm: Tensor[f64, [2, 2]] = Tensor.from([[2.0, 4.0], [6.0, 8.0]]);\n\
                 let fc: Tensor[f64, [2, 1]] = Tensor.from([[2.0], [4.0]]);\n\
                 let fq = fm.broadcast_div(fc);\n\
                 println(fq[1, 0]);\n\
                 println(m[1, 2]);\n\
             }\n",
        );
        if let Some(out) = out {
            // r[0,0]=1+10=11, r[1,2]=6+30=36; c[0,1]=2*100=200, c[1,0]=4*200=800;
            // d[0,0]=1-1=0, d[1,1]=5-2=3; g[1,0]=row[0,0]+col[1,0]=10+200=210;
            // h[0,0]=1+(1+1)=3; fq[1,0]=6/4=1.5; m reused=6.
            assert_eq!(
                out, "11\n36\n200\n800\n0\n3\n210\n3\n1.5\n6\n",
                "tensor broadcast AOT output must match the interpreter twin",
            );
        }
    }

    #[test]
    fn test_e2e_tensor_broadcast_runtime_dims_and_trap() {
        // `?`-dim operands: a compatible broadcast (row [1,?] over [?,?]) and
        // an incompatible one that the codegen runtime guard traps. The static
        // checker can't prove either, so both go through the header-driven
        // runtime path.
        let ok = run_program(
            "fn mk_mat(r: i64, c: i64) -> Tensor[i64, [?, ?]] {\n\
                 let t: Tensor[i64, [?, ?]] = Tensor.full([r, c], 2);\n\
                 t\n\
             }\n\
             fn mk_row(n: i64) -> Tensor[i64, [1, ?]] {\n\
                 let t: Tensor[i64, [1, ?]] = Tensor.full([1, n], 5);\n\
                 t\n\
             }\n\
             fn main() {\n\
                 let m: Tensor[i64, [?, ?]] = mk_mat(2, 3);\n\
                 let row: Tensor[i64, [1, ?]] = mk_row(3);\n\
                 let r = m.broadcast_add(row);\n\
                 println(r[0, 0]); println(r[1, 2]);\n\
             }\n",
        );
        if let Some(out) = ok {
            assert_eq!(
                out, "7\n7\n",
                "runtime-dim broadcast must match `karac run`"
            );
        }
        let captured = run_program_capturing(
            "fn mk(r: i64, c: i64) -> Tensor[i64, [?, ?]] {\n\
                 let t: Tensor[i64, [?, ?]] = Tensor.full([r, c], 1);\n\
                 t\n\
             }\n\
             fn main() {\n\
                 let a: Tensor[i64, [?, ?]] = mk(2, 3);\n\
                 let b: Tensor[i64, [?, ?]] = mk(2, 4);\n\
                 let r = a.broadcast_add(b);\n\
                 println(r[0, 0]);\n\
             }\n",
        );
        if let Some(c) = captured {
            assert!(
                c.stdout.contains("not broadcast-compatible"),
                "expected the broadcast-incompatible trap, got stdout={:?} stderr={:?}",
                c.stdout,
                c.stderr
            );
        }
    }

    // ── Owned String/Vec parameter retention (kata-22 family, 2026-06-06) ──
    //
    // The call ABI passes owned String/Vec headers by value while the
    // CALLER retains the buffer's scope-exit free — so a callee that
    // RETAINS the value (push into a container, return it, capture it
    // in a struct/enum payload) must deep-copy the buffer instead of
    // aliasing it (`emit_vecstr_defensive_copy`). Before the fix every
    // shape below either aborted under macOS malloc (exit 133 double
    // free) or read freed memory. The f-string siblings pin the
    // `last_fstr_acc` take-points at the same consume sites (the temp
    // accumulator's queued cleanup must be disarmed when the container
    // takes the buffer).

    #[test]
    fn test_e2e_owned_string_param_push_branch_move() {
        // Recursive backtracking shape: `cur` is moved into the vec in
        // the base-case branch and borrowed by the f-string in the
        // recursive branch. The cap-sentinel machinery gives the
        // per-branch flow sensitivity; the defensive copy keeps the
        // pushed buffer alive past the caller's f-string-temp cleanup.
        let out = run_program(
            r#"
fn add_rec(cur: String, k: i64, out: mut ref Vec[String]) {
    if k == 0 {
        out.push(cur);
        return;
    }
    add_rec(f"{cur}(", k - 1, out);
}

fn generate(n: i64) -> Vec[String] {
    let mut out: Vec[String] = Vec.new();
    add_rec("", n, mut out);
    out
}

fn main() {
    let combos = generate(3);
    println(combos.len());
    println(combos[0]);
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "1\n(((");
        }
    }

    #[test]
    fn test_e2e_map_insert_owned_string_param_value() {
        // `m.insert(k, v)` where `v: String` is an owned PARAM and the map
        // outlives the callee (passed `mut ref`): the Map must store a
        // private deep copy, not an alias into the caller's buffer, or the
        // caller's scope-exit free and the Map's bucket free double-hit the
        // same buffer (kata-22 owned-param UAF family, Cluster 1). The read
        // back through `m.get` proves the value buffer survives.
        let out = run_program(
            r#"
fn store(m: mut ref Map[i64, String], v: String) {
    m.insert(7i64, v);
}

fn main() {
    let mut m: Map[i64, String] = Map.new();
    let mut s = String.new();
    s.push_str("payload");
    store(mut m, s);
    println(m.len());
    match m.get(7i64) { Some(g) => println(g), None => println("missing") }
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "1\npayload");
        }
    }

    #[test]
    fn test_e2e_set_insert_owned_string_param() {
        // `s.insert(v)` where `v: String` is an owned PARAM and the set
        // outlives the callee: same defensive-copy requirement as
        // `Map.insert`'s value side (Set lowers to `Map[T, ()]`, the
        // element is the bucket key). The `contains` reads prove the keys
        // survive past the caller's frees.
        let out = run_program(
            r#"
fn add(set: mut ref Set[String], v: String) {
    set.insert(v);
}

fn main() {
    let mut s: Set[String] = Set.new();
    let mut a = String.new();
    a.push_str("apple");
    add(mut s, a);
    let mut b = String.new();
    b.push_str("banana");
    add(mut s, b);
    println(s.len());
    println(s.contains("apple"));
    println(s.contains("banana"));
    println(s.contains("cherry"));
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "2\ntrue\ntrue\nfalse");
        }
    }

    #[test]
    fn test_e2e_vec_map_param_deep_copy() {
        // `Vec[Map[i64, i64]]` owned param tail-returned: the defensive
        // copy must deep-clone each map handle, not alias it (Cluster 1).
        // Value-correctness companion to the ASAN double-free pin — the
        // cloned maps must carry the original entries.
        let out = run_program(
            r#"
fn id(v: Vec[Map[i64, i64]]) -> Vec[Map[i64, i64]] {
    v
}

fn main() {
    let mut v: Vec[Map[i64, i64]] = Vec.new();
    let mut m: Map[i64, i64] = Map.new();
    m.insert(1i64, 10i64);
    m.insert(2i64, 20i64);
    v.push(m);
    let mut m2: Map[i64, i64] = Map.new();
    m2.insert(3i64, 30i64);
    v.push(m2);
    let r = id(v);
    println(r.len());
    match r[0].get(1i64) { Some(x) => println(x), None => println(-1i64) }
    match r[0].get(2i64) { Some(x) => println(x), None => println(-1i64) }
    match r[1].get(3i64) { Some(x) => println(x), None => println(-1i64) }
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "2\n10\n20\n30");
        }
    }

    #[test]
    fn test_e2e_vec_map_returned_from_helper() {
        // The headline `Vec[Map]` ownership bug (Cluster 1): a Map pushed
        // into a Vec aliased a handle owned by the origin `m` binding, which
        // freed it at the helper's scope exit — so the returned Vec dangled
        // and the read in `main` saw a freed/reused handle (AOT printed
        // `-1`, interp `777`). The fix transfers ownership to the Vec at the
        // push and frees the handle at the Vec's drop. ASAN twin:
        // `memory_sanitizer.rs::asan_vec_map_returned_from_helper_no_uaf`.
        let out = run_program(
            r#"
fn make() -> Vec[Map[i64, i64]] {
    let mut v: Vec[Map[i64, i64]] = Vec.new();
    let mut m: Map[i64, i64] = Map.new();
    m.insert(1i64, 777i64);
    v.push(m);
    v
}

fn main() {
    let v = make();
    match v[0].get(1i64) { Some(x) => println(x), None => println(-1i64) }
}
"#,
        );
        if let Some(out) = out {
            assert_eq!(out.trim(), "777");
        }
    }

